/// acc -= x * y mod p via Karatsuba. Not squaring (x ≠ y).
fn mod_mul_sub_into_acc_karatsuba(
    b: &mut B,
    acc: &[QubitId],
    x: &[QubitId],
    y: &[QubitId],
    p: U256,
) {
    // Negate x in place, run karatsuba add, then restore x.
    mod_neg_inplace_fast(b, x, p);
    mod_mul_add_into_acc_karatsuba(b, acc, x, y, p);
    mod_neg_inplace_fast(b, x, p);
}

