fn square_tx_and_combined_ty_l2minus3qx(
    b: &mut B,
    tx: &[QubitId],
    ty: &[QubitId],
    lam: &[QubitId],
    ox: &[BitId],
    p: U256,
) {
    let n = tx.len();
    debug_assert_eq!(n, 256);
    debug_assert_eq!(ty.len(), n);
    debug_assert_eq!(lam.len(), n);

    b.set_phase("affine_combined_square");
    let tmp_ext = b.alloc_qubits(2 * n);
    schoolbook_square_symmetric_lowq(b, lam, &tmp_ext);

    b.set_phase("affine_combined_breg_red");
    let breg = b.alloc_qubits(n);
    mod_add_solinas_ext_product(b, &breg, &tmp_ext, p);
    mod_sub_double_qb(b, &breg, ox, p);
    mod_sub_qb(b, &breg, ox, p);

    b.set_phase("affine_combined_y_mul");
    if env_flag_enabled("POINT_ADD_AFFINE_COMBINED_Y_KARATSUBA_LOWQ", false) {
        mod_mul_add_into_acc_karatsuba_lowq(b, ty, lam, &breg, p);
    } else {
        mod_mul_add_into_acc_selected(b, ty, lam, &breg, p, "POINT_ADD_AFFINE_COMBINED_Y_MUL");
    }

    b.set_phase("affine_combined_breg_unred");
    mod_add_qb(b, &breg, ox, p);
    mod_add_double_qb(b, &breg, ox, p);
    mod_sub_solinas_ext_product(b, &breg, &tmp_ext, p);
    b.free_vec(&breg);

    b.set_phase("affine_combined_tx_update");
    mod_sub_solinas_ext_product(b, tx, &tmp_ext, p);
    mod_add_double_qb(b, tx, ox, p);
    mod_add_qb(b, tx, ox, p);
    mod_neg_inplace_fast(b, tx, p);

    schoolbook_square_symmetric_lowq_inverse(b, lam, &tmp_ext);
    b.free_vec(&tmp_ext);
}

/// Schoolbook squarer with Bennett uncompute. For squaring `tmp_ext = x*x`
/// (2n bits, no mod reduction), then sub from acc with on-the-fly Solinas
/// reduction, then uncompute tmp_ext via gate-level inverse. Saves ~170k
/// CCX vs walk-x squaring (459k → 289k) by avoiding 256 expensive
/// cmod_add_qq calls (each 5n) in favor of 2n²=131k of cheap AND+Cuccaro.
fn squaring_sub_from_acc_schoolbook(b: &mut B, acc: &[QubitId], x: &[QubitId], p: U256) {
    let n = acc.len();
    debug_assert_eq!(n, 256);
    debug_assert_eq!(x.len(), n);
    let c = U256::MAX.wrapping_sub(p).wrapping_add(U256::from(1));

    // Wide accumulator (2n bits) starts at 0.
    let tmp_ext = b.alloc_qubits(2 * n);

    // Phase 1: symmetric schoolbook tmp_ext = x*x (~half the CCX of full).
    schoolbook_square_symmetric(b, x, &tmp_ext);

    // Phase 2: subtract (lo + hi*c mod p) from acc.
    // For each set bit k of c, sub (hi shifted by k mod p) from acc, by
    // walking hi via mod_double in place. Sub lo first.
    let lo: Vec<QubitId> = tmp_ext[0..n].to_vec();
    let hi: Vec<QubitId> = tmp_ext[n..2 * n].to_vec();
    mod_sub_qq_fast(b, acc, &lo, p);
    let _ = c;
    // 977 consolidation: c = {+2^0, +2^4, -2^6, +2^10, +2^32}. For acc-=hi·c, signs flip:
    // acc -= hi·2^0, acc -= hi·2^4, acc += hi·2^6, acc -= hi·2^10, acc -= hi·2^32.
    mod_sub_qq_fast(b, acc, &hi, p);
    for _ in 0..4 {
        mod_double_inplace_fast(b, &hi, p);
    }
    mod_sub_qq_fast(b, acc, &hi, p);
    for _ in 0..2 {
        mod_double_inplace_fast(b, &hi, p);
    }
    mod_add_qq_fast(b, acc, &hi, p); // sign flipped
    for _ in 0..4 {
        mod_double_inplace_fast(b, &hi, p);
    }
    mod_sub_qq_fast(b, acc, &hi, p);
    let (spill, flag_inv, ovf) = mod_shift_left_by_k(b, &hi, p, 22);
    mod_sub_qq(b, acc, &hi, p);
    mod_shift_right_by_k(b, &hi, p, 22, spill, flag_inv, ovf);
    for _ in 0..10 {
        mod_halve_inplace_fast(b, &hi, p);
    }

    // Phase 3: uncompute tmp_ext via symmetric schoolbook inverse.
    schoolbook_square_symmetric_inverse(b, x, &tmp_ext);

    b.free_vec(&tmp_ext);
}

fn squaring_sub_from_acc_schoolbook_lowq_shift22(
    b: &mut B,
    acc: &[QubitId],
    x: &[QubitId],
    p: U256,
) {
    let n = acc.len();
    debug_assert_eq!(n, 256);
    debug_assert_eq!(x.len(), n);
    let c = U256::MAX.wrapping_sub(p).wrapping_add(U256::from(1));

    let tmp_ext = b.alloc_qubits(2 * n);
    schoolbook_square_symmetric_lowq(b, x, &tmp_ext);

    let lo: Vec<QubitId> = tmp_ext[0..n].to_vec();
    let hi: Vec<QubitId> = tmp_ext[n..2 * n].to_vec();
    mod_sub_qq(b, acc, &lo, p);
    let _ = c;
    mod_sub_qq(b, acc, &hi, p);
    for _ in 0..4 {
        mod_double_inplace_direct_const_fast(b, &hi, p);
    }
    mod_sub_qq(b, acc, &hi, p);
    for _ in 0..2 {
        mod_double_inplace_direct_const_fast(b, &hi, p);
    }
    mod_add_qq(b, acc, &hi, p);
    for _ in 0..4 {
        mod_double_inplace_direct_const_fast(b, &hi, p);
    }
    mod_sub_qq(b, acc, &hi, p);
    let (spill, flag_inv, ovf) = mod_shift_left_by_k_lowq(b, &hi, p, 22);
    mod_sub_qq(b, acc, &hi, p);
    mod_shift_right_by_k_lowq(b, &hi, p, 22, spill, flag_inv, ovf);
    for _ in 0..10 {
        mod_halve_inplace_direct_const_fast(b, &hi, p);
    }

    schoolbook_square_symmetric_lowq_inverse(b, x, &tmp_ext);
    b.free_vec(&tmp_ext);
}

fn squaring_sub_from_acc_walk_controls_lowq(b: &mut B, acc: &[QubitId], x: &[QubitId], p: U256) {
    let n = acc.len();
    debug_assert_eq!(n, 256);
    debug_assert_eq!(x.len(), n);

    let ctrl_copy = b.alloc_qubits(n);
    for i in 0..n {
        b.cx(x[i], ctrl_copy[i]);
    }

    mod_neg_inplace_fast(b, x, p);
    for i in 0..n {
        cmod_add_qq(b, acc, x, ctrl_copy[i], p);
        if i < n - 1 {
            mod_double_inplace_fast(b, x, p);
        }
    }
    for _ in 0..(n - 1) {
        mod_halve_inplace_fast(b, x, p);
    }
    mod_neg_inplace_fast(b, x, p);

    for i in 0..n {
        b.cx(x[i], ctrl_copy[i]);
    }
    b.free_vec(&ctrl_copy);
}

/// Schoolbook: tmp_ext (2n bits) += x * x. Each row i adds (x[i] AND x)
/// shifted by i, captured in n+1 bits to absorb carry into position i+n.
fn schoolbook_square_into(b: &mut B, x: &[QubitId], tmp_ext: &[QubitId]) {
    let n = x.len();
    debug_assert_eq!(tmp_ext.len(), 2 * n);
    for i in 0..n {
        let row = b.alloc_qubits(n);
        for k in 0..n {
            b.ccx(x[i], x[k], row[k]);
        }
        let pad = b.alloc_qubit();
        let mut row_padded = row.clone();
        row_padded.push(pad);
        let slice: Vec<QubitId> = tmp_ext[i..i + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_add_fast(b, &row_padded, &slice, c_in);
        b.free(c_in);
        b.free(pad);
        // Unload row via measurement-based AND uncompute.
        for k in 0..n {
            let m = b.alloc_bit();
            b.hmr(row[k], m);
            b.cz_if(x[i], x[k], m);
        }
        b.free_vec(&row);
    }
}

/// Gate-level inverse of schoolbook_square_into. Subtracts the same
/// row contributions in reverse iteration order, returning tmp_ext to 0.
fn schoolbook_square_into_inverse(b: &mut B, x: &[QubitId], tmp_ext: &[QubitId]) {
    let n = x.len();
    for i in (0..n).rev() {
        let row = b.alloc_qubits(n);
        for k in 0..n {
            b.ccx(x[i], x[k], row[k]);
        }
        let pad = b.alloc_qubit();
        let mut row_padded = row.clone();
        row_padded.push(pad);
        let slice: Vec<QubitId> = tmp_ext[i..i + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_sub_fast(b, &row_padded, &slice, c_in);
        b.free(c_in);
        b.free(pad);
        for k in 0..n {
            let m = b.alloc_bit();
            b.hmr(row[k], m);
            b.cz_if(x[i], x[k], m);
        }
        b.free_vec(&row);
    }
}

fn mod_mul_sub_qq(b: &mut B, acc: &[QubitId], x: &[QubitId], y: &[QubitId], p: U256) {
    // acc -= x * y mod p. Negate x, run schoolbook ADD (cheaper than sub),
    // then restore x. For x≠y we can walk the negated multiplicand in place
    // and halve it back afterwards, avoiding the doubled tmp register. For
    // squaring we snapshot the original control bits once into `ctrl_copy`,
    // then reuse the same in-place walk on the negated x.
    let n = acc.len();
    let is_squaring = x[0] == y[0]; // same register → squaring
    if is_squaring {
        // Use the schoolbook squarer for the squaring case (~170k savings).
        if std::env::var("SECP_D1_WALK_SQUARE").ok().as_deref() == Some("1") {
            squaring_sub_from_acc_walk_controls_lowq(b, acc, x, p);
        } else if std::env::var("SECP_D1_LOWQ_SQUARE").ok().as_deref() == Some("1") {
            squaring_sub_from_acc_schoolbook_lowq_shift22(b, acc, x, p);
        } else {
            squaring_sub_from_acc_schoolbook(b, acc, x, p);
        }
        return;
    }
    if false {
        // Hold the original x bits fixed for control while x itself walks
        // through (-x)*2^i mod p.
        let ctrl_copy = b.alloc_qubits(n);
        for i in 0..n {
            b.cx(x[i], ctrl_copy[i]);
        }
        mod_neg_inplace_fast(b, x, p);
        for i in 0..n {
            cmod_add_qq(b, acc, x, ctrl_copy[i], p);
            if i < n - 1 {
                mod_double_inplace_fast(b, x, p);
            }
        }
        for _ in 0..(n - 1) {
            mod_halve_inplace_fast(b, x, p);
        }
        mod_neg_inplace_fast(b, x, p);
        for i in 0..n {
            b.cx(x[i], ctrl_copy[i]);
        }
        b.free_vec(&ctrl_copy);
    } else {
        // Keep x negated during the loop and walk it in place.
        mod_neg_inplace_fast(b, x, p);
        for i in 0..n {
            cmod_add_qq(b, acc, x, y[i], p);
            if i < n - 1 {
                mod_double_inplace_fast(b, x, p);
            }
        }
        for _ in 0..(n - 1) {
            mod_halve_inplace_fast(b, x, p);
        }
        mod_neg_inplace_fast(b, x, p);
    }
}

fn mod_mul_add_qb(b: &mut B, acc: &[QubitId], x: &[QubitId], y: &[BitId], p: U256) {
    let n = acc.len();
    let tmp = b.alloc_qubits(n);
    for i in 0..n {
        b.cx(x[i], tmp[i]);
    }
    for i in 0..n {
        // Mask the whole conditional-add body by y[i]: on shots where
        // y[i]=0 nothing needs to happen AND nothing should be counted.
        b.push_condition(y[i]);
        cmod_add_qq_bit(b, acc, &tmp, y[i], p);
        b.pop_condition();
        if i < n - 1 {
            mod_double_inplace_fast(b, &tmp, p);
        }
    }
    for _ in 0..(n - 1) {
        mod_halve_inplace_fast(b, &tmp, p);
    }
    for i in 0..n {
        b.cx(x[i], tmp[i]);
    }
    b.free_vec(&tmp);
}

fn mod_mul_sub_qb(b: &mut B, acc: &[QubitId], x: &[QubitId], y: &[BitId], p: U256) {
    let n = acc.len();
    let tmp = b.alloc_qubits(n);
    for i in 0..n {
        b.cx(x[i], tmp[i]);
    }
    for i in 0..n {
        b.push_condition(y[i]);
        cmod_sub_qq_bit(b, acc, &tmp, y[i], p);
        b.pop_condition();
        if i < n - 1 {
            mod_double_inplace_fast(b, &tmp, p);
        }
    }
    for _ in 0..(n - 1) {
        mod_halve_inplace_fast(b, &tmp, p);
    }
    for i in 0..n {
        b.cx(x[i], tmp[i]);
    }
    b.free_vec(&tmp);
}

// ═══════════════════════════════════════════════════════════════════════════
//  Kaliski almost-inverse
// ═══════════════════════════════════════════════════════════════════════════

/// Fredkin (controlled swap): swap (a, t) if ctrl. Decomposed as CX/CCX/CX.
fn cswap(b: &mut B, ctrl: QubitId, a: QubitId, t: QubitId) {
    if a == t {
        return;
    }
    assert!(
        ctrl != a && ctrl != t,
        "invalid CSWAP with control aliased to swapped wire"
    );
    b.cx(t, a);
    b.ccx(ctrl, a, t);
    b.cx(t, a);
}

fn cmod_double_inplace(b: &mut B, v: &[QubitId], p: U256, ctrl: QubitId) {
    let n = v.len();
    let ovf = b.alloc_qubit();
    let mut v_ext: Vec<QubitId> = v.to_vec();
    v_ext.push(ovf);

    // Conditional left-shift: if ctrl=1, v[n-1] → ovf; v[i] → v[i+1].
    cswap(b, ctrl, v[n - 1], ovf);
    for i in (0..n - 1).rev() {
        cswap(b, ctrl, v[i], v[i + 1]);
    }

    csub_nbit_const(b, &v_ext, p, ctrl);
    cadd_nbit_const(b, &v_ext, p, ovf);
    // ovf ends at 0 by the same argument as mod_double_inplace.
    b.free(ovf);
}

/// `cmod_halve_inplace` = exact inverse of `cmod_double_inplace`.
fn cmod_halve_inplace(b: &mut B, v: &[QubitId], p: U256, ctrl: QubitId) {
    let n = v.len();
    let ovf = b.alloc_qubit();
    let mut v_ext: Vec<QubitId> = v.to_vec();
    v_ext.push(ovf);

    // Inverse of: cadd(v_ext, p, ovf).
    csub_nbit_const(b, &v_ext, p, ovf);
    // Inverse of: csub(v_ext, p, ctrl).
    cadd_nbit_const(b, &v_ext, p, ctrl);
    // Inverse of cswap cascade (self-inverse; reversed order).
    for i in 0..n - 1 {
        cswap(b, ctrl, v[i], v[i + 1]);
    }
    cswap(b, ctrl, v[n - 1], ovf);

    b.free(ovf);
}

/// Run `body` with `flag` holding (u < v), then uncompute the flag and
/// restore u, v. Uses carry-ancilla + measurement-based uncomputation
/// for the inv_MAJ sweep (0 Toffoli instead of n CCX).
/// Cost ≈ n CCX (forward MAJ) + body + 0 CCX (measurement inv_MAJ).
fn with_lt<F: FnOnce(&mut B)>(b: &mut B, u: &[QubitId], v: &[QubitId], flag: QubitId, body: F) {
    let n = u.len();
    assert_eq!(n, v.len());
    let c_in = b.alloc_qubit();
    let carries = b.alloc_qubits(n);
    for i in 0..n {
        b.x(u[i]);
    }

    // Forward MAJ sweep with separate carry ancillae.
    // maj_with_carry: CX(w,y); CX(w,x); CCX(x_new,y_new,carry); CX(carry,w)
    // Step 0: (x=c_in, y=v[0], w=u[0])
    b.cx(u[0], v[0]);
    b.cx(u[0], c_in);
    b.ccx(c_in, v[0], carries[0]);
    b.cx(carries[0], u[0]);
    // Steps 1..n-1: (x=u[i-1], y=v[i], w=u[i])
    for i in 1..n {
        b.cx(u[i], v[i]);
        b.cx(u[i], u[i - 1]);
        b.ccx(u[i - 1], v[i], carries[i]);
        b.cx(carries[i], u[i]);
    }

    b.cx(u[n - 1], flag);
    body(b);
    b.cx(u[n - 1], flag);

    // Backward inv_MAJ sweep with measurement-based carry uncompute (0 Toffoli).
    // inv_maj_with_carry: CX(carry,w); HMR+CZ(carry,x,y); CX(w,x); CX(w,y)
    for i in (1..n).rev() {
        b.cx(carries[i], u[i]); // restore w = u[i]
        let m = b.alloc_bit();
        b.hmr(carries[i], m); // measure carry
        b.cz_if(u[i - 1], v[i], m); // phase correction
        b.cx(u[i], u[i - 1]); // restore x = u[i-1]
        b.cx(u[i], v[i]); // restore y = v[i]
    }
    // Step 0: (x=c_in, y=v[0], w=u[0])
    b.cx(carries[0], u[0]);
    let m0 = b.alloc_bit();
    b.hmr(carries[0], m0);
    b.cz_if(c_in, v[0], m0);
    b.cx(u[0], c_in);
    b.cx(u[0], v[0]);

    for i in 0..n {
        b.x(u[i]);
    }
    b.free_vec(&carries);
    b.free(c_in);
}

/// Symmetric helper: runs `body` with `flag` holding (u > v).
fn with_gt<F: FnOnce(&mut B)>(b: &mut B, u: &[QubitId], v: &[QubitId], flag: QubitId, body: F) {
    with_lt(b, v, u, flag, body)
}

fn with_gt_lowq<F: FnOnce(&mut B)>(
    b: &mut B,
    u: &[QubitId],
    v: &[QubitId],
    flag: QubitId,
    body: F,
) {
    cmp_lt_into(b, v, u, flag);
    body(b);
    cmp_lt_into(b, v, u, flag);
}

fn kal_step2_lowq_cmp_enabled() -> bool {
    std::env::var("KAL_STEP2_LOWQ_CMP").ok().as_deref() == Some("1")
}

fn kal_step2_with_gt<F: FnOnce(&mut B)>(
    b: &mut B,
    u: &[QubitId],
    v: &[QubitId],
    flag: QubitId,
    body: F,
) {
    if kal_step2_lowq_cmp_enabled() {
        with_gt_lowq(b, u, v, flag, body);
    } else {
        with_gt(b, u, v, flag, body);
    }
}

/// Run `body` with `flag` holding (v == 0), then uncompute. Single forward
/// OR chain + body + single inverse OR chain — half the cost of two
/// `cmp_eq_zero_into` calls.
fn with_eq_zero<F: FnOnce(&mut B)>(b: &mut B, v: &[QubitId], flag: QubitId, body: F) {
    let n = v.len();
    assert!(n > 0);
    if n == 1 {
        b.x(v[0]);
        b.cx(v[0], flag);
        body(b);
        b.cx(v[0], flag);
        b.x(v[0]);
        return;
    }
    let or_chain: Vec<QubitId> = b.alloc_qubits(n - 1);
    or_step(b, v[0], v[1], or_chain[0]);
    for i in 1..n - 1 {
        or_step(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }
    // or_chain[n-2] = (v != 0). Take complement for "== 0".
    b.x(or_chain[n - 2]);
    b.cx(or_chain[n - 2], flag);
    b.x(or_chain[n - 2]);
    body(b);
    b.x(or_chain[n - 2]);
    b.cx(or_chain[n - 2], flag);
    b.x(or_chain[n - 2]);
    for i in (1..n - 1).rev() {
        or_step(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }
    or_step(b, v[0], v[1], or_chain[0]);
    b.free_vec(&or_chain);
}

/// flag ^= (u < v).  Non-destructive on u and v.
///
/// Uses a MAJ-only carry chain instead of the full sub+add pattern.
/// Identity: u < v iff carry-out of (~u + v) = 1, since
///   ~u + v = (2^n - 1 - u) + v = (v - u) + (2^n - 1)
/// which overflows 2^n iff v - u ≥ 1 iff v > u. We negate u in place,
/// run a forward MAJ sweep over (~u, v, c_in=0), capture u[n-1] (which
/// holds the high carry after the chain), then run the inverse MAJ
/// sweep + un-negate to restore u and v. Cost ≈ 2n CCX, half of the
/// previous sub+add (≈ 4n CCX).
fn cmp_lt_into(b: &mut B, u: &[QubitId], v: &[QubitId], flag: QubitId) {
    let n = u.len();
    assert_eq!(n, v.len());

    let c_in = b.alloc_qubit();

    // ~u in place (X is free in the metric).
    for i in 0..n {
        b.x(u[i]);
    }

    // Forward MAJ sweep — n MAJs (one more than cuccaro_add, which omits
    // the top one because it doesn't need the carry-out).
    maj(b, c_in, v[0], u[0]);
    for i in 1..n {
        maj(b, u[i - 1], v[i], u[i]);
    }
    // u[n-1] now holds the high carry = (u < v).
    b.cx(u[n - 1], flag);

    // Inverse sweep restores u and v to their (negated u) state.
    for i in (1..n).rev() {
        inv_maj(b, u[i - 1], v[i], u[i]);
    }
    inv_maj(b, c_in, v[0], u[0]);

    // Un-negate u.
    for i in 0..n {
        b.x(u[i]);
    }

    b.free(c_in);
}

/// flag ^= (v != 0). Computes OR of all bits of v into a scratch ancilla,
/// CXs into flag, then properly uncomputes the scratch.
///
/// We use the simple chain: `or[0] = v[0]`, `or[i] = or[i-1] OR v[i]`.
/// OR via de Morgan: `or[i] = NOT((NOT or[i-1]) AND (NOT v[i]))`, i.e.
///   x(or[i-1]); x(v[i]); ccx(or[i-1], v[i], or[i]); x(or[i]);
///   x(v[i]); x(or[i-1]);
/// Each `or[i]` is a fresh ancilla. We compute the chain, CX `or[n-1]`
/// into `flag`, then reverse the chain to return every ancilla to |0⟩.
fn cmp_neq_zero_into(b: &mut B, v: &[QubitId], flag: QubitId) {
    let n = v.len();
    assert!(n > 0);
    if n == 1 {
        b.cx(v[0], flag);
        return;
    }

    let or_chain: Vec<QubitId> = b.alloc_qubits(n - 1);
    // or_chain[0] = v[0] OR v[1]
    or_step(b, v[0], v[1], or_chain[0]);
    for i in 1..n - 1 {
        or_step(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }

    // flag ^= or_chain[n-2]
    b.cx(or_chain[n - 2], flag);

    // Uncompute.
    for i in (1..n - 1).rev() {
        or_step(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }
    or_step(b, v[0], v[1], or_chain[0]);

    b.free_vec(&or_chain);
}

/// out ^= (x OR y). `out` starts 0. Uses the de-Morgan form:
///   x(x); x(y); ccx(x, y, out); x(out); x(y); x(x);
/// After this, out = x OR y (assuming out started at 0). Its inverse is
/// the same gate sequence run in reverse — since it's symmetric (all gates
/// involutions, palindromic structure), running the exact same helper
/// again uncomputes it.
fn or_step(b: &mut B, x: QubitId, y: QubitId, out: QubitId) {
    b.x(x);
    b.x(y);
    b.ccx(x, y, out);
    b.x(out);
    b.x(y);
    b.x(x);
}

// ═══════════════════════════════════════════════════════════════════════════
//  Primitives for the Kaliski port (qrisp-style)
// ═══════════════════════════════════════════════════════════════════════════

/// 2-controlled X with per-control polarity. `polarity=true` means positive
/// control; `false` means anti-control (ctrl=0 triggers).
fn mcx2_polar(b: &mut B, c1: QubitId, p1: bool, c2: QubitId, p2: bool, target: QubitId) {
    if !p1 {
        b.x(c1);
    }
    if !p2 {
        b.x(c2);
    }
    b.ccx(c1, c2, target);
    if !p2 {
        b.x(c2);
    }
    if !p1 {
        b.x(c1);
    }
}

/// 3-controlled X with per-control polarity. Uses a borrowed scratch qubit
/// (must be supplied clean, returns clean).
fn mcx3_polar(
    b: &mut B,
    c1: QubitId,
    p1: bool,
    c2: QubitId,
    p2: bool,
    c3: QubitId,
    p3: bool,
    target: QubitId,
    scratch: QubitId,
) {
    if !p1 {
        b.x(c1);
    }
    if !p2 {
        b.x(c2);
    }
    if !p3 {
        b.x(c3);
    }
    b.ccx(c1, c2, scratch);
    b.ccx(scratch, c3, target);
    b.ccx(c1, c2, scratch);
    if !p3 {
        b.x(c3);
    }
    if !p2 {
        b.x(c2);
    }
    if !p1 {
        b.x(c1);
    }
}

/// flag ^= (v == 0).  Uses cmp_neq_zero_into internally.
fn cmp_eq_zero_into(b: &mut B, v: &[QubitId], flag: QubitId) {
    b.x(flag);
    cmp_neq_zero_into(b, v, flag);
}

/// flag ^= (u > v).  Symmetric to cmp_lt_into(v, u, flag).
fn cmp_gt_into(b: &mut B, u: &[QubitId], v: &[QubitId], flag: QubitId) {
    cmp_lt_into(b, v, u, flag);
}

/// Controlled n-bit subtract mod 2^n: if ctrl, acc -= a. Both are n-wide
/// qubit slices. Not a mod-p operation.
fn cucc_sub_ctrl(b: &mut B, a: &[QubitId], acc: &[QubitId], ctrl: QubitId) {
    let n = a.len();
    let tmp = b.alloc_qubits(n);
    for i in 0..n {
        b.ccx(ctrl, a[i], tmp[i]);
    }
    sub_nbit_qq(b, &tmp, acc);
    for i in 0..n {
        b.ccx(ctrl, a[i], tmp[i]);
    }
    b.free_vec(&tmp);
}

fn ctrl_maj(b: &mut B, ctrl: QubitId, x: QubitId, y: QubitId, w: QubitId, scratch: QubitId) {
    b.ccx(ctrl, w, y);
    b.ccx(ctrl, w, x);
    mcx3_polar(b, ctrl, true, x, true, y, true, w, scratch);
}

fn ctrl_uma(b: &mut B, ctrl: QubitId, x: QubitId, y: QubitId, w: QubitId, scratch: QubitId) {
    mcx3_polar(b, ctrl, true, x, true, y, true, w, scratch);
    b.ccx(ctrl, w, x);
    b.ccx(ctrl, x, y);
}

fn ctrl_inv_maj(b: &mut B, ctrl: QubitId, x: QubitId, y: QubitId, w: QubitId, scratch: QubitId) {
    mcx3_polar(b, ctrl, true, x, true, y, true, w, scratch);
    b.ccx(ctrl, w, x);
    b.ccx(ctrl, w, y);
}

fn ctrl_inv_uma(b: &mut B, ctrl: QubitId, x: QubitId, y: QubitId, w: QubitId, scratch: QubitId) {
    b.ccx(ctrl, x, y);
    b.ccx(ctrl, w, x);
    mcx3_polar(b, ctrl, true, x, true, y, true, w, scratch);
}

fn cuccaro_add_ctrl_lowq(
    b: &mut B,
    a: &[QubitId],
    acc: &[QubitId],
    ctrl: QubitId,
    c_in: QubitId,
    scratch: QubitId,
) {
    let n = a.len();
    assert_eq!(n, acc.len());
    if n == 0 {
        return;
    }
    if n == 1 {
        b.ccx(ctrl, c_in, acc[0]);
        b.ccx(ctrl, a[0], acc[0]);
        return;
    }

    ctrl_maj(b, ctrl, c_in, acc[0], a[0], scratch);
    for i in 1..n - 1 {
        ctrl_maj(b, ctrl, a[i - 1], acc[i], a[i], scratch);
    }

    b.ccx(ctrl, a[n - 2], acc[n - 1]);
    b.ccx(ctrl, a[n - 1], acc[n - 1]);

    for i in (1..n - 1).rev() {
        ctrl_uma(b, ctrl, a[i - 1], acc[i], a[i], scratch);
    }
    ctrl_uma(b, ctrl, c_in, acc[0], a[0], scratch);
}

fn cuccaro_sub_ctrl_lowq(
    b: &mut B,
    a: &[QubitId],
    acc: &[QubitId],
    ctrl: QubitId,
    c_in: QubitId,
    scratch: QubitId,
) {
    let n = a.len();
    assert_eq!(n, acc.len());
    if n == 0 {
        return;
    }
    if n == 1 {
        b.ccx(ctrl, a[0], acc[0]);
        b.ccx(ctrl, c_in, acc[0]);
        return;
    }

    ctrl_inv_uma(b, ctrl, c_in, acc[0], a[0], scratch);
    for i in 1..n - 1 {
        ctrl_inv_uma(b, ctrl, a[i - 1], acc[i], a[i], scratch);
    }

    b.ccx(ctrl, a[n - 1], acc[n - 1]);
    b.ccx(ctrl, a[n - 2], acc[n - 1]);

    for i in (1..n - 1).rev() {
        ctrl_inv_maj(b, ctrl, a[i - 1], acc[i], a[i], scratch);
    }
    ctrl_inv_maj(b, ctrl, c_in, acc[0], a[0], scratch);
}

fn cucc_add_ctrl_lowq(b: &mut B, a: &[QubitId], acc: &[QubitId], ctrl: QubitId) {
    let c_in = b.alloc_qubit();
    let scratch = b.alloc_qubit();
    cuccaro_add_ctrl_lowq(b, a, acc, ctrl, c_in, scratch);
    b.free(scratch);
    b.free(c_in);
}

fn cucc_sub_ctrl_lowq(b: &mut B, a: &[QubitId], acc: &[QubitId], ctrl: QubitId) {
    let c_in = b.alloc_qubit();
    let scratch = b.alloc_qubit();
    cuccaro_sub_ctrl_lowq(b, a, acc, ctrl, c_in, scratch);
    b.free(scratch);
    b.free(c_in);
}

/// Controlled n-bit add mod 2^n: if ctrl, acc += a.
fn cucc_add_ctrl(b: &mut B, a: &[QubitId], acc: &[QubitId], ctrl: QubitId) {
    let n = a.len();
    let tmp = b.alloc_qubits(n);
    for i in 0..n {
        b.ccx(ctrl, a[i], tmp[i]);
    }
    add_nbit_qq(b, &tmp, acc);
    for i in 0..n {
        b.ccx(ctrl, a[i], tmp[i]);
    }
    b.free_vec(&tmp);
}

/// Controlled shift-right by 1 of an n-bit register. ASSUMES v[0]=0 when
/// ctrl=1 (so no information is lost). Implemented as a controlled swap
/// cascade: if ctrl=1, new v[i] = old v[i+1] for i < n-1, new v[n-1] = 0.
fn c_shift_right_1(b: &mut B, v: &[QubitId], ctrl: QubitId) {
    let n = v.len();
    for i in 0..(n - 1) {
        cswap(b, ctrl, v[i], v[i + 1]);
    }
}

/// Unconditional shift-left by 1 of an (n+1)-bit register. ASSUMES r[n]=0
/// before the shift. After the shift: r[0]=0, r[i] = old r[i-1] for i ∈ [1, n].
fn shift_left_1(b: &mut B, r: &[QubitId]) {
    let n1 = r.len(); // n+1
                      // Swap r[n] ↔ r[0] first: r[0] gets the known-0 top bit.
    b.swap(r[n1 - 1], r[0]);
    // Then propagate: swap r[n] ↔ r[n-1], r[n-1] ↔ r[n-2], ..., r[2] ↔ r[1].
    for i in (2..n1).rev() {
        b.swap(r[i], r[i - 1]);
    }
}

/// Inverse of `shift_left_1`: shifts an (n+1)-bit register right by 1.
/// ASSUMES r[0]=0 before the shift (i.e., was even).
#[allow(dead_code)]
fn shift_right_1(b: &mut B, r: &[QubitId]) {
    let n1 = r.len();
    for i in 2..n1 {
        b.swap(r[i], r[i - 1]);
    }
    b.swap(r[n1 - 1], r[0]);
}

/// flag ^= (r > c).  r is (n+1)-wide; c is a compile-time constant.
/// Non-destructive: r is restored at the end.
fn cmp_gt_const_n1(b: &mut B, r: &[QubitId], c: U256, flag: QubitId) {
    let n1 = r.len();
    let c_plus_1 = c.wrapping_add(U256::from(1));
    sub_nbit_const(b, r, c_plus_1);
    // If r - (c+1) >= 0 (top bit 0), then r > c.
    b.x(r[n1 - 1]);
    b.cx(r[n1 - 1], flag);
    b.x(r[n1 - 1]);
    add_nbit_const(b, r, c_plus_1);
}

fn build_round629_frontier_predicate_stream_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const PACKED_WIDTH: usize = N + 1;

    let mut b = B::new();
    let frontier = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&frontier);
    let flag = b.alloc_qubit();
    b.declare_qubit_register(&[flag]);

    b.set_phase("round629_low_threshold_predicates");
    for i in 0..PACKED_WIDTH {
        let c = U256::from(i as u64);
        cmp_gt_const_n1(&mut b, &frontier, c, flag);
        cmp_gt_const_n1(&mut b, &frontier, c, flag);
    }

    b.set_phase("round629_high_threshold_predicates");
    for i in 0..PACKED_WIDTH {
        let c = U256::from(i as u64);
        cmp_gt_const_n1(&mut b, &frontier, c, flag);
        cmp_gt_const_n1(&mut b, &frontier, c, flag);
    }

    b
}

pub fn build_round629_frontier_predicate_stream_component() -> Vec<Op> {
    build_round629_frontier_predicate_stream_builder().ops
}

pub fn build_round629_frontier_predicate_stream_phase_resources(
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round629_frontier_predicate_stream_builder();
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

fn round630_emit_threshold_compute_uncompute(
    b: &mut B,
    frontier: &[QubitId],
    flag: QubitId,
    c: usize,
) {
    let c = U256::from(c as u64);
    cmp_gt_const_n1(b, frontier, c, flag);
    cmp_gt_const_n1(b, frontier, c, flag);
}

fn round630_emit_boundary_pair_compute_uncompute(
    b: &mut B,
    frontier: &[QubitId],
    lower_flag: QubitId,
    upper_flag: QubitId,
    c: usize,
) {
    cmp_gt_const_n1(b, frontier, U256::from(c as u64), lower_flag);
    cmp_gt_const_n1(b, frontier, U256::from((c + 1) as u64), upper_flag);
    cmp_gt_const_n1(b, frontier, U256::from((c + 1) as u64), upper_flag);
    cmp_gt_const_n1(b, frontier, U256::from(c as u64), lower_flag);
}

fn build_round630_variable_cuccaro_predicate_schedule_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const PACKED_WIDTH: usize = N + 1;

    let mut b = B::new();
    let frontier = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&frontier);
    let flag_a = b.alloc_qubit();
    let flag_b = b.alloc_qubit();
    b.declare_qubit_register(&[flag_a, flag_b]);

    b.set_phase("round630_low_forward_active");
    for i in 0..PACKED_WIDTH {
        round630_emit_threshold_compute_uncompute(&mut b, &frontier, flag_a, i);
    }

    b.set_phase("round630_low_top_boundary");
    for i in 0..PACKED_WIDTH {
        round630_emit_boundary_pair_compute_uncompute(&mut b, &frontier, flag_a, flag_b, i);
    }

    b.set_phase("round630_low_backward_active");
    for i in 0..PACKED_WIDTH {
        round630_emit_threshold_compute_uncompute(&mut b, &frontier, flag_a, i);
    }

    b.set_phase("round630_high_forward_active");
    for i in 0..PACKED_WIDTH {
        round630_emit_threshold_compute_uncompute(&mut b, &frontier, flag_a, i);
    }

    b.set_phase("round630_high_top_boundary");
    for i in 0..PACKED_WIDTH {
        round630_emit_boundary_pair_compute_uncompute(&mut b, &frontier, flag_a, flag_b, i);
    }

    b.set_phase("round630_high_backward_active");
    for i in 0..PACKED_WIDTH {
        round630_emit_threshold_compute_uncompute(&mut b, &frontier, flag_a, i);
    }

    b
}

pub fn build_round630_variable_cuccaro_predicate_schedule_component() -> Vec<Op> {
    build_round630_variable_cuccaro_predicate_schedule_builder().ops
}

pub fn build_round630_variable_cuccaro_predicate_schedule_phase_resources(
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round630_variable_cuccaro_predicate_schedule_builder();
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

fn round631_emit_eq_const_toggle(
    b: &mut B,
    frontier: &[QubitId],
    value: usize,
    target: QubitId,
    scratch: &[QubitId],
) {
    let n = frontier.len();
    assert!(n >= 2);
    assert!(value < (1usize << n));
    assert!(scratch.len() >= n - 2);

    for i in 0..n {
        if ((value >> i) & 1) == 0 {
            b.x(frontier[i]);
        }
    }

    if n == 2 {
        b.ccx(frontier[0], frontier[1], target);
    } else {
        b.ccx(frontier[0], frontier[1], scratch[0]);
        for i in 2..n - 1 {
            b.ccx(scratch[i - 2], frontier[i], scratch[i - 1]);
        }
        b.ccx(scratch[n - 3], frontier[n - 1], target);
        for i in (2..n - 1).rev() {
            b.ccx(scratch[i - 2], frontier[i], scratch[i - 1]);
        }
        b.ccx(frontier[0], frontier[1], scratch[0]);
    }

    for i in (0..n).rev() {
        if ((value >> i) & 1) == 0 {
            b.x(frontier[i]);
        }
    }
}

fn round640_emit_eq_const_except_toggle(
    b: &mut B,
    bits: &[QubitId],
    skip: usize,
    value: usize,
    target: QubitId,
    scratch: &[QubitId],
) {
    assert!(skip < bits.len());
    let mut selected = Vec::with_capacity(bits.len() - 1);
    let mut compressed = 0usize;
    for (idx, bit) in bits.iter().enumerate() {
        if idx == skip {
            continue;
        }
        if ((value >> idx) & 1) != 0 {
            compressed |= 1usize << selected.len();
        }
        selected.push(*bit);
    }
    round631_emit_eq_const_toggle(b, &selected, compressed, target, scratch);
}

fn round631_emit_low_active_stream(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    scratch: &[QubitId],
    width: usize,
) {
    b.x(active);
    round631_emit_eq_const_toggle(b, frontier, 0, active, scratch);
    for value in 1..=width {
        round631_emit_eq_const_toggle(b, frontier, value, active, scratch);
    }
}

fn round631_emit_high_active_stream(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    scratch: &[QubitId],
    width: usize,
) {
    b.x(active);
    round631_emit_eq_const_toggle(b, frontier, width, active, scratch);
    for value in (0..width).rev() {
        round631_emit_eq_const_toggle(b, frontier, value, active, scratch);
    }
}

fn round631_emit_boundary_stream(
    b: &mut B,
    frontier: &[QubitId],
    boundary: QubitId,
    scratch: &[QubitId],
    values: impl Iterator<Item = usize>,
) {
    for value in values {
        round631_emit_eq_const_toggle(b, frontier, value, boundary, scratch);
        round631_emit_eq_const_toggle(b, frontier, value, boundary, scratch);
    }
}

fn build_round631_frontier_equality_stream_schedule_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const PACKED_WIDTH: usize = N + 1;

    let mut b = B::new();
    let frontier = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&frontier);
    let active = b.alloc_qubit();
    let boundary = b.alloc_qubit();
    b.declare_qubit_register(&[active, boundary]);
    let scratch = b.alloc_qubits(FRONTIER_BITS - 2);

    b.set_phase("round631_low_forward_active_stream");
    round631_emit_low_active_stream(&mut b, &frontier, active, &scratch, PACKED_WIDTH);

    b.set_phase("round631_low_boundary_eq_stream");
    round631_emit_boundary_stream(&mut b, &frontier, boundary, &scratch, 1..=PACKED_WIDTH);

    b.set_phase("round631_low_backward_active_stream");
    round631_emit_low_active_stream(&mut b, &frontier, active, &scratch, PACKED_WIDTH);

    b.set_phase("round631_high_forward_active_stream");
    round631_emit_high_active_stream(&mut b, &frontier, active, &scratch, PACKED_WIDTH);

    b.set_phase("round631_high_boundary_eq_stream");
    round631_emit_boundary_stream(&mut b, &frontier, boundary, &scratch, 0..PACKED_WIDTH);

    b.set_phase("round631_high_backward_active_stream");
    round631_emit_high_active_stream(&mut b, &frontier, active, &scratch, PACKED_WIDTH);

    b.set_phase("round631_free_stream_scratch");
    b.free_vec(&scratch);
    b
}

pub fn build_round631_frontier_equality_stream_schedule_component() -> Vec<Op> {
    build_round631_frontier_equality_stream_schedule_builder().ops
}

pub fn build_round631_frontier_equality_stream_schedule_phase_resources(
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round631_frontier_equality_stream_schedule_builder();
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

fn round632_compute_body_ctrl(b: &mut B, step_ctrl: QubitId, local: QubitId, body_ctrl: QubitId) {
    b.ccx(step_ctrl, local, body_ctrl);
}

fn round632_uncompute_body_ctrl(b: &mut B, step_ctrl: QubitId, local: QubitId, body_ctrl: QubitId) {
    b.ccx(step_ctrl, local, body_ctrl);
}

fn round632_low_interior_forward_init(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    b.x(active);
    round631_emit_eq_const_toggle(b, frontier, 0, active, eq_scratch);
    round631_emit_eq_const_toggle(b, frontier, 1, active, eq_scratch);
    let _ = PACKED_WIDTH;
}

fn round632_low_interior_forward_next(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    bit: usize,
) {
    round631_emit_eq_const_toggle(b, frontier, bit + 2, active, eq_scratch);
}

fn round632_low_interior_backward_init(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    width: usize,
) {
    round631_emit_eq_const_toggle(b, frontier, width, active, eq_scratch);
}

fn round632_low_interior_backward_next(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    bit: usize,
) {
    if bit > 0 {
        round631_emit_eq_const_toggle(b, frontier, bit + 1, active, eq_scratch);
    }
}

fn round632_low_interior_backward_clean(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
) {
    round631_emit_eq_const_toggle(b, frontier, 1, active, eq_scratch);
    round631_emit_eq_const_toggle(b, frontier, 0, active, eq_scratch);
    b.x(active);
}

fn round632_high_interior_forward_init(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    width: usize,
) {
    b.x(active);
    round631_emit_eq_const_toggle(b, frontier, width - 1, active, eq_scratch);
    round631_emit_eq_const_toggle(b, frontier, width, active, eq_scratch);
}

fn round632_high_interior_forward_next(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    bit: usize,
) {
    if bit > 1 {
        round631_emit_eq_const_toggle(b, frontier, bit - 1, active, eq_scratch);
    }
}

fn round632_high_interior_forward_clean(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
) {
    round631_emit_eq_const_toggle(b, frontier, 0, active, eq_scratch);
}

fn round632_high_interior_backward_init(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
) {
    round631_emit_eq_const_toggle(b, frontier, 0, active, eq_scratch);
}

fn round632_high_interior_backward_next(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    bit: usize,
) {
    if bit + 1 < N + 1 {
        round631_emit_eq_const_toggle(b, frontier, bit, active, eq_scratch);
    }
}

fn round632_high_interior_backward_clean(
    b: &mut B,
    frontier: &[QubitId],
    active: QubitId,
    eq_scratch: &[QubitId],
    width: usize,
) {
    b.x(active);
    round631_emit_eq_const_toggle(b, frontier, width - 1, active, eq_scratch);
    round631_emit_eq_const_toggle(b, frontier, width, active, eq_scratch);
}

fn round632_emit_low_sub_body(
    b: &mut B,
    src: &[QubitId],
    dst: &[QubitId],
    frontier: &[QubitId],
    step_ctrl: QubitId,
    active: QubitId,
    boundary: QubitId,
    body_ctrl: QubitId,
    c_in: QubitId,
    body_scratch: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(src.len(), PACKED_WIDTH);
    debug_assert_eq!(dst.len(), PACKED_WIDTH);

    b.set_phase("round632_low_sub_forward_interior");
    round632_low_interior_forward_init(b, frontier, active, eq_scratch);
    for bit in 0..PACKED_WIDTH - 1 {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_inv_uma(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_forward_next(b, frontier, active, eq_scratch, bit);
    }

    b.set_phase("round632_low_sub_boundary_sum");
    for bit in 0..PACKED_WIDTH {
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        b.ccx(body_ctrl, src[bit], dst[bit]);
        b.ccx(body_ctrl, carry, dst[bit]);
        round632_uncompute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
    }

    b.set_phase("round632_low_sub_backward_interior");
    round632_low_interior_backward_init(b, frontier, active, eq_scratch, PACKED_WIDTH);
    for bit in (0..PACKED_WIDTH - 1).rev() {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_inv_maj(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_backward_next(b, frontier, active, eq_scratch, bit);
    }
    round632_low_interior_backward_clean(b, frontier, active, eq_scratch);
}

fn round658_latch_borrow_majority(
    b: &mut B,
    body_ctrl: QubitId,
    carry: QubitId,
    dst_bit: QubitId,
    src_bit: QubitId,
    borrow_flag: QubitId,
    scratch: QubitId,
) {
    mcx3_polar(
        b,
        body_ctrl,
        true,
        src_bit,
        true,
        carry,
        true,
        borrow_flag,
        scratch,
    );
    mcx3_polar(
        b,
        body_ctrl,
        true,
        dst_bit,
        false,
        carry,
        true,
        borrow_flag,
        scratch,
    );
    mcx3_polar(
        b,
        body_ctrl,
        true,
        dst_bit,
        false,
        src_bit,
        true,
        borrow_flag,
        scratch,
    );
}

fn round658_emit_low_sub_body_with_borrow(
    b: &mut B,
    src: &[QubitId],
    dst: &[QubitId],
    frontier: &[QubitId],
    step_ctrl: QubitId,
    borrow_flag: QubitId,
    active: QubitId,
    boundary: QubitId,
    body_ctrl: QubitId,
    c_in: QubitId,
    body_scratch: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(src.len(), PACKED_WIDTH);
    debug_assert_eq!(dst.len(), PACKED_WIDTH);

    b.set_phase("round658_low_sub_borrow_forward_interior");
    round632_low_interior_forward_init(b, frontier, active, eq_scratch);
    for bit in 0..PACKED_WIDTH - 1 {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_inv_uma(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_forward_next(b, frontier, active, eq_scratch, bit);
    }

    b.set_phase("round658_low_sub_boundary_borrow_and_sum");
    for bit in 0..PACKED_WIDTH {
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        round658_latch_borrow_majority(
            b,
            body_ctrl,
            carry,
            dst[bit],
            src[bit],
            borrow_flag,
            body_scratch,
        );
        b.ccx(body_ctrl, src[bit], dst[bit]);
        b.ccx(body_ctrl, carry, dst[bit]);
        round632_uncompute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
    }

    b.set_phase("round658_low_sub_borrow_backward_interior");
    round632_low_interior_backward_init(b, frontier, active, eq_scratch, PACKED_WIDTH);
    for bit in (0..PACKED_WIDTH - 1).rev() {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_inv_maj(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_backward_next(b, frontier, active, eq_scratch, bit);
    }
    round632_low_interior_backward_clean(b, frontier, active, eq_scratch);
}

