fn round659_emit_source_over_frontier_pairs(
    b: &mut B,
    source_lane: &[QubitId],
    source_start: &[QubitId],
    dst_start: &[QubitId],
    step_ctrl: QubitId,
    overflow_flag: QubitId,
    eq_a: QubitId,
    eq_b: QubitId,
    pair_ctrl: QubitId,
    body_scratch: QubitId,
    eq_scratch: &[QubitId],
    or_chain: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    const MAX_DELTA: usize = 19;
    debug_assert_eq!(source_lane.len(), PACKED_WIDTH);
    debug_assert!(or_chain.len() >= MAX_DELTA - 1);

    for delta in 1..=MAX_DELTA {
        for lower in 0..=PACKED_WIDTH - delta {
            round653_compute_pair_ctrl(
                b,
                source_start,
                dst_start,
                lower + delta,
                lower,
                step_ctrl,
                eq_a,
                eq_b,
                pair_ctrl,
                body_scratch,
                eq_scratch,
            );
            round653_ctrl_range_or_into(
                b,
                pair_ctrl,
                source_lane,
                lower,
                delta,
                overflow_flag,
                or_chain,
                body_scratch,
            );
            round653_uncompute_pair_ctrl(
                b,
                source_start,
                dst_start,
                lower + delta,
                lower,
                step_ctrl,
                eq_a,
                eq_b,
                pair_ctrl,
                body_scratch,
                eq_scratch,
            );
        }
    }
}

