fn round662_emit_low_add_body(
    b: &mut B,
    src: &[QubitId],
    dst: &[QubitId],
    frontier: &[QubitId],
    step_ctrl: QubitId,
    active: QubitId,
    boundary: QubitId,
    body_ctrl: QubitId,
    c_in: QubitId,
    body_scratch: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(src.len(), PACKED_WIDTH);
    debug_assert_eq!(dst.len(), PACKED_WIDTH);

    b.set_phase("round662_low_add_forward_interior");
    round632_low_interior_forward_init(b, frontier, active, eq_scratch);
    for bit in 0..PACKED_WIDTH - 1 {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_maj(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_forward_next(b, frontier, active, eq_scratch, bit);
    }

    b.set_phase("round662_low_add_boundary_sum");
    for bit in 0..PACKED_WIDTH {
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        b.ccx(body_ctrl, carry, dst[bit]);
        b.ccx(body_ctrl, src[bit], dst[bit]);
        round632_uncompute_body_ctrl(b, step_ctrl, boundary, body_ctrl);
        round631_emit_eq_const_toggle(b, frontier, bit + 1, boundary, eq_scratch);
    }

    b.set_phase("round662_low_add_backward_interior");
    round632_low_interior_backward_init(b, frontier, active, eq_scratch, PACKED_WIDTH);
    for bit in (0..PACKED_WIDTH - 1).rev() {
        let carry = if bit == 0 { c_in } else { src[bit - 1] };
        round632_compute_body_ctrl(b, step_ctrl, active, body_ctrl);
        ctrl_uma(b, body_ctrl, carry, dst[bit], src[bit], body_scratch);
        round632_uncompute_body_ctrl(b, step_ctrl, active, body_ctrl);
        round632_low_interior_backward_next(b, frontier, active, eq_scratch, bit);
    }
    round632_low_interior_backward_clean(b, frontier, active, eq_scratch);
}

fn build_round662_borrow_branch_recovery_arithmetic_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const PACKED_WIDTH: usize = N + 1;

    let mut b = B::new();
    let lane_a = b.alloc_qubits(PACKED_WIDTH);
    b.declare_qubit_register(&lane_a);
    let lane_b = b.alloc_qubits(PACKED_WIDTH);
    b.declare_qubit_register(&lane_b);
    let start_a = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_a);
    let start_b = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_b);
    let borrow_ctrl = b.alloc_qubit();
    b.declare_qubit_register(&[borrow_ctrl]);

    let active = b.alloc_qubit();
    let boundary = b.alloc_qubit();
    let body_ctrl = b.alloc_qubit();
    let c_in = b.alloc_qubit();
    let body_scratch = b.alloc_qubit();
    let eq_scratch = b.alloc_qubits(FRONTIER_BITS - 2);
    let min_start = b.alloc_qubits(FRONTIER_BITS);
    let rhs_lt_lhs = b.alloc_qubit();

    round662_emit_low_add_body(
        &mut b,
        &lane_a,
        &lane_b,
        &start_b,
        borrow_ctrl,
        active,
        boundary,
        body_ctrl,
        c_in,
        body_scratch,
        &eq_scratch,
    );

    round634_emit_min_frontier_compute(&mut b, &start_a, &start_b, &min_start, rhs_lt_lhs);
    round632_emit_high_add_body(
        &mut b,
        &lane_a,
        &lane_b,
        &min_start,
        borrow_ctrl,
        active,
        boundary,
        body_ctrl,
        c_in,
        body_scratch,
        &eq_scratch,
    );
    round634_emit_min_frontier_uncompute(&mut b, &start_a, &start_b, &min_start, rhs_lt_lhs);

    round632_emit_low_sub_body(
        &mut b,
        &lane_b,
        &lane_a,
        &start_b,
        borrow_ctrl,
        active,
        boundary,
        body_ctrl,
        c_in,
        body_scratch,
        &eq_scratch,
    );

    round648_emit_step9_cswap(&mut b, borrow_ctrl, &lane_a, &lane_b, &start_a, &start_b);

    b.set_phase("round662_free_recovery_scratch");
    b.free(rhs_lt_lhs);
    b.free_vec(&min_start);
    b.free_vec(&eq_scratch);
    b.free(body_scratch);
    b.free(c_in);
    b.free(body_ctrl);
    b.free(boundary);
    b.free(active);
    b
}

