fn round664_emit_delta_growth_frontier_update(
    b: &mut B,
    start_a: &[QubitId],
    start_b: &[QubitId],
    delta_bits: &[QubitId],
    growth_ctrl: QubitId,
    swap_ctrl: QubitId,
) {
    debug_assert_eq!(start_a.len(), 9);
    debug_assert_eq!(start_b.len(), 9);
    debug_assert_eq!(delta_bits.len(), 4);

    b.set_phase("round664_apply_delta_to_start_b");
    for (bit, delta_bit) in delta_bits.iter().enumerate() {
        csub_nbit_const_direct_fast(b, start_b, U256::from(1u64 << bit), *delta_bit);
    }

    b.set_phase("round664_apply_growth_decrement");
    csub_nbit_const_direct_fast(b, start_b, U256::from(1u64), growth_ctrl);

    b.set_phase("round664_swap_refreshed_frontiers");
    for i in 0..start_a.len() {
        cswap(b, swap_ctrl, start_a[i], start_b[i]);
    }
}

fn build_round664_delta_growth_frontier_update_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const DELTA_BITS: usize = 4;

    let mut b = B::new();
    let start_a = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_a);
    let start_b = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_b);
    let delta_bits = b.alloc_qubits(DELTA_BITS);
    b.declare_qubit_register(&delta_bits);
    let growth_ctrl = b.alloc_qubit();
    let swap_ctrl = b.alloc_qubit();
    b.declare_qubit_register(&[growth_ctrl, swap_ctrl]);

    round664_emit_delta_growth_frontier_update(
        &mut b,
        &start_a,
        &start_b,
        &delta_bits,
        growth_ctrl,
        swap_ctrl,
    );

    b
}

