fn round634_emit_min_frontier_compute(
    b: &mut B,
    lhs: &[QubitId],
    rhs: &[QubitId],
    min_out: &[QubitId],
    rhs_lt_lhs: QubitId,
) {
    debug_assert_eq!(lhs.len(), rhs.len());
    debug_assert_eq!(lhs.len(), min_out.len());

    b.set_phase("round634_copy_lhs_frontier_to_min");
    for i in 0..lhs.len() {
        b.cx(lhs[i], min_out[i]);
    }

    b.set_phase("round634_compute_rhs_lt_lhs");
    cmp_lt_into(b, rhs, lhs, rhs_lt_lhs);

    b.set_phase("round634_mux_rhs_into_min");
    for i in 0..lhs.len() {
        b.ccx(rhs_lt_lhs, lhs[i], min_out[i]);
        b.ccx(rhs_lt_lhs, rhs[i], min_out[i]);
    }
}

fn round634_emit_min_frontier_uncompute(
    b: &mut B,
    lhs: &[QubitId],
    rhs: &[QubitId],
    min_out: &[QubitId],
    rhs_lt_lhs: QubitId,
) {
    debug_assert_eq!(lhs.len(), rhs.len());
    debug_assert_eq!(lhs.len(), min_out.len());

    b.set_phase("round634_unmux_rhs_from_min");
    for i in (0..lhs.len()).rev() {
        b.ccx(rhs_lt_lhs, rhs[i], min_out[i]);
        b.ccx(rhs_lt_lhs, lhs[i], min_out[i]);
    }

    b.set_phase("round634_uncompute_rhs_lt_lhs");
    cmp_lt_into(b, rhs, lhs, rhs_lt_lhs);

    b.set_phase("round634_clear_min");
    for i in (0..lhs.len()).rev() {
        b.cx(lhs[i], min_out[i]);
    }
}

fn round634_emit_step3_cswap(
    b: &mut B,
    swap_ctrl: QubitId,
    lane_a: &[QubitId],
    lane_b: &[QubitId],
    start_a: &[QubitId],
    start_b: &[QubitId],
) {
    debug_assert_eq!(lane_a.len(), lane_b.len());
    debug_assert_eq!(start_a.len(), start_b.len());

    b.set_phase("round634_step3_cswap_packed_lanes");
    for i in 0..lane_a.len() {
        cswap(b, swap_ctrl, lane_a[i], lane_b[i]);
    }

    b.set_phase("round634_step3_cswap_frontiers");
    for i in 0..start_a.len() {
        cswap(b, swap_ctrl, start_a[i], start_b[i]);
    }
}

fn build_round634_packed_step3_step4_shell_builder() -> B {
    const FRONTIER_BITS: usize = 9;
    const PACKED_WIDTH: usize = N + 1;

    let mut b = B::new();
    let lane_a = b.alloc_qubits(PACKED_WIDTH);
    b.declare_qubit_register(&lane_a);
    let lane_b = b.alloc_qubits(PACKED_WIDTH);
    b.declare_qubit_register(&lane_b);
    let start_a = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_a);
    let start_b = b.alloc_qubits(FRONTIER_BITS);
    b.declare_qubit_register(&start_b);
    let swap_ctrl = b.alloc_qubit();
    let add_ctrl = b.alloc_qubit();
    b.declare_qubit_register(&[swap_ctrl, add_ctrl]);

    let active = b.alloc_qubit();
    let boundary = b.alloc_qubit();
    let body_ctrl = b.alloc_qubit();
    let c_in = b.alloc_qubit();
    let body_scratch = b.alloc_qubit();
    let eq_scratch = b.alloc_qubits(FRONTIER_BITS - 2);
    let min_start = b.alloc_qubits(FRONTIER_BITS);
    let rhs_lt_lhs = b.alloc_qubit();

    round634_emit_step3_cswap(&mut b, swap_ctrl, &lane_a, &lane_b, &start_a, &start_b);

    round632_emit_low_sub_body(
        &mut b,
        &lane_a,
        &lane_b,
        &start_b,
        add_ctrl,
        active,
        boundary,
        body_ctrl,
        c_in,
        body_scratch,
        &eq_scratch,
    );

    round634_emit_min_frontier_compute(&mut b, &start_a, &start_b, &min_start, rhs_lt_lhs);
    round632_emit_high_add_body(
        &mut b,
        &lane_b,
        &lane_a,
        &min_start,
        add_ctrl,
        active,
        boundary,
        body_ctrl,
        c_in,
        body_scratch,
        &eq_scratch,
    );
    round634_emit_min_frontier_uncompute(&mut b, &start_a, &start_b, &min_start, rhs_lt_lhs);

    b.set_phase("round634_free_step4_shell_scratch");
    b.free(rhs_lt_lhs);
    b.free_vec(&min_start);
    b.free_vec(&eq_scratch);
    b.free(body_scratch);
    b.free(c_in);
    b.free(body_ctrl);
    b.free(boundary);
    b.free(active);
    b
}

