fn round647_high_bits_from_packed_lane(lane: &[QubitId]) -> Vec<QubitId> {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(lane.len(), PACKED_WIDTH);
    (0..N).map(|idx| lane[PACKED_WIDTH - 1 - idx]).collect()
}

fn round647_emit_decrement_start_if_high_nonzero(
    b: &mut B,
    start: &[QubitId],
    flag: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(start.len(), 9);
    debug_assert!(eq_scratch.len() >= 7);

    // Compute flag = (start != 257), decrement under it, then uncompute from
    // the output.  The predicate is unchanged by this saturating-at-257 map:
    // zero-high states stay 257, nonzero-high states land in 0..255.
    round631_emit_eq_const_toggle(b, start, PACKED_WIDTH, flag, eq_scratch);
    b.x(flag);
    csub_nbit_const_direct_fast(b, start, U256::from(1u64), flag);
    b.x(flag);
    round631_emit_eq_const_toggle(b, start, PACKED_WIDTH, flag, eq_scratch);
}

fn round647_emit_packed_shift_double_frontier(
    b: &mut B,
    lane: &[QubitId],
    start: &[QubitId],
    flag: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(lane.len(), PACKED_WIDTH);

    b.set_phase("round647_packed_v_shift_r_double");
    for idx in 0..PACKED_WIDTH - 1 {
        b.swap(lane[idx], lane[idx + 1]);
    }

    b.set_phase("round647_packed_solinas_fold_spill");
    let high = round647_high_bits_from_packed_lane(lane);
    let spill = lane[0];
    let solinas_c = U256::MAX
        .wrapping_sub(SECP256K1_P)
        .wrapping_add(U256::from(1u64));
    cadd_nbit_const_direct_fast(b, &high, solinas_c, spill);
    b.cx(high[0], spill);

    b.set_phase("round647_packed_high_start_decrement");
    round647_emit_decrement_start_if_high_nonzero(b, start, flag, eq_scratch);
}

fn round648_emit_packed_shift_double_frontier_dirty(
    b: &mut B,
    lane: &[QubitId],
    start: &[QubitId],
    dirty: &[QubitId],
    q_clean2: &[QubitId; 2],
    flag: QubitId,
    eq_scratch: &[QubitId],
) {
    const PACKED_WIDTH: usize = N + 1;
    debug_assert_eq!(lane.len(), PACKED_WIDTH);
    debug_assert!(dirty.len() >= N - 2);

    b.set_phase("round648_packed_v_shift_r_double");
    for idx in 0..PACKED_WIDTH - 1 {
        b.swap(lane[idx], lane[idx + 1]);
    }

    b.set_phase("round648_packed_solinas_fold_spill_dirty_vented");
    let high = round647_high_bits_from_packed_lane(lane);
    let spill = lane[0];
    let solinas_c = U256::MAX
        .wrapping_sub(SECP256K1_P)
        .wrapping_add(U256::from(1u64));
    venting::ciadd_dirty_2clean_classical(
        b,
        &high,
        &dirty[..N - 2],
        q_clean2,
        solinas_c.as_limbs()[0],
        spill,
        false,
    );
    b.cx(high[0], spill);

    b.set_phase("round648_packed_high_start_decrement");
    round647_emit_decrement_start_if_high_nonzero(b, start, flag, eq_scratch);
}

fn round648_emit_step9_cswap(
    b: &mut B,
    swap_ctrl: QubitId,
    lane_a: &[QubitId],
    lane_b: &[QubitId],
    start_a: &[QubitId],
    start_b: &[QubitId],
) {
    debug_assert_eq!(lane_a.len(), lane_b.len());
    debug_assert_eq!(start_a.len(), start_b.len());

    b.set_phase("round648_step9_cswap_packed_lanes");
    for i in 0..lane_a.len() {
        cswap(b, swap_ctrl, lane_a[i], lane_b[i]);
    }

    b.set_phase("round648_step9_cswap_frontiers");
    for i in 0..start_a.len() {
        cswap(b, swap_ctrl, start_a[i], start_b[i]);
    }
}

