fn with_kal_branch_inv_raw_roll<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    let n = v_in.len();
    let mut st = alloc_kaliski_branch_state_no_add(b, n, iters);
    let term_bits = b.alloc_qubits(9);
    kaliski_branch_record_forward_term(b, v_in, &st, &term_bits, p, iters);

    // Final denominator state is known when iters is beyond the convergence
    // tail. Free it so coefficient replay carries only histories + inv coeffs.
    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    let inv_raw = b.alloc_qubits(n);
    let coeff_s = b.alloc_qubits(n);
    b.x(coeff_s[0]);
    apply_coeff_channel_from_term_roll(
        b, p, &inv_raw, &coeff_s, &st.a_hist, &st.m_hist, &term_bits,
    );

    body(b, &inv_raw);

    apply_coeff_channel_from_term_roll_inverse(
        b, p, &inv_raw, &coeff_s, &st.a_hist, &st.m_hist, &term_bits,
    );
    b.x(coeff_s[0]);
    b.free_vec(&coeff_s);
    b.free_vec(&inv_raw);

    st.u = b.alloc_qubits(n);
    st.v_w = b.alloc_qubits(n);
    st.f_flag = b.alloc_qubit();
    b.x(st.u[0]);
    kaliski_branch_record_backward_term(b, v_in, &st, &term_bits, p, iters);
    b.free_vec(&term_bits);
    free_kaliski_branch_state(b, st);
}

fn with_kal_branch_term_roll_tagged_div<F: FnOnce(&mut B)>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    coeff: (&[QubitId], &[QubitId]),
    body: F,
) {
    let n = v_in.len();
    let mut st = alloc_kaliski_branch_state_no_add(b, n, iters);
    let term_bits = b.alloc_qubits(9);
    kaliski_branch_record_forward_term(b, v_in, &st, &term_bits, p, iters);

    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    apply_coeff_channel_from_term_roll(b, p, coeff.0, coeff.1, &st.a_hist, &st.m_hist, &term_bits);
    body(b);

    st.u = b.alloc_qubits(n);
    st.v_w = b.alloc_qubits(n);
    st.f_flag = b.alloc_qubit();
    b.x(st.u[0]);
    kaliski_branch_record_backward_term(b, v_in, &st, &term_bits, p, iters);
    b.free_vec(&term_bits);
    free_kaliski_branch_state(b, st);
}

fn with_kal_branch_term_tagged_div<F: FnOnce(&mut B)>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    coeff: (&[QubitId], &[QubitId]),
    body: F,
) {
    let n = v_in.len();
    let mut st = alloc_kaliski_branch_state_no_add(b, n, iters);
    let term_bits = b.alloc_qubits(9);
    kaliski_branch_record_forward_term(b, v_in, &st, &term_bits, p, iters);

    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    apply_coeff_channel_from_term_index(b, p, coeff.0, coeff.1, &st.a_hist, &st.m_hist, &term_bits);
    body(b);

    st.u = b.alloc_qubits(n);
    st.v_w = b.alloc_qubits(n);
    st.f_flag = b.alloc_qubit();
    b.x(st.u[0]);
    kaliski_branch_record_backward_term(b, v_in, &st, &term_bits, p, iters);
    b.free_vec(&term_bits);
    free_kaliski_branch_state(b, st);
}

fn with_kal_branch_stream_tagged_div<F: FnOnce(&mut B)>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    coeff: (&[QubitId], &[QubitId]),
    body: F,
) {
    let n = v_in.len();
    let mut st = alloc_kaliski_branch_state(b, n, iters);
    kaliski_branch_record_forward(b, v_in, &st, p, iters);

    // At sufficient iteration count the denominator state is known `(u,v,f)=(1,0,0)`.
    // Free it before the coefficient replay so the replay peak is history + coeff,
    // not history + denominator + coeff.
    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    apply_coeff_channel_from_hist(b, p, coeff.0, coeff.1, &st.a_hist, &st.add_hist);
    body(b);

    st.u = b.alloc_qubits(n);
    st.v_w = b.alloc_qubits(n);
    st.f_flag = b.alloc_qubit();
    b.x(st.u[0]);
    kaliski_branch_record_backward(b, v_in, &st, p, iters);
    free_kaliski_branch_state(b, st);
}

fn with_kal_branch_tagged_div_coeff<F: FnOnce(&mut B)>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    coeff: (&[QubitId], &[QubitId]),
    body: F,
) {
    let st = alloc_kaliski_branch_state(b, v_in.len(), iters);
    kaliski_branch_forward_with_coeff(b, v_in, &st, p, iters, coeff);
    body(b);
    kaliski_branch_backward(b, v_in, &st, p, iters);
    free_kaliski_branch_state(b, st);
}

/// Run `body` with `inv` holding `v_in^{-1} mod p`, leaving `v_in`
/// unchanged. Allocates the kaliski state and `inv` register itself, then
/// frees them at the end. The body must NOT touch `st` or `v_in`.
///
/// Implementation keeps `st` live across the body, so we only run
/// `kaliski_forward` ONCE (and its emit_inverse once), instead of the
/// 4-call structure of the previous Bennett-cleaned `kal_compute_into`.
/// Halves the dominant kaliski cost.
fn emit_inverse_hmr_safe<F: FnOnce(&mut B)>(b: &mut B, f: F) {
    let start = b.ops.len();
    f(b);
    let end = b.ops.len();
    let fwd: Vec<_> = b.ops[start..end].to_vec();
    b.ops.truncate(start);
    for op in fwd.into_iter().rev() {
        match op.kind {
            OperationType::X
            | OperationType::Z
            | OperationType::CX
            | OperationType::CZ
            | OperationType::CCX
            | OperationType::CCZ
            | OperationType::Swap => b.push_op(op),
            OperationType::R
            | OperationType::Hmr
            | OperationType::Register
            | OperationType::AppendToRegister
            | OperationType::DebugPrint => {}
            _ => panic!(
                "emit_inverse_hmr_safe: non-invertible op kind {:?} inside forward block",
                op.kind
            ),
        }
    }
}

fn with_kal_inv_raw<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    let iters = kaliski_effective_iters(v_in.len(), iters);
    with_kal_inv_raw_coeff(b, v_in, p, iters, None, body);
}

fn hmr_reset_unknown_vec(b: &mut B, qs: &[QubitId]) {
    if round499_zero_condition_hmr_erase_enabled() {
        let zero = b.alloc_bit();
        b.bit_store0(zero);
        for &q in qs {
            b.hmr_if(q, zero, zero);
        }
        b.free_vec(qs);
        return;
    }

    let masks = b.alloc_bits(qs.len());
    for (&q, &m) in qs.iter().zip(masks.iter()) {
        b.hmr(q, m);
    }
    b.free_vec(qs);
}

fn hmr_reset_unknown_vec_with_masks(b: &mut B, qs: &[QubitId]) -> Vec<BitId> {
    let masks = b.alloc_bits(qs.len());
    for (&q, &m) in qs.iter().zip(masks.iter()) {
        b.hmr(q, m);
    }
    b.free_vec(qs);
    masks
}

fn round499_zero_condition_hmr_erase_enabled() -> bool {
    if std::env::var("ROUND499_ZERO_COND_HMR_ERASE")
        .ok()
        .as_deref()
        != Some("1")
    {
        return false;
    }
    assert!(
        std::env::var("ROUND499_ALLOW_GOOGLE_FAILING_PROBE")
            .ok()
            .as_deref()
            == Some("1"),
        "ROUND499_ZERO_COND_HMR_ERASE is invalid under the Zenodo/Google simulator: \
         condition-false HMR does not reset the qubit.  Use \
         ROUND499_ALLOW_GOOGLE_FAILING_PROBE=1 only to reproduce the rejected probe."
    );
    true
}

fn hmr_discard_kaliski_non_inverse_phase_dirty(b: &mut B, st: &KaliskiState, p: U256) {
    b.set_phase("kal_hmr_discard_known_terminal_state");
    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    b.set_phase("kal_hmr_discard_clean_terminal_s");
    for i in 0..st.s.len() {
        if bit(p, i) {
            b.x(st.s[i]);
        }
    }
    b.free_vec(&st.s);

    b.set_phase("kal_hmr_discard_non_inverse_state_phase_dirty");
    if let Some((&m0, rest)) = st.m_hist.split_first() {
        // For nonzero denominators, the first Kaliski branch bit is always 1:
        // u starts at the odd prime p, v is nonzero, and the step1/step2
        // updates force m0 high regardless of v's low bit.  Free it as a
        // known constant instead of paying an avoidable HMR phase term.
        b.x(m0);
        b.free(m0);
        let zero_tail = std::env::var("D1_DIRECT_QUOTIENT_HMR_CLEAR_ZERO_M_TAIL")
            .ok()
            .and_then(|s| s.parse::<usize>().ok())
            .unwrap_or(0)
            .min(rest.len());
        assert!(
            zero_tail == 0
                || std::env::var("D1_DIRECT_QUOTIENT_HMR_CLEAR_ZERO_M_TAIL_UNSAFE_PROBE")
                    .ok()
                    .as_deref()
                    == Some("1"),
            "D1_DIRECT_QUOTIENT_HMR_CLEAR_ZERO_M_TAIL is not stable under the Google hash harness: \
             changing the opstream changes the Fiat-Shamir samples and the cleared tail can add \
             uncaptured R phase. Set D1_DIRECT_QUOTIENT_HMR_CLEAR_ZERO_M_TAIL_UNSAFE_PROBE=1 only \
             to reproduce the rejected diagnostic."
        );
        if zero_tail == 0 {
            hmr_reset_unknown_vec(b, rest);
        } else {
            let split = rest.len() - zero_tail;
            let (unknown, known_zero) = rest.split_at(split);
            hmr_reset_unknown_vec(b, unknown);
            b.free_vec(known_zero);
        }
    }
}

fn hmr_discard_kaliski_non_inverse_transcript_repair(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
) {
    b.set_phase("kal_hmr_discard_known_terminal_state");
    b.x(st.u[0]);
    b.free_vec(&st.u);
    b.free_vec(&st.v_w);
    b.free(st.f_flag);

    b.set_phase("kal_hmr_discard_clean_terminal_s");
    for i in 0..st.s.len() {
        if bit(p, i) {
            b.x(st.s[i]);
        }
    }
    b.free_vec(&st.s);

    b.set_phase("kal_hmr_discard_non_inverse_state_hmr_masks");
    let masks = hmr_reset_unknown_vec_with_masks(b, &st.m_hist);

    b.set_phase("kal_hmr_discard_non_inverse_transcript_recompute");
    let mut repair = alloc_kaliski_branch_state_no_add(b, v_in.len(), iters);
    let term_bits = b.alloc_qubits(9);
    kaliski_branch_record_forward_term(b, v_in, &repair, &term_bits, p, iters);

    b.set_phase("kal_hmr_discard_non_inverse_transcript_apply_phase");
    for (&q, &m) in repair.m_hist.iter().zip(masks.iter()) {
        b.z_if(q, m);
    }

    b.set_phase("kal_hmr_discard_non_inverse_transcript_uncompute");
    kaliski_branch_record_backward_term(b, v_in, &repair, &term_bits, p, iters);
    b.free_vec(&term_bits);
    free_kaliski_branch_state(b, repair);
}

fn hmr_discard_kaliski_inverse_phase_dirty(b: &mut B, st: KaliskiState) {
    if std::env::var("D1_DIRECT_QUOTIENT_HMR_CLEAR_R_RAW_UNSAFE_PROBE")
        .ok()
        .as_deref()
        == Some("1")
    {
        b.set_phase("kal_hmr_discard_inverse_state_free_raw_r_unsafe_probe");
        b.free_vec(&st.r);
        return;
    }
    b.set_phase("kal_hmr_discard_inverse_state_phase_dirty");
    hmr_reset_unknown_vec(b, &st.r);
}

fn hmr_discard_kaliski_inverse_raw_repair(
    b: &mut B,
    v_in: &[QubitId],
    st: KaliskiState,
    p: U256,
    iters: usize,
) {
    b.set_phase("kal_hmr_discard_inverse_state_hmr_masks");
    let masks = hmr_reset_unknown_vec_with_masks(b, &st.r);

    b.set_phase("kal_hmr_discard_inverse_raw_recompute");
    with_kal_inv_raw(b, v_in, p, iters, |b, inv_raw| {
        b.set_phase("kal_hmr_discard_inverse_raw_apply_phase");
        for (&q, &m) in inv_raw.iter().zip(masks.iter()) {
            b.z_if(q, m);
        }
    });
}

fn with_kal_inv_raw_hmr_discard<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    let n = v_in.len();
    let iters = kaliski_effective_iters(n, iters);
    let st = alloc_kaliski_state(b, n, iters);
    kaliski_forward(b, v_in, &st, p, iters);
    if std::env::var("D1_DIRECT_QUOTIENT_HMR_REPAIR_M_HIST")
        .ok()
        .as_deref()
        == Some("1")
    {
        hmr_discard_kaliski_non_inverse_transcript_repair(b, v_in, &st, p, iters);
    } else {
        hmr_discard_kaliski_non_inverse_phase_dirty(b, &st, p);
    }
    let r_low: Vec<QubitId> = st.r[..n].to_vec();
    body(b, &r_low);
    if std::env::var("D1_DIRECT_QUOTIENT_HMR_REPAIR_R_RAW")
        .ok()
        .as_deref()
        == Some("1")
    {
        hmr_discard_kaliski_inverse_raw_repair(b, v_in, st, p, iters);
    } else {
        hmr_discard_kaliski_inverse_phase_dirty(b, st);
    }
}

fn kaliski_effective_iters(n: usize, iters: usize) -> usize {
    iters.min(2 * n)
}

fn with_kal_inv_raw_borrowing_v<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in_out: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    let n = v_in_out.len();
    let iters = kaliski_effective_iters(n, iters);
    let mut st = alloc_kaliski_state_borrowing_v(b, v_in_out, iters);
    let keep_full_state = std::env::var("KAL_KEEP_FULL_STATE").ok().as_deref() == Some("1");
    let keep_u = keep_full_state || std::env::var("KAL_KEEP_U").ok().as_deref() == Some("1");
    let unsafe_free_f = std::env::var("KAL_FREE_F").ok().as_deref() == Some("1");
    assert!(
        !unsafe_free_f || std::env::var("KAL_FREE_F_UNSAFE_PROBE").ok().as_deref() == Some("1"),
        "KAL_FREE_F=1 is forbidden for borrowed-v Kaliski PA backends: the f_flag \
         sentinel is needed by the explicit backward pass. The 9024 Google PA \
         harness rejects this one-qubit shave with a value/phase failure. Set \
         KAL_FREE_F_UNSAFE_PROBE=1 only for reproducing that rejected lane."
    );
    // In the borrowed-v path the body is allowed to keep long-lived outputs
    // that can reuse freed Kaliski qubits.  Resetting/reallocating f_flag then
    // breaks the explicit backward contract on the raw-borrow PA path; keep the
    // one-bit sentinel live unless an experiment explicitly asks to free it.
    let keep_f = keep_full_state
        || std::env::var("KAL_KEEP_F").ok().as_deref() == Some("1")
        || !unsafe_free_f;
    let free_s = !keep_full_state && std::env::var("KAL_FREE_S").ok().as_deref() != Some("0");
    let relocate_r_to_terminal_v = std::env::var("KAL_RELOCATE_R_TO_BORROWED_V")
        .ok()
        .as_deref()
        == Some("1");

    for i in 0..n {
        if bit(p, i) {
            b.x(st.u[i]);
        }
    }
    kaliski_forward_borrowing_v(b, &st, p, iters);

    if !keep_f {
        b.free(st.f_flag);
    }
    if !keep_u {
        b.x(st.u[0]);
        b.free_vec(&st.u);
    }
    if free_s {
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
        b.free_vec(&st.s);
    }

    if relocate_r_to_terminal_v {
        b.set_phase("kal_relocate_r_to_terminal_borrowed_v");
        for i in 0..n {
            b.swap(st.r[i], st.v_w[i]);
        }
        b.free_vec(&st.r);
        st.r = Vec::new();
        let r_low: Vec<QubitId> = st.v_w[..n].to_vec();
        body(b, &r_low);
        st.r = b.alloc_qubits(n);
        b.set_phase("kal_restore_r_from_terminal_borrowed_v");
        for i in (0..n).rev() {
            b.swap(st.r[i], st.v_w[i]);
        }
    } else {
        let r_low: Vec<QubitId> = st.r[..n].to_vec();
        body(b, &r_low);
    }

    if !keep_u {
        st.u = b.alloc_qubits(n);
        b.x(st.u[0]);
    }
    if !keep_f {
        st.f_flag = b.alloc_qubit();
    }
    if free_s {
        st.s = b.alloc_qubits(n);
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
    }

    kaliski_backward_borrowing_v(b, &st, p, iters);
    free_kaliski_state_borrowed_v(b, st);
}

fn kaliski_forward_prescaled_mixed(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
) {
    kaliski_forward_prescaled_kind(b, v_in, st, p, iters, scale, false);
}

fn kaliski_forward_prescaled_chunked(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
) {
    kaliski_forward_prescaled_kind(b, v_in, st, p, iters, scale, true);
}

fn kaliski_forward_prescaled_kind(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
    chunked: bool,
) {
    let n = v_in.len();
    debug_assert!(iters <= st.m_hist.len());

    for i in 0..n {
        if bit(p, i) {
            b.x(st.u[i]);
        }
    }
    if chunked {
        mul_by_const_acc_chunked_shifts_inplace_src(b, v_in, scale, &st.v_w, p, false);
    } else {
        mul_by_const_acc_exact_adds_fast_shifts(b, v_in, scale, &st.v_w, p, false);
    }
    b.x(st.s[0]);
    b.x(st.f_flag);

    let use_bulk_prefix3 = bulk_prefix_enabled();
    let bulk_prefix_iters = bulk_prefix_safe_iters();
    for i in 0..iters {
        if use_bulk_prefix3 && i < bulk_prefix_iters {
            kaliski_iteration_bulk_prefix3(
                b,
                p,
                &st.u,
                &st.v_w,
                &st.r,
                &st.s,
                st.m_hist[i],
                i,
                None,
            );
        } else {
            kaliski_iteration(
                b,
                p,
                &st.u,
                &st.v_w,
                &st.r,
                &st.s,
                st.m_hist[i],
                st.f_flag,
                i,
                None,
            );
        }
    }
}

fn kaliski_backward_prescaled_mixed(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
) {
    kaliski_backward_prescaled_kind(b, v_in, st, p, iters, scale, false);
}

fn kaliski_backward_prescaled_chunked(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
) {
    kaliski_backward_prescaled_kind(b, v_in, st, p, iters, scale, true);
}

fn kaliski_backward_prescaled_kind(
    b: &mut B,
    v_in: &[QubitId],
    st: &KaliskiState,
    p: U256,
    iters: usize,
    scale: U256,
    chunked: bool,
) {
    let n = v_in.len();
    debug_assert!(iters <= st.m_hist.len());

    let use_bulk_prefix3 = bulk_prefix_enabled();
    let bulk_prefix_iters = bulk_prefix_safe_iters();
    for i in (0..iters).rev() {
        if use_bulk_prefix3 && i < bulk_prefix_iters {
            kaliski_iteration_bulk_prefix3_backward(
                b,
                p,
                &st.u,
                &st.v_w,
                &st.r,
                &st.s,
                st.m_hist[i],
                i,
                None,
            );
        } else {
            kaliski_iteration_backward(
                b,
                p,
                &st.u,
                &st.v_w,
                &st.r,
                &st.s,
                st.m_hist[i],
                st.f_flag,
                i,
                None,
            );
        }
    }

    b.x(st.f_flag);
    b.x(st.s[0]);
    if chunked {
        mul_by_const_acc_chunked_shifts_inplace_src(b, v_in, scale, &st.v_w, p, true);
    } else {
        mul_by_const_acc_exact_adds_fast_shifts(b, v_in, scale, &st.v_w, p, true);
    }
    for i in 0..n {
        if bit(p, i) {
            b.x(st.u[i]);
        }
    }
}

fn with_kal_inv_raw_prescaled_mixed<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    with_kal_inv_raw_prescaled_kind(b, v_in, p, iters, false, body);
}

fn with_kal_inv_raw_prescaled_chunked<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    with_kal_inv_raw_prescaled_kind(b, v_in, p, iters, true, body);
}

fn with_kal_inv_raw_prescaled_kind<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    chunked: bool,
    body: F,
) {
    let n = v_in.len();
    let iters = kaliski_effective_iters(n, iters);
    let mut st = alloc_kaliski_state(b, n, iters);
    let scale = pow_mod_2_k(p, iters);
    let keep_full_state = std::env::var("KAL_KEEP_FULL_STATE").ok().as_deref() == Some("1");
    let keep_u = keep_full_state || std::env::var("KAL_KEEP_U").ok().as_deref() == Some("1");
    let keep_v = keep_full_state || std::env::var("KAL_KEEP_V").ok().as_deref() == Some("1");
    let keep_f = keep_full_state || std::env::var("KAL_KEEP_F").ok().as_deref() == Some("1");
    let free_s = !keep_full_state && std::env::var("KAL_FREE_S").ok().as_deref() != Some("0");

    if chunked {
        kaliski_forward_prescaled_chunked(b, v_in, &st, p, iters, scale);
    } else {
        kaliski_forward_prescaled_mixed(b, v_in, &st, p, iters, scale);
    }

    if !keep_v {
        b.free_vec(&st.v_w);
    }
    if !keep_f {
        b.free(st.f_flag);
    }
    if !keep_u {
        b.x(st.u[0]);
        b.free_vec(&st.u);
    }
    if free_s {
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
        b.free_vec(&st.s);
    }

    let r_low: Vec<QubitId> = st.r[..n].to_vec();
    body(b, &r_low);

    if !keep_u {
        st.u = b.alloc_qubits(n);
        b.x(st.u[0]);
    }
    if !keep_f {
        st.f_flag = b.alloc_qubit();
    }
    if !keep_v {
        st.v_w = b.alloc_qubits(n);
    }
    if free_s {
        st.s = b.alloc_qubits(n);
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
    }

    if chunked {
        kaliski_backward_prescaled_chunked(b, v_in, &st, p, iters, scale);
    } else {
        kaliski_backward_prescaled_mixed(b, v_in, &st, p, iters, scale);
    }
    free_kaliski_state(b, st);
}

fn with_kal_inv_raw_coeff<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    coeff: Option<(&[QubitId], &[QubitId])>,
    body: F,
) {
    let n = v_in.len();
    let iters = kaliski_effective_iters(n, iters);
    let mut st = alloc_kaliski_state(b, n, iters);
    let keep_full_state = std::env::var("KAL_KEEP_FULL_STATE").ok().as_deref() == Some("1");
    let keep_u = keep_full_state || std::env::var("KAL_KEEP_U").ok().as_deref() == Some("1");
    let keep_v = keep_full_state || std::env::var("KAL_KEEP_V").ok().as_deref() == Some("1");
    let keep_f = keep_full_state || std::env::var("KAL_KEEP_F").ok().as_deref() == Some("1");
    // KAL_FREE_S=1 (default ON in this branch): at end of forward Kaliski,
    // the s register provably equals p (the modulus) when iters >= ~407
    // (verified classically for our specific Kaliski variant). Free s by
    // X-ing the bits of p, then re-load before backward.
    let free_s = !keep_full_state && std::env::var("KAL_FREE_S").ok().as_deref() != Some("0");

    // Forward kaliski. st.r[..n] holds raw = v_in^{-1} * 2^(2n) mod p.
    // If coeff is supplied, the same branch controls also transform that
    // external coefficient pair, but the ordinary qrisp sentinel state remains
    // available for clean branch-flag uncomputation.
    kaliski_forward_with_coeff(b, v_in, &st, p, iters, coeff);

    if !keep_v {
        b.free_vec(&st.v_w);
    }
    if !keep_f {
        b.free(st.f_flag);
    }
    if !keep_u {
        b.x(st.u[0]);
        b.free_vec(&st.u);
    }
    if free_s {
        // s = p at this point. X each bit of p to zero it.
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
        b.free_vec(&st.s);
    }

    let r_low: Vec<QubitId> = st.r[..n].to_vec();
    body(b, &r_low);

    if !keep_u {
        // Re-alloc at |0> for the backward pass; restore u[0] = 1.
        st.u = b.alloc_qubits(n);
        b.x(st.u[0]);
    }
    if !keep_f {
        st.f_flag = b.alloc_qubit();
    }
    if !keep_v {
        st.v_w = b.alloc_qubits(n);
    }
    if free_s {
        // Re-allocate s and load p back.
        st.s = b.alloc_qubits(n);
        for i in 0..n {
            if bit(p, i) {
                b.x(st.s[i]);
            }
        }
    }

    // Experimental mode: use the exact reversed forward block shape, but skip
    // HMR/R in the reverse replay. This is heavier than the explicit backward,
    // but it keeps the specialized prefix and its matching global reverse in a
    // single contract. The hope is to eliminate the residual phase mismatch.
    if std::env::var("KAL_BULK3_GENERALIZED_REVERSE").is_ok() {
        emit_inverse_hmr_safe(b, |b| kaliski_forward(b, v_in, &st, p, iters));
    } else {
        // Explicit backward pass (uses measurement-based uncompute, saves
        // ~511 CCX per iteration vs the emit_inverse version).
        kaliski_backward(b, v_in, &st, p, iters);
    }

    free_kaliski_state(b, st);
}

fn with_kal_inv<F: FnOnce(&mut B, &[QubitId])>(
    b: &mut B,
    v_in: &[QubitId],
    p: U256,
    iters: usize,
    body: F,
) {
    with_kal_inv_raw(b, v_in, p, iters, |b, inv_raw| {
        // Kaliski's raw output carries a 2^(2n-1) factor. Apply the
        // correction in place when callers need the exact inverse.
        for _ in 0..iters {
            mod_halve_inplace_fast(b, inv_raw, p);
        }
        body(b, inv_raw);
        for _ in 0..iters {
            mod_double_inplace_fast(b, inv_raw, p);
        }
    });
}

fn kaliski_inv_inplace(b: &mut B, v_in: &[QubitId], p: U256) {
    let n = v_in.len();
    let iters = 2 * n - 114;

    // Bennett compute-copy-uncompute pattern. Each call of
    // `kaliski_inv_inplace` maps v_in ↔ v_in^{-1} (involution), with
    // internal scratch fully zeroed by function end.
    let st = alloc_kaliski_state(b, n, iters);
    let output = b.alloc_qubits(n);

    // ─── Phase 1: compute inverse of v_in into output ───
    kaliski_forward(b, v_in, &st, p, iters);
    // st.r[..n] now holds raw inverse (in mod 2p, low n bits).
    // Apply classical correction: st.r[..n] *= K mod p, where K = 2^{-2n} mod p.
    let two_2n = pow_mod_2_k(p, 2 * n);
    let k_const = classical_modinv(two_2n, p);
    in_place_mul_const(b, &st.r[..n], k_const, p);
    // Copy exact inverse into output.
    for i in 0..n {
        b.cx(st.r[i], output[i]);
    }
    // Undo the correction: st.r[..n] *= K^{-1} mod p.
    in_place_mul_const(b, &st.r[..n], two_2n, p);
    // Now st is back to its post-kaliski_forward state. Reverse the forward.
    emit_inverse(b, |b| kaliski_forward(b, v_in, &st, p, iters));
    // st is all 0 again. v_in unchanged. output = v_in^{-1}.

    // Swap v_in and output.
    for i in 0..n {
        b.swap(v_in[i], output[i]);
    }
    // v_in = inverse, output = v_orig.

    // ─── Phase 2: zero output via a second Bennett pass ───
    // Compute inverse of current v_in (which is v_orig^{-1}), = v_orig,
    // and XOR it into output. Since output currently = v_orig, the XOR
    // zeroes output.
    kaliski_forward(b, v_in, &st, p, iters);
    in_place_mul_const(b, &st.r[..n], k_const, p);
    for i in 0..n {
        b.cx(st.r[i], output[i]);
    } // output ^= v_orig = 0
    in_place_mul_const(b, &st.r[..n], two_2n, p);
    emit_inverse(b, |b| kaliski_forward(b, v_in, &st, p, iters));
    // st all 0, output all 0 (hopefully), v_in = inverse.

    b.free_vec(&output);
    free_kaliski_state(b, st);
}

/// Classical: compute `2^k mod p`.
fn pow_mod_2_k(p: U256, k: usize) -> U256 {
    let mut r = U256::from(1);
    let two = U256::from(2);
    for _ in 0..k {
        r = mulmod(r, two, p);
    }
    r
}

fn secp256k1_curve() -> WeierstrassEllipticCurve {
    WeierstrassEllipticCurve {
        modulus: U256::from_str_radix(
            "FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEFFFFFC2F",
            16,
        )
        .unwrap(),
        a: U256::from(0),
        b: U256::from(7),
        gx: U256::from_str_radix(
            "79BE667EF9DCBBAC55A06295CE870B07029BFCDB2DCE28D959F2815B16F81798",
            16,
        )
        .unwrap(),
        gy: U256::from_str_radix(
            "483ADA7726A3C4655DA4FBFC0E1108A8FD17B448A68554199C47D08FFB10D4B8",
            16,
        )
        .unwrap(),
        order: U256::from_str_radix(
            "FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141",
            16,
        )
        .unwrap(),
    }
}

fn alt_seed_xof(ops: &[Op], tag: u64) -> sha3::Shake256Reader {
    let mut hasher = Shake256::default();
    hasher.update(b"quantum_ecc-alt-seed-v1");
    hasher.update(&tag.to_le_bytes());
    hasher.update(&(ops.len() as u64).to_le_bytes());
    for op in ops {
        hasher.update(&[op.kind as u8]);
        hasher.update(&op.q_control2.0.to_le_bytes());
        hasher.update(&op.q_control1.0.to_le_bytes());
        hasher.update(&op.q_target.0.to_le_bytes());
        hasher.update(&op.c_target.0.to_le_bytes());
        hasher.update(&op.c_condition.0.to_le_bytes());
        hasher.update(&op.r_target.0.to_le_bytes());
    }
    hasher.finalize_xof()
}

fn run_alt_seed_checks(ops: &[Op]) {
    let n_seeds = if std::env::var("ALT_SEED_COMMIT").is_ok() {
        ALT_SEED_COMMIT
    } else {
        ALT_SEED_COUNT
    };

    let curve = secp256k1_curve();
    let (total_qubits, num_bits, _num_regs, regs) = analyze_ops(ops.iter());
    assert!(regs.len() == 4);
    for (i, r) in regs.iter().enumerate() {
        assert_eq!(r.len(), 256, "register {i} should be 256 wide");
    }
    for q in &regs[0] {
        assert!(matches!(q, QubitOrBit::Qubit(_)));
    }
    for q in &regs[1] {
        assert!(matches!(q, QubitOrBit::Qubit(_)));
    }
    for q in &regs[2] {
        assert!(matches!(q, QubitOrBit::Bit(_)));
    }
    for q in &regs[3] {
        assert!(matches!(q, QubitOrBit::Bit(_)));
    }

    eprintln!(
        "=== alternate-seed diagnostic ({} seeds × {} shots, classical_limit={}, parallel) ===",
        n_seeds, ALT_SEED_SHOTS, ALT_SEED_CLASSICAL_LIMIT,
    );

    let results: Vec<(u64, usize, usize, usize)> = std::thread::scope(|scope| {
        let curve = &curve;
        let regs = &regs;
        let mut handles = Vec::with_capacity(n_seeds);
        for tag_idx in 0..n_seeds {
            let tag = (tag_idx as u64) + 1;
            let handle = scope.spawn(move || {
                const BATCH: usize = 64;
                let mut xof = alt_seed_xof(ops, tag);
                let mut targets = Vec::with_capacity(ALT_SEED_SHOTS);
                let mut offsets = Vec::with_capacity(ALT_SEED_SHOTS);
                let mut expected = Vec::with_capacity(ALT_SEED_SHOTS);
                while targets.len() < ALT_SEED_SHOTS {
                    let mut rb = [[0u8; 32]; 2];
                    xof.read(&mut rb[0]);
                    xof.read(&mut rb[1]);
                    let k1 = U256::from_le_bytes(rb[0]);
                    let k2 = U256::from_le_bytes(rb[1]);
                    let t = curve.mul(curve.gx, curve.gy, k1);
                    let o = curve.mul(curve.gx, curve.gy, k2);
                    if t.0 == o.0 {
                        continue;
                    }
                    if t.0.is_zero() && t.1.is_zero() {
                        continue;
                    }
                    if o.0.is_zero() && o.1.is_zero() {
                        continue;
                    }
                    let e = curve.add(t.0, t.1, o.0, o.1);
                    targets.push(t);
                    offsets.push(o);
                    expected.push(e);
                }

                let mut sim = Simulator::new(total_qubits as usize, num_bits as usize, &mut xof);
                let mut classical_failures = 0usize;
                let mut phase_garbage_batches = 0usize;
                let mut ancilla_garbage_batches = 0usize;
                let num_batches = (ALT_SEED_SHOTS + BATCH - 1) / BATCH;
                for batch in 0..num_batches {
                    let bs = BATCH.min(ALT_SEED_SHOTS - batch * BATCH);
                    let cond_mask: u64 = if bs == 64 { u64::MAX } else { (1u64 << bs) - 1 };
                    sim.clear_for_shot();
                    for shot in 0..bs {
                        let i = batch * BATCH + shot;
                        sim.set_register(&regs[0], targets[i].0, shot);
                        sim.set_register(&regs[1], targets[i].1, shot);
                        sim.set_register(&regs[2], offsets[i].0, shot);
                        sim.set_register(&regs[3], offsets[i].1, shot);
                    }
                    sim.apply_iter(ops.iter());
                    for shot in 0..bs {
                        let i = batch * BATCH + shot;
                        let gx = sim.get_register(&regs[0], shot);
                        let gy = sim.get_register(&regs[1], shot);
                        if gx != expected[i].0 || gy != expected[i].1 {
                            classical_failures += 1;
                        }
                    }
                    let phase = sim.phase & cond_mask;
                    if phase != 0 {
                        phase_garbage_batches += 1;
                    }
                    for register in regs {
                        for qb in register {
                            if let QubitOrBit::Qubit(q) = *qb {
                                *sim.qubit_mut(q) = 0;
                            }
                        }
                    }
                    let mut garbage = false;
                    for q in 0..total_qubits {
                        if (sim.qubit(QubitId(q)) & cond_mask) != 0 {
                            garbage = true;
                            break;
                        }
                    }
                    if garbage {
                        ancilla_garbage_batches += 1;
                    }
                }
                (
                    tag,
                    classical_failures,
                    phase_garbage_batches,
                    ancilla_garbage_batches,
                )
            });
            handles.push(handle);
        }
        handles.into_iter().map(|h| h.join().unwrap()).collect()
    });

    let mut total_classical = 0usize;
    let mut total_phase_batches = 0usize;
    let mut total_ancilla_batches = 0usize;
    for (tag, classical_failures, phase_garbage_batches, ancilla_garbage_batches) in &results {
        total_classical += classical_failures;
        total_phase_batches += phase_garbage_batches;
        total_ancilla_batches += ancilla_garbage_batches;
        eprintln!(
            "ALT-SEED tag={} classical_mismatches={} phase_batches={} ancilla_batches={}",
            tag, classical_failures, phase_garbage_batches, ancilla_garbage_batches,
        );
    }

    println!("METRIC altseed_classical_total={}", total_classical);
    println!("METRIC altseed_phase_batches_total={}", total_phase_batches);
    println!(
        "METRIC altseed_ancilla_batches_total={}",
        total_ancilla_batches
    );

    let phase_limit: usize = std::env::var("ALT_SEED_PHASE_LIMIT")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);
    assert!(
        total_phase_batches <= phase_limit,
        "ALT-SEED PHASE FAILURE: {} phase-garbage batches (limit {}) across {} seeds × {} shots",
        total_phase_batches,
        phase_limit,
        n_seeds,
        ALT_SEED_SHOTS,
    );
    assert!(
        total_ancilla_batches == 0,
        "ALT-SEED ANCILLA FAILURE: {} ancilla-garbage batches across {} seeds × {} shots",
        total_ancilla_batches,
        n_seeds,
        ALT_SEED_SHOTS,
    );
    assert!(
        total_classical <= ALT_SEED_CLASSICAL_LIMIT,
        "ALT-SEED CLASSICAL FAILURE: {} classical mismatches exceeds limit {} across {} seeds × {} shots",
        total_classical,
        ALT_SEED_CLASSICAL_LIMIT,
        n_seeds,
        ALT_SEED_SHOTS,
    );
}

// ═══════════════════════════════════════════════════════════════════════════
//  Top-level point addition
// ═══════════════════════════════════════════════════════════════════════════

#[derive(Clone, Copy)]
enum SourceLiveCubicLamClean {
    Dirty,
    HmrPhaseRepair { inverse_iters: usize },
    Inverse { inverse_iters: usize },
    Product { inverse_iters: usize },
}

fn emit_source_live_cubic_hmr_repair_from_inverse(
    b: &mut B,
    ty: &[QubitId],
    lam: &[QubitId],
    oy: &[BitId],
    inv_raw: &[QubitId],
    lam_masks: &[BitId],
    p: U256,
    inverse_iters: usize,
    prescaled_inverse: bool,
) {
    let repair_start = b.ops.len();
    b.set_phase("source_live_cubic_hmr_repair_add_qy_to_yprod");
    mod_add_qb_phase_clean(b, ty, oy, p);
    b.set_phase("source_live_cubic_hmr_recompute_old_lam");
    if prescaled_inverse {
        d1_direct_quotient_arithmetic_from_prescaled_inverse(b, ty, lam, inv_raw, p);
    } else {
        d1_direct_quotient_arithmetic_from_raw_inverse(b, ty, lam, inv_raw, p, inverse_iters);
    }
    let repair_forward: Vec<_> = b.ops[repair_start..].to_vec();

    b.set_phase("source_live_cubic_hmr_apply_lam_mask");
    for i in 0..N {
        b.z_if(lam[i], lam_masks[i]);
    }

    b.set_phase("source_live_cubic_hmr_uncompute_old_lam");
    emit_inverse_ops_measurement_clean_scoped(
        b,
        &repair_forward,
        "source_live_cubic_hmr_phase_repair",
    );
}

fn emit_source_live_cubic_xtail_ytail(
    b: &mut B,
    tx: &[QubitId],
    ty: &[QubitId],
    lam: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    p: U256,
    clean_lam: SourceLiveCubicLamClean,
) {
    debug_assert_eq!(tx.len(), N);
    debug_assert_eq!(ty.len(), N);
    debug_assert_eq!(lam.len(), N);
    debug_assert_eq!(ox.len(), N);
    debug_assert_eq!(oy.len(), N);

    // Entry convention: tx = dx, ty = dy, lam = -lambda. Keeping dy live
    // gives the curve-supported identity
    //   Ry = dy + lam^3 - 3*Qx*lam - Qy.
    // The clean mode then uses the second affine identity
    //   Ry + Qy = lam * (Rx - Qx)
    // to zero the separate slope word with only the pair2 inverse/multiply
    // cleanup. It deliberately does not route through the D1 in-place product
    // lowerer, whose displaced old target is the source of the dirty product
    // shortcut.
    let lam_sq = b.alloc_qubits(N);
    b.set_phase("source_live_cubic_compute_lam_sq");
    squaring_add_to_acc_schoolbook_phase_clean(b, &lam_sq, lam, p);

    b.set_phase("source_live_cubic_xtail_sub_lam_sq");
    mod_sub_qq(b, tx, &lam_sq, p);
    b.set_phase("source_live_cubic_xtail_add_3qx");
    mod_add_double_qb_phase_clean(b, tx, ox, p);
    mod_add_qb_phase_clean(b, tx, ox, p);
    b.set_phase("source_live_cubic_xtail_neg_to_rx_minus_qx");
    mod_neg_inplace(b, tx, p);

    b.set_phase("source_live_cubic_ytail_add_lam_cube");
    if std::env::var("SOURCE_LIVE_CUBIC_LAMCUBE_MUL").is_ok() {
        mod_mul_add_into_acc_selected(b, ty, &lam_sq, lam, p, "SOURCE_LIVE_CUBIC_LAMCUBE_MUL");
    } else {
        mod_mul_add_into_acc_schoolbook_phase_clean(b, ty, &lam_sq, lam, p);
    }

    let three_lam = b.alloc_qubits(N);
    b.set_phase("source_live_cubic_build_three_lam");
    for i in 0..N {
        b.cx(lam[i], three_lam[i]);
    }
    mod_double_inplace(b, &three_lam, p);
    mod_add_qq(b, &three_lam, lam, p);

    b.set_phase("source_live_cubic_ytail_sub_3qx_lam");
    if std::env::var("SOURCE_LIVE_CUBIC_QX_CLASSICAL_MUL")
        .ok()
        .as_deref()
        == Some("1")
    {
        mod_mul_sub_qb(b, ty, &three_lam, ox, p);
    } else {
        let qx = load_bits(b, ox);
        match std::env::var("SOURCE_LIVE_CUBIC_QX_MUL").ok().as_deref() {
            Some("karatsuba1") | Some("1") => {
                mod_mul_sub_into_acc_karatsuba(b, ty, &three_lam, &qx, p)
            }
            Some("schoolbook_peak_lowq") => {
                mod_mul_sub_into_acc_schoolbook_peak_lowq(b, ty, &three_lam, &qx, p)
            }
            Some("schoolbook") => mod_mul_sub_into_acc_schoolbook(b, ty, &three_lam, &qx, p),
            Some(other) => panic!(
                "unsupported SOURCE_LIVE_CUBIC_QX_MUL={other}; expected schoolbook, schoolbook_peak_lowq, or karatsuba1"
            ),
            None => mod_mul_sub_into_acc_schoolbook_phase_clean(b, ty, &three_lam, &qx, p),
        }
        unload_bits(b, &qx, ox);
    }

    b.set_phase("source_live_cubic_uncompute_three_lam");
    mod_sub_qq(b, &three_lam, lam, p);
    mod_halve_inplace(b, &three_lam, p);
    for i in 0..N {
        b.cx(lam[i], three_lam[i]);
    }
    b.free_vec(&three_lam);

    b.set_phase("source_live_cubic_ytail_sub_qy");
    mod_sub_qb_phase_clean(b, ty, oy, p);

    b.set_phase("source_live_cubic_uncompute_lam_sq");
    squaring_sub_from_acc_schoolbook_phase_clean(b, &lam_sq, lam, p);
    b.free_vec(&lam_sq);

    match clean_lam {
        SourceLiveCubicLamClean::Dirty => {}
        SourceLiveCubicLamClean::HmrPhaseRepair { inverse_iters } => {
            b.set_phase("source_live_cubic_hmr_measure_old_lam");
            let lam_masks = b.alloc_bits(N);
            for i in 0..N {
                b.hmr(lam[i], lam_masks[i]);
            }

            b.set_phase("source_live_cubic_hmr_repair_inverse");
            let prescaled_inverse = std::env::var("PA_SOURCE_LIVE_CUBIC_HMR_PRESCALED_KAL")
                .ok()
                .as_deref()
                == Some("1");
            if prescaled_inverse {
                let chunked = std::env::var("PA_SOURCE_LIVE_CUBIC_HMR_PRESCALED_CHUNKED")
                    .ok()
                    .as_deref()
                    != Some("0");
                if chunked {
                    with_kal_inv_raw_prescaled_chunked(b, tx, p, inverse_iters, |b, inv_raw| {
                        emit_source_live_cubic_hmr_repair_from_inverse(
                            b,
                            ty,
                            lam,
                            oy,
                            inv_raw,
                            &lam_masks,
                            p,
                            inverse_iters,
                            true,
                        );
                    });
                } else {
                    with_kal_inv_raw_prescaled_mixed(b, tx, p, inverse_iters, |b, inv_raw| {
                        emit_source_live_cubic_hmr_repair_from_inverse(
                            b,
                            ty,
                            lam,
                            oy,
                            inv_raw,
                            &lam_masks,
                            p,
                            inverse_iters,
                            true,
                        );
                    });
                }
            } else {
                with_kal_inv_raw_borrowing_v(b, tx, p, inverse_iters, |b, inv_raw| {
                    emit_source_live_cubic_hmr_repair_from_inverse(
                        b,
                        ty,
                        lam,
                        oy,
                        inv_raw,
                        &lam_masks,
                        p,
                        inverse_iters,
                        false,
                    );
                });
            }

            b.set_phase("source_live_cubic_hmr_free_zero_lam");
            b.free_vec(lam);
        }
        SourceLiveCubicLamClean::Inverse { inverse_iters } => {
            b.set_phase("source_live_cubic_lambda_clean_add_qy_to_yprod");
            mod_add_qb_phase_clean(b, ty, oy, p);

            b.set_phase("source_live_cubic_lambda_clean_inverse");
            with_kal_inv_raw(b, tx, p, inverse_iters, |b, inv_raw| {
                b.set_phase("source_live_cubic_lambda_clean_double");
                for _ in 0..inverse_iters {
                    mod_double_inplace_fast(b, lam, p);
                }
                b.set_phase("source_live_cubic_lambda_clean_mul");
                mod_mul_add_into_acc_selected(
                    b,
                    lam,
                    inv_raw,
                    ty,
                    p,
                    "SOURCE_LIVE_CUBIC_CLEAN_LAM_MUL",
                );
                b.set_phase("source_live_cubic_lambda_clean_restore_ry");
                mod_sub_qb_phase_clean(b, ty, oy, p);
                b.set_phase("source_live_cubic_lambda_clean_backward");
            });

            b.set_phase("source_live_cubic_lambda_clean_free_lam");
            b.free_vec(lam);
        }
        SourceLiveCubicLamClean::Product { inverse_iters } => {
            b.set_phase("source_live_cubic_product_clean_lam_times_rx_minus_qx");
            d1_inplace_product_lowerer_with_kaliski_clean(b, tx, lam, p, inverse_iters);
            b.set_phase("source_live_cubic_product_clean_sub_ry");
            mod_sub_qq(b, lam, ty, p);
            b.set_phase("source_live_cubic_product_clean_sub_qy");
            mod_sub_qb_phase_clean(b, lam, oy, p);
            b.set_phase("source_live_cubic_product_clean_free_lam");
            b.free_vec(lam);
        }
    }

    b.set_phase("source_live_cubic_finalize_rx");
    mod_add_qb_phase_clean(b, tx, ox, p);
}

fn emit_source_live_clean_product_tail(
    b: &mut B,
    tx: &[QubitId],
    ty: &[QubitId],
    lam: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    p: U256,
    inverse_iters: usize,
) {
    debug_assert_eq!(tx.len(), N);
    debug_assert_eq!(ty.len(), N);
    debug_assert_eq!(lam.len(), N);
    debug_assert_eq!(ox.len(), N);
    debug_assert_eq!(oy.len(), N);

    // Entry convention: tx = dx, ty = dy, lam = -lambda.  First consume the
    // source-live invariant dy + lam*dx = 0, then use lam itself as the product
    // target: lam <- lam*(Rx-Qx) = Ry+Qy.  Swapping that word into ty leaves
    // the separate slope register clean without the dirty cubic reset.
    b.set_phase("source_live_product_tail_zero_dy");
    mod_mul_add_into_acc_selected(b, ty, lam, tx, p, "SOURCE_LIVE_ZERO_DY_MUL");
    b.free_vec(ty);

    if std::env::var("PA_SOURCE_LIVE_DIRECT_XTAIL_SQUARE")
        .ok()
        .as_deref()
        == Some("1")
    {
        b.set_phase("source_live_product_tail_direct_xtail_square");
        mod_mul_sub_qq(b, tx, lam, lam, p);
    } else {
        let lam_sq = b.alloc_qubits(N);
        b.set_phase("source_live_product_tail_compute_lam_sq");
        squaring_add_to_acc_schoolbook_phase_clean(b, &lam_sq, lam, p);

        b.set_phase("source_live_product_tail_xtail_sub_lam_sq");
        mod_sub_qq(b, tx, &lam_sq, p);
        b.set_phase("source_live_product_tail_uncompute_lam_sq");
        squaring_sub_from_acc_schoolbook_phase_clean(b, &lam_sq, lam, p);
        b.free_vec(&lam_sq);
    }
    b.set_phase("source_live_product_tail_xtail_add_3qx");
    mod_add_double_qb_phase_clean(b, tx, ox, p);
    mod_add_qb_phase_clean(b, tx, ox, p);
    b.set_phase("source_live_product_tail_xtail_neg_to_rx_minus_qx");
    mod_neg_inplace(b, tx, p);

    if std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_OVERWRITE")
        .ok()
        .as_deref()
        == Some("1")
    {
        let quotient_phase_repair =
            std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_QUOTIENT_PHASE_REPAIR")
                .ok()
                .as_deref()
                == Some("1");
        let direct_quotient_phase_repair =
            std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_DIRECT_QUOTIENT_PHASE_REPAIR")
                .ok()
                .as_deref()
                == Some("1");
        let single_inverse_phase_repair =
            std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_SINGLE_INVERSE_PHASE_REPAIR")
                .ok()
                .as_deref()
                == Some("1");
        assert!(
            !(quotient_phase_repair || direct_quotient_phase_repair || single_inverse_phase_repair)
                || std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_REPAIR_UNSAFE_PROBE")
                    .ok()
                    .as_deref()
                    == Some("1"),
            "source-live product HMR phase-repair flags are rejected: Round508 basis-fuzz probes \
             show quotient, direct-quotient, and single-inverse repairs are value-corrupt and over \
             budget. Set PA_SOURCE_LIVE_PRODUCT_HMR_REPAIR_UNSAFE_PROBE=1 only to reproduce the \
             rejected lanes."
        );
        b.set_phase("source_live_product_tail_hmr_reacquire_zero_ty");
        b.reacquire_vec(ty);
        b.set_phase("source_live_product_tail_hmr_product_into_ty");
        mod_mul_write_into_zero_acc_selected(
            b,
            ty,
            lam,
            tx,
            p,
            "SOURCE_LIVE_PRODUCT_HMR_WRITE_MUL",
        );

        b.set_phase("source_live_product_tail_hmr_measure_old_lam");
        let lam_masks = b.alloc_bits(N);
        for i in 0..N {
            b.hmr(lam[i], lam_masks[i]);
        }

        if single_inverse_phase_repair {
            b.set_phase("source_live_product_tail_hmr_single_inv_phase_repair");
            with_kal_inv_raw_borrowing_v(b, tx, p, inverse_iters, |b, inv_raw| {
                let repair_start = b.ops.len();
                d1_direct_quotient_arithmetic_from_raw_inverse(
                    b,
                    ty,
                    lam,
                    inv_raw,
                    p,
                    inverse_iters,
                );
                let repair_forward: Vec<_> = b.ops[repair_start..].to_vec();

                b.set_phase("source_live_product_tail_hmr_single_inv_apply_lam_mask");
                for i in 0..N {
                    b.z_if(lam[i], lam_masks[i]);
                }

                b.set_phase("source_live_product_tail_hmr_single_inv_uncompute_old_lam");
                if source_live_product_hmr_keep_measured_conditions_enabled() {
                    emit_inverse_ops_hmr_safe_keep_conditions(
                        b,
                        &repair_forward,
                        "source_live_product_tail_hmr_single_inverse_phase_repair",
                    );
                } else {
                    emit_inverse_ops_measurement_clean_scoped(
                        b,
                        &repair_forward,
                        "source_live_product_tail_hmr_single_inverse_phase_repair",
                    );
                }
            });
        } else if direct_quotient_phase_repair {
            b.set_phase("source_live_product_tail_hmr_direct_phase_compute_old_lam");
            let direct_start = b.ops.len();
            d1_direct_quotient_compute_into_zero(b, tx, ty, lam, p, inverse_iters);
            let direct_forward: Vec<_> = b.ops[direct_start..].to_vec();

            b.set_phase("source_live_product_tail_hmr_direct_phase_apply_lam_mask");
            for i in 0..N {
                b.z_if(lam[i], lam_masks[i]);
            }

            if source_live_product_hmr_direct_forward_clean_enabled() {
                b.set_phase("source_live_product_tail_hmr_direct_phase_product_clean_lam");
                d1_inplace_product_lowerer_with_kaliski_clean(b, tx, lam, p, inverse_iters);
                b.set_phase("source_live_product_tail_hmr_direct_phase_sub_yprod");
                mod_sub_qq(b, lam, ty, p);
            } else if source_live_product_hmr_keep_measured_conditions_enabled() {
                b.set_phase("source_live_product_tail_hmr_direct_phase_uncompute_old_lam");
                emit_inverse_ops_hmr_safe_keep_conditions(
                    b,
                    &direct_forward,
                    "source_live_product_tail_hmr_direct_quotient_phase_repair",
                );
            } else {
                b.set_phase("source_live_product_tail_hmr_direct_phase_uncompute_old_lam");
                emit_inverse_ops_measurement_clean_scoped(
                    b,
                    &direct_forward,
                    "source_live_product_tail_hmr_direct_quotient_phase_repair",
                );
            }
        } else if quotient_phase_repair {
            b.set_phase("source_live_product_tail_hmr_phase_copy_yprod_to_lam");
            for i in 0..N {
                b.cx(ty[i], lam[i]);
            }

            b.set_phase("source_live_product_tail_hmr_phase_recompute_old_lam");
            d1_inplace_product_hmr_phase_compute_old_target(b, tx, lam, p, inverse_iters);

            b.set_phase("source_live_product_tail_hmr_phase_apply_lam_mask");
            for i in 0..N {
                b.z_if(lam[i], lam_masks[i]);
            }

            b.set_phase("source_live_product_tail_hmr_phase_uncompute_old_lam");
            d1_inplace_product_lowerer_with_kaliski_clean(b, tx, lam, p, inverse_iters);

            b.set_phase("source_live_product_tail_hmr_phase_uncopy_yprod_from_lam");
            for i in (0..N).rev() {
                b.cx(ty[i], lam[i]);
            }
        }
        b.free_vec(lam);

        b.set_phase("source_live_product_tail_sub_qy");
        mod_sub_qb_phase_clean(b, ty, oy, p);

        b.set_phase("source_live_product_tail_finalize_rx");
        mod_add_qb_phase_clean(b, tx, ox, p);
        return;
    }

    if std::env::var("PA_SOURCE_LIVE_PRODUCT_CENTERED_QUOTIENT_CLEAN")
        .ok()
        .as_deref()
        == Some("1")
    {
        b.set_phase("source_live_product_tail_centered_reacquire_zero_ty");
        b.reacquire_vec(ty);
        b.set_phase("source_live_product_tail_centered_product_into_ty");
        mod_mul_write_into_zero_acc_selected(
            b,
            ty,
            lam,
            tx,
            p,
            "SOURCE_LIVE_PRODUCT_CENTERED_WRITE_MUL",
        );

        b.set_phase("source_live_product_tail_centered_clean_lam");
        add_neg_quotient_into_acc_with_centered_by_bench(b, lam, tx, ty, p);
        b.free_vec(lam);

        b.set_phase("source_live_product_tail_sub_qy");
        mod_sub_qb_phase_clean(b, ty, oy, p);

        b.set_phase("source_live_product_tail_finalize_rx");
        mod_add_qb_phase_clean(b, tx, ox, p);
        return;
    }

    b.set_phase("source_live_product_tail_inplace_lam_times_rx_minus_qx");
    d1_inplace_product_lowerer_with_kaliski_clean(b, tx, lam, p, inverse_iters);

    b.set_phase("source_live_product_tail_sub_qy");
    mod_sub_qb_phase_clean(b, lam, oy, p);

    b.set_phase("source_live_product_tail_reacquire_zero_ty");
    b.reacquire_vec(ty);
    b.set_phase("source_live_product_tail_swap_y_into_ty");
    for i in 0..N {
        b.swap(ty[i], lam[i]);
    }
    b.set_phase("source_live_product_tail_free_zero_lam");
    b.free_vec(lam);

    b.set_phase("source_live_product_tail_finalize_rx");
    mod_add_qb_phase_clean(b, tx, ox, p);
}

fn source_live_product_hmr_keep_measured_conditions_enabled() -> bool {
    std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_KEEP_MEASURED_CONDITIONS")
        .ok()
        .as_deref()
        == Some("1")
}

fn source_live_product_hmr_direct_forward_clean_enabled() -> bool {
    std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_DIRECT_FORWARD_CLEAN")
        .ok()
        .as_deref()
        == Some("1")
}

fn build_standard_point_add(
    b: &mut B,
    tx: &[QubitId],
    ty: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    p: U256,
) {
    if halfgcd_live_pa::round162_halfgcd_live_pa_enabled() {
        halfgcd_live_pa::emit_round162_halfgcd_live_pa_or_fail(b, tx, ty, ox, oy, p);
    }

    if round158_halfgcd_splice_live::round158_live_prefix_pa_route_enabled() {
        round158_halfgcd_splice_live::abort_round158_live_prefix_pa_route(tx, ty, ox, oy, p);
    }

    let pair2_branch_inv = std::env::var("KAL_PAIR2_BRANCH_INV_ROLL").ok().as_deref() == Some("1");
    let prescale_pair1 = std::env::var("KAL_PRESCALE_PAIR1_SAFE").ok().as_deref() == Some("1");
    let prescale_pair1_mixed =
        std::env::var("KAL_PRESCALE_PAIR1_MIXED").ok().as_deref() == Some("1");
    let prescale_pair1_chunked =
        std::env::var("KAL_PRESCALE_PAIR1_CHUNKED").ok().as_deref() == Some("1");
    let prescale_pair1_folded =
        std::env::var("KAL_PRESCALE_PAIR1_FOLDED").ok().as_deref() == Some("1");
    let prescale_pair1_folded_chunked = std::env::var("KAL_PRESCALE_PAIR1_FOLDED_CHUNKED")
        .ok()
        .as_deref()
        == Some("1");
    let prescale_pair2 = std::env::var("KAL_PRESCALE_PAIR2_SAFE").ok().as_deref() == Some("1");
    let prescale_pair2_mixed =
        std::env::var("KAL_PRESCALE_PAIR2_MIXED").ok().as_deref() == Some("1");
    let prescale_pair2_chunked =
        std::env::var("KAL_PRESCALE_PAIR2_CHUNKED").ok().as_deref() == Some("1");
    let prescale_pair2_folded =
        std::env::var("KAL_PRESCALE_PAIR2_FOLDED").ok().as_deref() == Some("1");
    let prescale_pair2_folded_chunked = std::env::var("KAL_PRESCALE_PAIR2_FOLDED_CHUNKED")
        .ok()
        .as_deref()
        == Some("1");
    let by_pair1_centered = std::env::var("BY_CENTERED_PAIR1_REPLACE").ok().as_deref() == Some("1");
    let by_pair2_centered = std::env::var("BY_CENTERED_PAIR2_REPLACE").ok().as_deref() == Some("1");
    let by_pair2_scaled_product = std::env::var("BY_SCALED_PAIR2_PRODUCT_REPLACE")
        .ok()
        .as_deref()
        == Some("1");
    let round200_full_gcd_pair1 = std::env::var("ROUND200_FULL_GCD_PAIR1_REPLACE")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_cubic_ytail =
        std::env::var("PA_SOURCE_LIVE_CUBIC_YTAIL").ok().as_deref() == Some("1");
    let source_live_cubic_lambda_clean = std::env::var("PA_SOURCE_LIVE_CUBIC_LAMBDA_CLEAN")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_cubic_product_clean = std::env::var("PA_SOURCE_LIVE_CUBIC_PRODUCT_CLEAN")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_cubic_hmr_phase_repair = std::env::var("PA_SOURCE_LIVE_CUBIC_HMR_PHASE_REPAIR")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_clean_product_tail = std::env::var("PA_SOURCE_LIVE_CLEAN_PRODUCT_TAIL")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_product_hmr_overwrite = std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_OVERWRITE")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_product_hmr_quotient_phase_repair =
        std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_QUOTIENT_PHASE_REPAIR")
            .ok()
            .as_deref()
            == Some("1");
    let source_live_product_hmr_direct_quotient_phase_repair =
        std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_DIRECT_QUOTIENT_PHASE_REPAIR")
            .ok()
            .as_deref()
            == Some("1");
    let source_live_product_hmr_single_inverse_phase_repair =
        std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_SINGLE_INVERSE_PHASE_REPAIR")
            .ok()
            .as_deref()
            == Some("1");
    let source_live_product_centered_quotient_clean =
        std::env::var("PA_SOURCE_LIVE_PRODUCT_CENTERED_QUOTIENT_CLEAN")
            .ok()
            .as_deref()
            == Some("1");
    let source_live_product_hmr_allow_dirty =
        std::env::var("PA_SOURCE_LIVE_PRODUCT_HMR_ALLOW_PHASE_DIRTY")
            .ok()
            .as_deref()
            == Some("1");
    let source_live_tail = source_live_cubic_ytail
        || source_live_cubic_lambda_clean
        || source_live_cubic_product_clean
        || source_live_cubic_hmr_phase_repair
        || source_live_clean_product_tail;
    let source_live_cubic_allow_dirty = std::env::var("PA_SOURCE_LIVE_CUBIC_ALLOW_PHASE_DIRTY")
        .ok()
        .as_deref()
        == Some("1");
    let source_live_cubic_borrow_pair1 = std::env::var("PA_SOURCE_LIVE_CUBIC_BORROW_PAIR1")
        .ok()
        .as_deref()
        == Some("1");
    let coeff_channel_div = std::env::var("KAL_TAGGED_DIV_COEFF_CHANNEL")
        .ok()
        .as_deref()
        == Some("1");
    let branch_hist_div = std::env::var("KAL_TAGGED_DIV_BRANCH_HIST").ok().as_deref() == Some("1");
    let branch_stream_div = std::env::var("KAL_TAGGED_DIV_BRANCH_STREAM")
        .ok()
        .as_deref()
        == Some("1");
    let branch_term_div = std::env::var("KAL_TAGGED_DIV_BRANCH_TERM").ok().as_deref() == Some("1");
    let branch_term_roll_div = std::env::var("KAL_TAGGED_DIV_BRANCH_TERM_ROLL")
        .ok()
        .as_deref()
        == Some("1");
    let tagged_div_validate = coeff_channel_div
        || branch_hist_div
        || branch_stream_div
        || branch_term_div
        || branch_term_roll_div
        || std::env::var("KAL_TAGGED_DIV_VALIDATE").ok().as_deref() == Some("1");
    let pair1_iters = std::env::var("KAL_PAIR1_ITERS")
        .ok()
        .and_then(|s| s.parse::<usize>().ok())
        .map(|iters| {
            checked_kaliski_iters(
                "round8 pair1",
                "KAL_PAIR1_ITERS",
                iters,
                ROUND24_PAIR1_MIN_SAFE_ITERS,
            )
        })
        .unwrap_or(ROUND24_PAIR1_MIN_SAFE_ITERS);
    // The tagged validation paths change the op stream / Fiat-Shamir seed;
    // keep pair2 at the prior robust 404 setting to avoid conflating the
    // algebra probe with an iteration-threshold phase cliff.  Env overrides are
    // for approximate-correctness threshold research only; default remains the
    // exact checked setting.  For the normal exact path, full-harness probes
    // after the R_SMALL_THRESHOLD=260 update found pair2=400 clean; pair2=399
    // remains outside the verified safety margin.  A Google-sample KMX row with
    // pair1=400,pair2=400 passes 9024, but the source alt-seed diagnostic still
    // catches a phase batch, so the robust source default stays at pair1=404.
    let pair2_default = if tagged_div_validate || pair2_branch_inv {
        404
    } else {
        400
    };
    let pair2_iters = std::env::var("KAL_PAIR2_ITERS")
        .ok()
        .and_then(|s| s.parse::<usize>().ok())
        .map(|iters| {
            checked_kaliski_iters(
                "round8 pair2",
                "KAL_PAIR2_ITERS",
                iters,
                ROUND8_QTAIL_PAIR2_MIN_SAFE_ITERS,
            )
        })
        .unwrap_or(pair2_default);
    let lend_ty_pair1_backward =
        std::env::var("KAL_LEND_TY_PAIR1_BACKWARD").ok().as_deref() == Some("1");
    let free_lam_before_pair2_backward = std::env::var("KAL_FREE_LAM_BEFORE_PAIR2_BACKWARD")
        .ok()
        .as_deref()
        == Some("1");
    let defer_pair2_product = (std::env::var("KAL_DEFER_PAIR2_PRODUCT").ok().as_deref()
        == Some("1")
        || std::env::var("KAL_DEFER_PAIR2_PRODUCT_LOWQ")
            .ok()
            .as_deref()
            == Some("1"))
        && !by_pair2_centered
        && !pair2_branch_inv
        && !prescale_pair2
        && !prescale_pair2_mixed
        && !prescale_pair2_chunked
        && !prescale_pair2_folded
        && !prescale_pair2_folded_chunked
        && !by_pair2_scaled_product;
    let affine_combined_y = env_flag_enabled("POINT_ADD_AFFINE_COMBINED_Y", true)
        && !round200_full_gcd_pair1
        && !source_live_tail
        && !source_live_cubic_borrow_pair1
        && !by_pair1_centered
        && !by_pair2_centered
        && !by_pair2_scaled_product
        && !coeff_channel_div
        && !branch_hist_div
        && !branch_stream_div
        && !branch_term_div
        && !branch_term_roll_div
        && !tagged_div_validate
        && !pair2_branch_inv
        && !prescale_pair1
        && !prescale_pair1_mixed
        && !prescale_pair1_chunked
        && !prescale_pair1_folded
        && !prescale_pair1_folded_chunked
        && !prescale_pair2
        && !prescale_pair2_mixed
        && !prescale_pair2_chunked
        && !prescale_pair2_folded
        && !prescale_pair2_folded_chunked
        && !lend_ty_pair1_backward
        && !defer_pair2_product;
    assert!(
        [
            source_live_cubic_ytail,
            source_live_cubic_lambda_clean,
            source_live_cubic_product_clean,
            source_live_cubic_hmr_phase_repair,
            source_live_clean_product_tail
        ]
        .iter()
        .filter(|&&enabled| enabled)
        .count()
            <= 1,
        "select only one source-live y-tail"
    );
    if source_live_cubic_ytail {
        assert!(
            source_live_cubic_allow_dirty,
            "PA_SOURCE_LIVE_CUBIC_YTAIL leaves the separate lam word nonzero; \
             set PA_SOURCE_LIVE_CUBIC_ALLOW_PHASE_DIRTY=1 only for red-team \
             resource probes, not candidate KMX emission"
        );
        assert!(
            !by_pair1_centered
                && !coeff_channel_div
                && !branch_hist_div
                && !branch_stream_div
                && !branch_term_div
                && !branch_term_roll_div
                && !tagged_div_validate
                && !prescale_pair1
                && !prescale_pair1_mixed
                && !prescale_pair1_chunked
                && !prescale_pair1_folded
                && !prescale_pair1_folded_chunked
                && !lend_ty_pair1_backward
                && !pair2_branch_inv
                && !prescale_pair2
                && !prescale_pair2_mixed
                && !prescale_pair2_chunked
                && !prescale_pair2_folded
                && !prescale_pair2_folded_chunked
                && !by_pair2_centered
                && !by_pair2_scaled_product
                && !defer_pair2_product
                && !free_lam_before_pair2_backward,
            "PA_SOURCE_LIVE_CUBIC_YTAIL requires a raw pair1 Kaliski path and bypasses pair2"
        );
    }
    if source_live_clean_product_tail {
        assert!(
            !(source_live_product_hmr_overwrite && source_live_product_centered_quotient_clean),
            "select only one source-live product-tail lambda cleanup"
        );
        assert!(
            [
                source_live_product_hmr_quotient_phase_repair,
                source_live_product_hmr_direct_quotient_phase_repair,
                source_live_product_hmr_single_inverse_phase_repair,
                source_live_product_hmr_allow_dirty,
            ]
            .iter()
            .filter(|&&enabled| enabled)
            .count()
                <= 1,
            "select only one source-live HMR phase policy"
        );
        assert!(
            !source_live_product_hmr_overwrite
                || source_live_product_hmr_quotient_phase_repair
                || source_live_product_hmr_direct_quotient_phase_repair
                || source_live_product_hmr_single_inverse_phase_repair
                || source_live_product_hmr_allow_dirty,
            "PA_SOURCE_LIVE_PRODUCT_HMR_OVERWRITE measures the old lam word and is phase-dirty; \
             set PA_SOURCE_LIVE_PRODUCT_HMR_QUOTIENT_PHASE_REPAIR=1 for the counted in-place repair, \
             set PA_SOURCE_LIVE_PRODUCT_HMR_DIRECT_QUOTIENT_PHASE_REPAIR=1 for the output-side quotient phase repair, or \
             set PA_SOURCE_LIVE_PRODUCT_HMR_SINGLE_INVERSE_PHASE_REPAIR=1 for the live-inverse output-side repair, or \
             set PA_SOURCE_LIVE_PRODUCT_HMR_ALLOW_PHASE_DIRTY=1 only for red-team resource probes, \
             not candidate KMX emission"
        );
        assert!(
            !round200_full_gcd_pair1
                && !by_pair1_centered
                && !coeff_channel_div
                && !branch_hist_div
                && !branch_stream_div
                && !branch_term_div
                && !branch_term_roll_div
                && !tagged_div_validate
                && !prescale_pair1
                && !prescale_pair1_mixed
                && !prescale_pair1_chunked
                && !prescale_pair1_folded
                && !prescale_pair1_folded_chunked
                && !lend_ty_pair1_backward
                && !pair2_branch_inv
                && !prescale_pair2
                && !prescale_pair2_mixed
                && !prescale_pair2_chunked
                && !prescale_pair2_folded
                && !prescale_pair2_folded_chunked
                && !by_pair2_centered
                && !by_pair2_scaled_product
                && !defer_pair2_product
                && !free_lam_before_pair2_backward,
            "PA_SOURCE_LIVE_CLEAN_PRODUCT_TAIL requires a raw pair1 Kaliski path and bypasses pair2"
        );
    }
    if source_live_cubic_lambda_clean {
        assert!(
            !round200_full_gcd_pair1
                && !by_pair1_centered
                && !coeff_channel_div
                && !branch_hist_div
                && !branch_stream_div
                && !branch_term_div
                && !branch_term_roll_div
                && !tagged_div_validate
                && !prescale_pair1
                && !prescale_pair1_mixed
                && !prescale_pair1_chunked
                && !prescale_pair1_folded
                && !prescale_pair1_folded_chunked
                && !lend_ty_pair1_backward
                && !pair2_branch_inv
                && !prescale_pair2
                && !prescale_pair2_mixed
                && !prescale_pair2_chunked
                && !prescale_pair2_folded
                && !prescale_pair2_folded_chunked
                && !by_pair2_centered
                && !by_pair2_scaled_product
                && !defer_pair2_product
                && !free_lam_before_pair2_backward,
            "PA_SOURCE_LIVE_CUBIC_LAMBDA_CLEAN requires a raw pair1 Kaliski path and bypasses pair2 product emission"
        );
    }
    if source_live_cubic_product_clean {
        assert!(
            !round200_full_gcd_pair1
                && !by_pair1_centered
                && !coeff_channel_div
                && !branch_hist_div
                && !branch_stream_div
                && !branch_term_div
                && !branch_term_roll_div
                && !tagged_div_validate
                && !prescale_pair1
                && !prescale_pair1_mixed
                && !prescale_pair1_chunked
                && !prescale_pair1_folded
                && !prescale_pair1_folded_chunked
                && !lend_ty_pair1_backward
                && !pair2_branch_inv
                && !prescale_pair2
                && !prescale_pair2_mixed
                && !prescale_pair2_chunked
                && !prescale_pair2_folded
                && !prescale_pair2_folded_chunked
                && !by_pair2_centered
                && !by_pair2_scaled_product
                && !defer_pair2_product
                && !free_lam_before_pair2_backward,
            "PA_SOURCE_LIVE_CUBIC_PRODUCT_CLEAN requires a raw pair1 Kaliski path and bypasses pair2 product emission"
        );
    }
    if source_live_cubic_hmr_phase_repair {
        assert!(
            !round200_full_gcd_pair1
                && !by_pair1_centered
                && !coeff_channel_div
                && !branch_hist_div
                && !branch_stream_div
                && !branch_term_div
                && !branch_term_roll_div
                && !tagged_div_validate
                && !prescale_pair1
                && !prescale_pair1_mixed
                && !prescale_pair1_chunked
                && !prescale_pair1_folded
                && !prescale_pair1_folded_chunked
                && !lend_ty_pair1_backward
                && !pair2_branch_inv
                && !prescale_pair2
                && !prescale_pair2_mixed
                && !prescale_pair2_chunked
                && !prescale_pair2_folded
                && !prescale_pair2_folded_chunked
                && !by_pair2_centered
                && !by_pair2_scaled_product
                && !defer_pair2_product
                && !free_lam_before_pair2_backward,
            "PA_SOURCE_LIVE_CUBIC_HMR_PHASE_REPAIR requires a raw pair1 Kaliski path and bypasses pair2"
        );
    }
    if tagged_div_validate && !by_pair1_centered {
        // Structural validation path for the 600-scratch DIV idea: seed the
        // numerator as dy+dx, so the Kaliski coefficient output is tagged by
        // a known k*dx term. This is default-off because it adds gates; it is
        // an algebra/circuit integration probe, not a benchmark optimization.
        b.set_phase("tagged_div_seed");
        mod_add_qq_fast(b, &ty, &tx, p);
    }

    let lam_cell: std::cell::RefCell<Option<Vec<QubitId>>> = std::cell::RefCell::new(None);
    let ty_lent_pair1_backward = std::cell::Cell::new(false);
    if round200_full_gcd_pair1 {
        let lam_inner = emit_round200_semantic_full_gcd_pair1_checkpoint_in_place_with_options(
            b,
            &tx,
            &ty,
            p,
            source_live_tail,
        );
        *lam_cell.borrow_mut() = Some(lam_inner);
    } else if by_pair1_centered {
        let lam_inner = compute_pair1_lam_with_centered_by_bench(b, &tx, &ty, p);
        b.set_phase("pair1_by_centered_zero_ty_mul2");
        mod_mul_add_into_acc_selected(b, &ty, &lam_inner, &tx, p, "PAIR1_ZERO_TY_MUL");
        *lam_cell.borrow_mut() = Some(lam_inner);
    } else if branch_term_roll_div {
        // Compressed branch stream with a rolling active flag. This keeps the
        // 9-bit terminal index qubit saving, but avoids branch_term's expensive
        // per-iteration `term_idx > i` comparator and double cmod-add replay.
        let lam_inner = b.alloc_qubits(N);
        let lam_coeff = lam_inner.clone();
        let ty_coeff: Vec<QubitId> = ty.to_vec();
        b.set_phase("pair1_kaliski_branch_term_roll");
        with_kal_branch_term_roll_tagged_div(
            b,
            &tx,
            p,
            pair1_iters,
            (&lam_coeff, &ty_coeff),
            |b| {
                b.set_phase("pair1_branch_term_roll_halve");
                for _ in 0..pair1_iters {
                    mod_halve_inplace_fast(b, &lam_inner, p);
                }
                b.set_phase("pair1_branch_term_roll_untag_lam");
                mod_add_qc(b, &lam_inner, U256::from(1u64), p);
                *lam_cell.borrow_mut() = Some(lam_inner);
            },
        );
    } else if branch_term_div {
        // Compressed branch stream: store m_hist+a_hist plus a 9-bit terminal
        // index instead of a full add_hist. Coefficient replay reconstructs
        // active VG adds using term_idx > i.
        let lam_inner = b.alloc_qubits(N);
        let lam_coeff = lam_inner.clone();
        let ty_coeff: Vec<QubitId> = ty.to_vec();
        b.set_phase("pair1_kaliski_branch_term");
        with_kal_branch_term_tagged_div(b, &tx, p, pair1_iters, (&lam_coeff, &ty_coeff), |b| {
            b.set_phase("pair1_branch_term_halve");
            for _ in 0..pair1_iters {
                mod_halve_inplace_fast(b, &lam_inner, p);
            }
            b.set_phase("pair1_branch_term_untag_lam");
            mod_add_qc(b, &lam_inner, U256::from(1u64), p);
            *lam_cell.borrow_mut() = Some(lam_inner);
        });
    } else if branch_stream_div {
        // Branch-generation stream: record just branch histories, free the
        // denominator state, then replay those histories into the tagged
        // coefficient channel. This tests the qubit shape that a future
        // self-cleaning DIV would need.
        let lam_inner = b.alloc_qubits(N);
        let lam_coeff = lam_inner.clone();
        let ty_coeff: Vec<QubitId> = ty.to_vec();
        b.set_phase("pair1_kaliski_branch_stream");
        with_kal_branch_stream_tagged_div(b, &tx, p, pair1_iters, (&lam_coeff, &ty_coeff), |b| {
            b.set_phase("pair1_branch_stream_halve");
            for _ in 0..pair1_iters {
                mod_halve_inplace_fast(b, &lam_inner, p);
            }
            b.set_phase("pair1_branch_stream_untag_lam");
            mod_add_qc(b, &lam_inner, U256::from(1u64), p);
            *lam_cell.borrow_mut() = Some(lam_inner);
        });
    } else if branch_hist_div {
        // More aggressive structural probe: do not run the ordinary inverse
        // coefficient `(r,s)` at all. Store `a_hist` next to `m_hist`; together
        // they recover the branch pair while the external `(lam,ty)` channel
        // receives the tagged quotient.
        let lam_inner = b.alloc_qubits(N);
        let lam_coeff = lam_inner.clone();
        let ty_coeff: Vec<QubitId> = ty.to_vec();
        b.set_phase("pair1_kaliski_branch_hist_coeff");
        with_kal_branch_tagged_div_coeff(b, &tx, p, pair1_iters, (&lam_coeff, &ty_coeff), |b| {
            b.set_phase("pair1_branch_hist_halve");
            for _ in 0..pair1_iters {
                mod_halve_inplace_fast(b, &lam_inner, p);
            }
            b.set_phase("pair1_branch_hist_untag_lam");
            mod_add_qc(b, &lam_inner, U256::from(1u64), p);
            *lam_cell.borrow_mut() = Some(lam_inner);
        });
    } else if coeff_channel_div {
        // Experimental structural path: compute the tagged quotient by carrying
        // an external coefficient pair `(lam_inner, ty)` through the Kaliski
        // forward pass. This removes pair1's two schoolbook multiplications;
        // the ordinary inverse state is still present solely to provide clean
        // branch controls and to be Bennett-uncomputed afterwards.
        let lam_inner = b.alloc_qubits(N);
        let lam_coeff = lam_inner.clone();
        let ty_coeff: Vec<QubitId> = ty.to_vec();
        b.set_phase("pair1_kaliski_forward_coeff_channel");
        with_kal_inv_raw_coeff(
            b,
            &tx,
            p,
            pair1_iters,
            Some((&lam_coeff, &ty_coeff)),
            |b, _inv_raw| {
                b.set_phase("pair1_coeff_channel_halve");
                for _ in 0..pair1_iters {
                    mod_halve_inplace_fast(b, &lam_inner, p);
                }
                // lam_inner = -(lambda+1) after consuming tagged ty=(dy+dx).
                // Add 1 to recover the normal lam_inner=-lambda expected by
                // the remaining point-add scaffold.
                b.set_phase("pair1_coeff_channel_untag_lam");
                mod_add_qc(b, &lam_inner, U256::from(1u64), p);
                b.set_phase("pair1_kaliski_backward");
                *lam_cell.borrow_mut() = Some(lam_inner);
            },
        );
    } else if prescale_pair1
        || prescale_pair1_mixed
        || prescale_pair1_chunked
        || prescale_pair1_folded
        || prescale_pair1_folded_chunked
    {
        // Scale absorption probe: Kaliski raw output is `-v^-1 * 2^iters`.
        // Feed `v = 2^iters * dx` so the exposed raw inverse is exactly
        // `-dx^-1`; this deletes the pair1 correction-halving loop.
        if prescale_pair1_folded || prescale_pair1_folded_chunked {
            if prescale_pair1_folded_chunked {
                b.set_phase("pair1_kaliski_forward_prescaled_folded_chunked");
                with_kal_inv_raw_prescaled_chunked(b, &tx, p, pair1_iters, |b, inv_raw| {
                    let lam_inner = b.alloc_qubits(N);
                    b.set_phase("pair1_prescale_mul1");
                    mod_mul_write_into_zero_acc_schoolbook(b, &lam_inner, &ty, inv_raw, p);
                    b.set_phase("pair1_prescale_mul2");
                    mod_mul_add_into_acc_selected(b, &ty, &lam_inner, &tx, p, "PAIR1_ZERO_TY_MUL");
                    b.set_phase("pair1_kaliski_backward_prescaled_folded_chunked");
                    *lam_cell.borrow_mut() = Some(lam_inner);
                });
            } else {
                b.set_phase("pair1_kaliski_forward_prescaled_folded");
                with_kal_inv_raw_prescaled_mixed(b, &tx, p, pair1_iters, |b, inv_raw| {
                    let lam_inner = b.alloc_qubits(N);
                    b.set_phase("pair1_prescale_mul1");
                    mod_mul_write_into_zero_acc_schoolbook(b, &lam_inner, &ty, inv_raw, p);
                    b.set_phase("pair1_prescale_mul2");
                    mod_mul_add_into_acc_selected(b, &ty, &lam_inner, &tx, p, "PAIR1_ZERO_TY_MUL");
                    b.set_phase("pair1_kaliski_backward_prescaled_folded");
                    *lam_cell.borrow_mut() = Some(lam_inner);
                });
            }
        } else {
            // SAFE path uses exact Cuccaro arithmetic because the generic fast
            // prescaler was classically correct but alt-seed phase-unsafe. The
            // MIXED path keeps fast shifts but exact q-q add/sub. CHUNKED keeps
            // the exact q-q add/sub contract but replaces long scale walks with
            // Solinas k-bit shifts between sparse set-bit positions.  The
            // full pair1+pair2 folded-chunked harness is phase-clean and saves
            // Toffoli, but even after source borrowing it peaks at 2897q, so
            // keep it opt-in until the shifted prescaler is fused or made
            // lower-peak without reusing phase-tainted scratch as Kaliski state.
            let scaled_tx = b.alloc_qubits(N);
            let scale = pow_mod_2_k(p, pair1_iters);
            b.set_phase("pair1_prescale_den_safe");
            if prescale_pair1_chunked {
                mul_by_const_acc_chunked_shifts_inplace_src(b, &tx, scale, &scaled_tx, p, false);
            } else if prescale_pair1_mixed {
                mul_by_const_acc_exact_adds_fast_shifts(b, &tx, scale, &scaled_tx, p, false);
            } else {
                mul_by_const_acc_phase_clean(b, &tx, scale, &scaled_tx, p, false);
            }
            b.set_phase("pair1_kaliski_forward_prescaled_safe");
            with_kal_inv_raw(b, &scaled_tx, p, pair1_iters, |b, inv_raw| {
                let lam_inner = b.alloc_qubits(N);
                b.set_phase("pair1_prescale_mul1");
                mod_mul_write_into_zero_acc_schoolbook(b, &lam_inner, &ty, inv_raw, p);
                b.set_phase("pair1_prescale_mul2");
                mod_mul_add_into_acc_selected(b, &ty, &lam_inner, &tx, p, "PAIR1_ZERO_TY_MUL");
                b.set_phase("pair1_kaliski_backward_prescaled_safe");
                *lam_cell.borrow_mut() = Some(lam_inner);
            });
            b.set_phase("pair1_unprescale_den_safe");
            if prescale_pair1_chunked {
                mul_by_const_acc_chunked_shifts_inplace_src(b, &tx, scale, &scaled_tx, p, true);
            } else if prescale_pair1_mixed {
                mul_by_const_acc_exact_adds_fast_shifts(b, &tx, scale, &scaled_tx, p, true);
            } else {
                mul_by_const_acc_phase_clean(b, &tx, scale, &scaled_tx, p, true);
            }
            b.free_vec(&scaled_tx);
        }
    } else if source_live_tail && source_live_cubic_borrow_pair1 {
        b.set_phase("pair1_source_live_cubic_borrow_v_kaliski_forward");
        with_kal_inv_raw_borrowing_v(b, &tx, p, pair1_iters, |b, inv_raw| {
            let lam_inner = b.alloc_qubits(N);
            b.set_phase("pair1_source_live_cubic_borrow_v_mul1");
            match std::env::var("SOURCE_LIVE_PAIR1_LAM_MUL").ok().as_deref() {
                Some("schoolbook") => {
                    mod_mul_add_into_acc_schoolbook(b, &lam_inner, &ty, inv_raw, p)
                }
                Some("schoolbook_peak_lowq") => {
                    mod_mul_add_into_acc_schoolbook_peak_lowq(
                        b,
                        &lam_inner,
                        &ty,
                        inv_raw,
                        p,
                    )
                }
                Some("karatsuba1") | Some("1") => {
                    mod_mul_add_into_acc_karatsuba(b, &lam_inner, &ty, inv_raw, p)
                }
                Some("karatsuba2") | Some("2") => {
                    mod_mul_add_into_acc_karatsuba2(b, &lam_inner, &ty, inv_raw, p)
                }
                Some(other) => panic!(
                    "unsupported SOURCE_LIVE_PAIR1_LAM_MUL={other}; expected schoolbook, schoolbook_peak_lowq, karatsuba1, karatsuba2"
                ),
                None => {
                    mod_mul_add_into_acc_schoolbook_phase_clean(
                        b,
                        &lam_inner,
                        &ty,
                        inv_raw,
                        p,
                    )
                }
            }
            b.set_phase("pair1_source_live_cubic_borrow_v_halve");
            for _ in 0..pair1_iters {
                mod_halve_inplace_fast(b, &lam_inner, p);
            }
            *lam_cell.borrow_mut() = Some(lam_inner);
            b.set_phase("pair1_source_live_cubic_borrow_v_kaliski_backward");
        });
    } else {
        b.set_phase("pair1_kaliski_forward");
        with_kal_inv_raw(b, &tx, p, pair1_iters, |b, inv_raw| {
            let lam_inner = b.alloc_qubits(N);
            b.set_phase("pair1_mul1");
            if source_live_tail {
                match std::env::var("SOURCE_LIVE_PAIR1_LAM_MUL").ok().as_deref() {
                    Some("schoolbook") => {
                        mod_mul_add_into_acc_schoolbook(b, &lam_inner, &ty, inv_raw, p)
                    }
                    Some("schoolbook_peak_lowq") => {
                        mod_mul_add_into_acc_schoolbook_peak_lowq(
                            b,
                            &lam_inner,
                            &ty,
                            inv_raw,
                            p,
                        )
                    }
                    Some("karatsuba1") | Some("1") => {
                        mod_mul_add_into_acc_karatsuba(b, &lam_inner, &ty, inv_raw, p)
                    }
                    Some("karatsuba2") | Some("2") => {
                        mod_mul_add_into_acc_karatsuba2(b, &lam_inner, &ty, inv_raw, p)
                    }
                    Some(other) => panic!(
                        "unsupported SOURCE_LIVE_PAIR1_LAM_MUL={other}; expected schoolbook, schoolbook_peak_lowq, karatsuba1, karatsuba2"
                    ),
                    None => {
                        mod_mul_add_into_acc_schoolbook_phase_clean(
                            b,
                            &lam_inner,
                            &ty,
                            inv_raw,
                            p,
                        )
                    }
                }
            } else {
                mod_mul_write_into_zero_acc_selected(
                    b,
                    &lam_inner,
                    &ty,
                    inv_raw,
                    p,
                    "PAIR1_MUL1_WRITE",
                );
            }
            b.set_phase("pair1_halve");
            for _ in 0..pair1_iters {
                mod_halve_inplace_fast(b, &lam_inner, p);
            }
            if source_live_tail {
                b.set_phase("pair1_preserve_dy_for_source_live_tail");
            } else if affine_combined_y {
                b.set_phase("pair1_mul2_deferred_affine_combined_y");
            } else {
                b.set_phase("pair1_mul2");
                mod_mul_add_into_acc_selected(b, &ty, &lam_inner, &tx, p, "PAIR1_ZERO_TY_MUL");
            }
            if tagged_div_validate {
                // lam_inner = -(lambda+1) after consuming tagged ty=(dy+dx).
                // Add 1 to recover the normal lam_inner=-lambda expected by the
                // remaining point-add scaffold.
                b.set_phase("tagged_div_untag_lam");
                mod_add_qc(b, &lam_inner, U256::from(1u64), p);
            }
            if lend_ty_pair1_backward {
                b.set_phase("pair1_lend_zero_ty_before_kaliski_backward");
                b.free_vec(&ty);
                ty_lent_pair1_backward.set(true);
            }
            b.set_phase("pair1_kaliski_backward");
            *lam_cell.borrow_mut() = Some(lam_inner);
        });
    }
    if ty_lent_pair1_backward.get() {
        b.set_phase("pair1_reacquire_ty_after_kaliski_backward");
        b.reacquire_vec(&ty);
    }
    let lam: Vec<QubitId> = lam_cell.into_inner().expect("lam set");

    if source_live_clean_product_tail {
        emit_source_live_clean_product_tail(b, &tx, &ty, &lam, &ox, &oy, p, pair2_iters);
        return;
    }

    if source_live_cubic_lambda_clean {
        emit_source_live_cubic_xtail_ytail(
            b,
            &tx,
            &ty,
            &lam,
            &ox,
            &oy,
            p,
            SourceLiveCubicLamClean::Inverse {
                inverse_iters: pair2_iters,
            },
        );
        return;
    }

    if source_live_cubic_product_clean {
        emit_source_live_cubic_xtail_ytail(
            b,
            &tx,
            &ty,
            &lam,
            &ox,
            &oy,
            p,
            SourceLiveCubicLamClean::Product {
                inverse_iters: pair2_iters,
            },
        );
        return;
    }

    if source_live_cubic_hmr_phase_repair {
        emit_source_live_cubic_xtail_ytail(
            b,
            &tx,
            &ty,
            &lam,
            &ox,
            &oy,
            p,
            SourceLiveCubicLamClean::HmrPhaseRepair {
                inverse_iters: pair2_iters,
            },
        );
        return;
    }

    if source_live_cubic_ytail {
        emit_source_live_cubic_xtail_ytail(
            b,
            &tx,
            &ty,
            &lam,
            &ox,
            &oy,
            p,
            SourceLiveCubicLamClean::Dirty,
        );
        // Dirty experimental path only: lam is still `-lambda` here, so this
        // reset is the measured source of the inverted phase failures.
        b.set_phase("source_live_cubic_dirty_free_lam");
        b.free_vec(&lam);
        return;
    }

    if affine_combined_y {
        square_tx_and_combined_ty_l2minus3qx(b, &tx, &ty, &lam, &ox, p);
    } else {
        mod_mul_sub_qq(b, &tx, &lam, &lam, p);
        mod_add_double_qb(b, &tx, &ox, p);
        mod_add_qb(b, &tx, &ox, p);
        mod_neg_inplace_fast(b, &tx, p);
    }
    let lam_freed_before_pair2_backward = std::cell::Cell::new(false);
    if by_pair2_scaled_product {
        b.set_phase("pair2_by_scaled_product");
        write_pair2_product_and_clean_lam_with_scaled_by_bench(b, &lam, &tx, &ty, p);
        b.set_phase("pair2_by_scaled_product_cleanup");
        mod_sub_qb(b, &ty, &oy, p);
    } else {
        let ty_lent_pair2_forward = std::cell::Cell::new(false);
        if affine_combined_y {
            b.set_phase("mul3_deferred_affine_combined_y");
        } else if defer_pair2_product {
            b.set_phase("pair2_lend_zero_ty_before_kaliski_forward");
            b.free_vec(&ty);
            ty_lent_pair2_forward.set(true);
        } else {
            b.set_phase("mul3_between_pair");
            mod_mul_write_into_zero_acc_karatsuba2(b, &ty, &lam, &tx, p);
        }
        if by_pair2_centered {
            b.set_phase("pair2_by_centered_compute_correction");
            add_neg_quotient_into_acc_with_centered_by_bench(b, &lam, &tx, &ty, p);
            b.set_phase("pair2_by_centered_cleanup");
            mod_sub_qb(b, &ty, &oy, p);
        } else {
            b.set_phase("pair2_kaliski_forward");
            if pair2_branch_inv {
                // Compact exact inversion scaffold for pair2: branch histories +
                // coefficient replay compute inv_raw, then replay is reversed after
                // lam cleanup. This targets qubit shape rather than Toffoli.
                with_kal_branch_inv_raw_roll(b, &tx, p, pair2_iters, |b, inv_raw| {
                    b.set_phase("pair2_branch_inv_double");
                    for _ in 0..pair2_iters {
                        mod_double_inplace_fast(b, &lam, p);
                    }
                    b.set_phase("pair2_branch_inv_mul");
                    mod_mul_add_into_acc_selected(b, &lam, inv_raw, &ty, p, "PAIR2_CLEAN_LAM_MUL");
                    b.set_phase("pair2_branch_inv_cleanup");
                    mod_sub_qb(b, &ty, &oy, p);
                });
            } else if prescale_pair2
                || prescale_pair2_mixed
                || prescale_pair2_chunked
                || prescale_pair2_folded
                || prescale_pair2_folded_chunked
            {
                // Pair2 scale absorption: feed `2^iters * (Rx-Qx)` so the raw inverse
                // is exact and the lam-doubling correction loop disappears.
                if prescale_pair2_folded || prescale_pair2_folded_chunked {
                    if prescale_pair2_folded_chunked {
                        with_kal_inv_raw_prescaled_chunked(b, &tx, p, pair2_iters, |b, inv_raw| {
                            b.set_phase("pair2_prescale_mul");
                            mod_mul_add_into_acc_selected(
                                b,
                                &lam,
                                inv_raw,
                                &ty,
                                p,
                                "PAIR2_CLEAN_LAM_MUL",
                            );
                            b.set_phase("pair2_prescale_cleanup");
                            mod_sub_qb(b, &ty, &oy, p);
                            b.set_phase("pair2_kaliski_backward_prescaled_folded_chunked");
                        });
                    } else {
                        with_kal_inv_raw_prescaled_mixed(b, &tx, p, pair2_iters, |b, inv_raw| {
                            b.set_phase("pair2_prescale_mul");
                            mod_mul_add_into_acc_selected(
                                b,
                                &lam,
                                inv_raw,
                                &ty,
                                p,
                                "PAIR2_CLEAN_LAM_MUL",
                            );
                            b.set_phase("pair2_prescale_cleanup");
                            mod_sub_qb(b, &ty, &oy, p);
                            b.set_phase("pair2_kaliski_backward_prescaled_folded");
                        });
                    }
                } else {
                    let scaled_tx = b.alloc_qubits(N);
                    let scale = pow_mod_2_k(p, pair2_iters);
                    b.set_phase("pair2_prescale_den_safe");
                    if prescale_pair2_chunked {
                        mul_by_const_acc_chunked_shifts_inplace_src(
                            b, &tx, scale, &scaled_tx, p, false,
                        );
                    } else if prescale_pair2_mixed {
                        mul_by_const_acc_exact_adds_fast_shifts(
                            b, &tx, scale, &scaled_tx, p, false,
                        );
                    } else {
                        mul_by_const_acc_phase_clean(b, &tx, scale, &scaled_tx, p, false);
                    }
                    with_kal_inv_raw(b, &scaled_tx, p, pair2_iters, |b, inv_raw| {
                        b.set_phase("pair2_prescale_mul");
                        mod_mul_add_into_acc_selected(
                            b,
                            &lam,
                            inv_raw,
                            &ty,
                            p,
                            "PAIR2_CLEAN_LAM_MUL",
                        );
                        b.set_phase("pair2_prescale_cleanup");
                        mod_sub_qb(b, &ty, &oy, p);
                        b.set_phase("pair2_kaliski_backward_prescaled_safe");
                    });
                    b.set_phase("pair2_unprescale_den_safe");
                    if prescale_pair2_chunked {
                        mul_by_const_acc_chunked_shifts_inplace_src(
                            b, &tx, scale, &scaled_tx, p, true,
                        );
                    } else if prescale_pair2_mixed {
                        mul_by_const_acc_exact_adds_fast_shifts(b, &tx, scale, &scaled_tx, p, true);
                    } else {
                        mul_by_const_acc_phase_clean(b, &tx, scale, &scaled_tx, p, true);
                    }
                    b.free_vec(&scaled_tx);
                }
            } else {
                let borrow_pair2_tx_inverse =
                    std::env::var("KAL_PAIR2_BORROW_TX_INVERSE").ok().as_deref() == Some("1")
                        && !defer_pair2_product;
                if borrow_pair2_tx_inverse {
                    b.set_phase("pair2_kaliski_forward_borrow_tx");
                    with_kal_inv_raw_borrowing_v(b, &tx, p, pair2_iters, |b, inv_raw| {
                        b.set_phase("pair2_double");
                        for _ in 0..pair2_iters {
                            mod_double_inplace_fast(b, &lam, p);
                        }
                        b.set_phase("pair2_mul");
                        mod_mul_add_into_acc_selected(
                            b,
                            &lam,
                            inv_raw,
                            &ty,
                            p,
                            "PAIR2_CLEAN_LAM_MUL",
                        );
                        b.set_phase("pair2_cleanup");
                        mod_sub_qb(b, &ty, &oy, p);
                        if free_lam_before_pair2_backward {
                            b.set_phase("pair2_free_lam_before_kaliski_backward");
                            b.free_vec(&lam);
                            lam_freed_before_pair2_backward.set(true);
                        }
                        b.set_phase("pair2_kaliski_backward_borrow_tx");
                    });
                } else {
                    with_kal_inv_raw(b, &tx, p, pair2_iters, |b, inv_raw| {
                        if defer_pair2_product && ty_lent_pair2_forward.get() {
                            b.set_phase("pair2_reacquire_ty_and_mul3_after_kaliski_forward");
                            b.reacquire_vec(&ty);
                            if std::env::var("KAL_DEFER_PAIR2_PRODUCT_LOWQ")
                                .ok()
                                .as_deref()
                                == Some("1")
                            {
                                mod_mul_add_qq(b, &ty, &lam, &tx, p);
                            } else {
                                mod_mul_write_into_zero_acc_karatsuba2(b, &ty, &lam, &tx, p);
                            }
                        }
                        b.set_phase("pair2_double");
                        for _ in 0..pair2_iters {
                            mod_double_inplace_fast(b, &lam, p);
                        }
                        b.set_phase("pair2_mul");
                        mod_mul_add_into_acc_selected(
                            b,
                            &lam,
                            inv_raw,
                            &ty,
                            p,
                            "PAIR2_CLEAN_LAM_MUL",
                        );
                        b.set_phase("pair2_cleanup");
                        mod_sub_qb(b, &ty, &oy, p);
                        if free_lam_before_pair2_backward {
                            b.set_phase("pair2_free_lam_before_kaliski_backward");
                            b.free_vec(&lam);
                            lam_freed_before_pair2_backward.set(true);
                        }
                        b.set_phase("pair2_kaliski_backward");
                    });
                }
            }
        }
    }
    mod_add_qb(b, &tx, &ox, p);
    if !lam_freed_before_pair2_backward.get() {
        b.free_vec(&lam);
    }
}

fn round24_pair1_iters() -> usize {
    let (env_name, value) = if let Ok(s) = std::env::var("ROUND24_PAIR1_ITERS") {
        ("ROUND24_PAIR1_ITERS", s)
    } else if let Ok(s) = std::env::var("KAL_PAIR1_ITERS") {
        ("KAL_PAIR1_ITERS", s)
    } else {
        return ROUND24_PAIR1_MIN_SAFE_ITERS;
    };
    let iters = value
        .parse::<usize>()
        .unwrap_or_else(|_| panic!("{env_name} must be a usize, got {value:?}"));
    checked_kaliski_iters(
        "round24 pair1 checkpoint",
        env_name,
        iters,
        ROUND24_PAIR1_MIN_SAFE_ITERS,
    )
}

fn round24_swap_clean_lam_into_ty(b: &mut B, ty: &[QubitId], lam: &[QubitId], p: U256) {
    debug_assert_eq!(ty.len(), lam.len());
    b.set_phase("round24_pair1_negate_lam_to_positive_slope");
    mod_neg_inplace_fast(b, lam, p);
    b.set_phase("round24_pair1_swap_lam_into_zero_ty");
    for i in 0..ty.len() {
        b.swap(ty[i], lam[i]);
    }
    b.set_phase("round24_pair1_free_zero_lam_scratch");
    b.free_vec(lam);
}

fn round24_mul_lam_into_zero(
    b: &mut B,
    lam: &[QubitId],
    numerator: &[QubitId],
    inv_raw: &[QubitId],
    p: U256,
) {
    match std::env::var("ROUND24_PAIR1_LAM_MUL").ok().as_deref() {
        Some("walk") => mod_mul_add_qq(b, lam, inv_raw, numerator, p),
        Some("schoolbook_lowq") => {
            mod_mul_write_into_zero_acc_schoolbook_lowq(b, lam, numerator, inv_raw, p)
        }
        Some("schoolbook_peak_lowq") => {
            mod_mul_write_into_zero_acc_schoolbook_peak_lowq(b, lam, numerator, inv_raw, p)
        }
        Some("karatsuba1") => mod_mul_write_into_zero_acc_karatsuba(b, lam, numerator, inv_raw, p),
        Some("karatsuba_lowq") | Some("lowq") => {
            mod_mul_write_into_zero_acc_karatsuba_lowq(b, lam, numerator, inv_raw, p)
        }
        Some("karatsuba2") => mod_mul_write_into_zero_acc_karatsuba2(b, lam, numerator, inv_raw, p),
        _ => mod_mul_write_into_zero_acc_schoolbook(b, lam, numerator, inv_raw, p),
    }
}

fn mod_mul_add_into_acc_selected(
    b: &mut B,
    acc: &[QubitId],
    x: &[QubitId],
    y: &[QubitId],
    p: U256,
    env_name: &str,
) {
    let local = std::env::var(env_name).ok();
    let global = std::env::var("PA_MUL_ADD_INTO_ACC").ok();
    let default = match env_name {
        "PAIR1_ZERO_TY_MUL" => "karatsuba_lowq",
        "PAIR2_CLEAN_LAM_MUL" => "karatsuba1",
        _ => "schoolbook",
    };
    match local.as_deref().or(global.as_deref()).unwrap_or(default) {
        "walk" => mod_mul_add_qq(b, acc, x, y, p),
        "karatsuba1" | "1" => mod_mul_add_into_acc_karatsuba(b, acc, x, y, p),
        "karatsuba2" | "2" => mod_mul_add_into_acc_karatsuba2(b, acc, x, y, p),
        "karatsuba_lowq" | "lowq" => {
            mod_mul_add_into_acc_karatsuba_lowq(b, acc, x, y, p)
        }
        "schoolbook_peak_lowq" => mod_mul_add_into_acc_schoolbook_peak_lowq(b, acc, x, y, p),
        "schoolbook" => mod_mul_add_into_acc_schoolbook(b, acc, x, y, p),
        other => panic!(
            "unsupported {env_name}={other}; expected schoolbook, schoolbook_peak_lowq, walk, karatsuba1, karatsuba2, or karatsuba_lowq"
        ),
    }
}

fn mod_mul_write_into_zero_acc_selected(
    b: &mut B,
    acc: &[QubitId],
    x: &[QubitId],
    y: &[QubitId],
    p: U256,
    env_name: &str,
) {
    let local = std::env::var(env_name).ok();
    let global = std::env::var("PA_MUL_WRITE_INTO_ZERO_ACC").ok();
    let default = match env_name {
        "PAIR1_MUL1_WRITE" => "karatsuba1",
        _ => "schoolbook",
    };
    match local.as_deref().or(global.as_deref()).unwrap_or(default) {
        "walk" => mod_mul_add_qq(b, acc, x, y, p),
        "karatsuba1" | "1" => mod_mul_write_into_zero_acc_karatsuba(b, acc, x, y, p),
        "karatsuba_lowq" | "lowq" => mod_mul_write_into_zero_acc_karatsuba_lowq(b, acc, x, y, p),
        "karatsuba2" | "2" => mod_mul_write_into_zero_acc_karatsuba2(b, acc, x, y, p),
        "schoolbook_peak_lowq" => mod_mul_write_into_zero_acc_schoolbook_peak_lowq(b, acc, x, y, p),
        "schoolbook_lowq" => mod_mul_write_into_zero_acc_schoolbook_lowq(b, acc, x, y, p),
        "schoolbook" => mod_mul_write_into_zero_acc_schoolbook(b, acc, x, y, p),
        other => panic!(
            "unsupported {env_name}={other}; expected schoolbook, schoolbook_lowq, schoolbook_peak_lowq, walk, karatsuba1, karatsuba_lowq, or karatsuba2"
        ),
    }
}

fn round24_emit_two_bank_pair1_checkpoint(b: &mut B, tx: &[QubitId], ty: &[QubitId], p: U256) {
    let pair1_iters = round24_pair1_iters();
    let mode = std::env::var("ROUND24_PAIR1_MODE").unwrap_or_else(|_| "folded_chunked".to_string());

    match mode.as_str() {
        "raw" => {
            b.set_phase("round24_pair1_raw_kaliski_forward");
            with_kal_inv_raw(b, tx, p, pair1_iters, |b, inv_raw| {
                let lam = b.alloc_qubits(N);
                b.set_phase("round24_pair1_raw_mul_lam_scratch");
                round24_mul_lam_into_zero(b, &lam, ty, inv_raw, p);
                b.set_phase("round24_pair1_raw_halve_lam_scratch");
                for _ in 0..pair1_iters {
                    mod_halve_inplace_fast(b, &lam, p);
                }
                b.set_phase("round24_pair1_raw_zero_ty");
                mod_mul_add_into_acc_selected(b, ty, &lam, tx, p, "ROUND24_PAIR1_ZERO_TY_MUL");
                round24_swap_clean_lam_into_ty(b, ty, &lam, p);
                b.set_phase("round24_pair1_raw_kaliski_backward");
            });
        }
        "folded_chunked" => {
            b.set_phase("round24_pair1_folded_chunked_kaliski_forward");
            with_kal_inv_raw_prescaled_chunked(b, tx, p, pair1_iters, |b, inv_raw| {
                let lam = b.alloc_qubits(N);
                b.set_phase("round24_pair1_folded_chunked_mul_lam_scratch");
                round24_mul_lam_into_zero(b, &lam, ty, inv_raw, p);
                b.set_phase("round24_pair1_folded_chunked_zero_ty");
                mod_mul_add_into_acc_selected(b, ty, &lam, tx, p, "ROUND24_PAIR1_ZERO_TY_MUL");
                round24_swap_clean_lam_into_ty(b, ty, &lam, p);
                b.set_phase("round24_pair1_folded_chunked_kaliski_backward");
            });
        }
        "raw_borrow_v" => {
            let lam_cell: std::cell::RefCell<Option<Vec<QubitId>>> = std::cell::RefCell::new(None);
            b.set_phase("round24_pair1_raw_borrow_v_kaliski_forward");
            with_kal_inv_raw_borrowing_v(b, tx, p, pair1_iters, |b, inv_raw| {
                let lam = b.alloc_qubits(N);
                b.set_phase("round24_pair1_raw_borrow_v_mul_lam_scratch");
                round24_mul_lam_into_zero(b, &lam, ty, inv_raw, p);
                b.set_phase("round24_pair1_raw_borrow_v_halve_lam_scratch");
                for _ in 0..pair1_iters {
                    mod_halve_inplace_fast(b, &lam, p);
                }
                *lam_cell.borrow_mut() = Some(lam);
                b.set_phase("round24_pair1_raw_borrow_v_kaliski_backward");
            });
            let lam = lam_cell.into_inner().expect("round24 raw_borrow_v lam set");
            b.set_phase("round24_pair1_raw_borrow_v_zero_ty_after_restore");
            mod_mul_add_into_acc_selected(b, ty, &lam, tx, p, "ROUND24_PAIR1_ZERO_TY_MUL");
            round24_swap_clean_lam_into_ty(b, ty, &lam, p);
        }
        other => panic!(
            "unsupported ROUND24_PAIR1_MODE={other}; expected raw, folded_chunked, or raw_borrow_v"
        ),
    }
}

pub fn build_round24_two_bank_pair1_checkpoint() -> Vec<Op> {
    let b = &mut B::new();
    let tx = b.alloc_qubits(N);
    b.declare_qubit_register(&tx);
    let ty = b.alloc_qubits(N);
    b.declare_qubit_register(&ty);
    let ox = b.alloc_bits(N);
    b.declare_bit_register(&ox);
    let oy = b.alloc_bits(N);
    b.declare_bit_register(&oy);

    let p = SECP256K1_P;
    b.set_phase("round24_google_abi_dx");
    mod_sub_qb(b, &tx, &ox, p);
    b.set_phase("round24_google_abi_dy");
    mod_sub_qb(b, &ty, &oy, p);
    round24_emit_two_bank_pair1_checkpoint(b, &tx, &ty, p);

    // This guarded hook intentionally stops at (h, lambda), so the production
    // point-add semantic alt-seed check is not applicable here.
    b.ops.clone()
}

fn round84_emit_fused_square_xtail(
    b: &mut B,
    tx: &[QubitId],
    lam: &[QubitId],
    ox: &[BitId],
    p: U256,
) {
    b.set_phase("round84_fused_square_xtail_dx_sub_lam_square_lowq");
    if std::env::var("ROUND84_XTAIL_WALK_SQUARE").ok().as_deref() == Some("1") {
        squaring_sub_from_acc_walk_controls_lowq(b, tx, lam, p);
    } else if std::env::var("ROUND84_XTAIL_SCHOOLBOOK").ok().as_deref() == Some("1") {
        squaring_sub_from_acc_schoolbook(b, tx, lam, p);
    } else {
        squaring_sub_from_acc_schoolbook_lowq_shift22(b, tx, lam, p);
    }
    b.set_phase("round84_fused_square_xtail_add_double_ox");
    mod_add_double_qb(b, tx, ox, p);
    b.set_phase("round84_fused_square_xtail_negate_to_x3");
    mod_neg_inplace_fast(b, tx, p);
}

pub fn build_round84_fused_square_xtail_component() -> Vec<Op> {
    build_round84_fused_square_xtail_component_builder().ops
}

fn build_round84_fused_square_xtail_component_builder() -> B {
    let mut b = B::new();
    let tx = b.alloc_qubits(N);
    b.declare_qubit_register(&tx);
    let lam = b.alloc_qubits(N);
    b.declare_qubit_register(&lam);
    let ox = b.alloc_bits(N);
    b.declare_bit_register(&ox);
    let oy = b.alloc_bits(N);
    b.declare_bit_register(&oy);

    round84_emit_fused_square_xtail(&mut b, &tx, &lam, &ox, SECP256K1_P);
    b
}

pub fn build_round84_fused_square_xtail_component_phase_resources(
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round84_fused_square_xtail_component_builder();
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

fn toggle_eq_zero_flag_fast(b: &mut B, v: &[QubitId], flag: QubitId) {
    let n = v.len();
    assert!(n > 0);
    if n == 1 {
        b.x(v[0]);
        b.cx(v[0], flag);
        b.x(v[0]);
        return;
    }

    let or_chain = b.alloc_qubits(n - 1);
    or_step(b, v[0], v[1], or_chain[0]);
    for i in 1..n - 1 {
        or_step(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }
    b.x(or_chain[n - 2]);
    b.cx(or_chain[n - 2], flag);
    b.x(or_chain[n - 2]);
    for i in (1..n - 1).rev() {
        or_step_uncompute(b, or_chain[i - 1], v[i + 1], or_chain[i]);
    }
    or_step_uncompute(b, v[0], v[1], or_chain[0]);
    b.free_vec(&or_chain);
}

fn round564_compute_polarized_d(
    b: &mut B,
    x: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    eq: QubitId,
    p: U256,
) -> Vec<QubitId> {
    let d = load_bits(b, ox);
    mod_sub_qq_fast(b, &d, x, p);

    let two_oy = load_bits(b, oy);
    mod_double_inplace_fast(b, &two_oy, p);
    cmod_add_qq(b, &d, &two_oy, eq, p);
    mod_halve_inplace_fast(b, &two_oy, p);
    unload_bits(b, &two_oy, oy);
    d
}

fn round564_uncompute_polarized_d(
    b: &mut B,
    d: &[QubitId],
    x: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    eq: QubitId,
    p: U256,
) {
    let two_oy = load_bits(b, oy);
    mod_double_inplace_fast(b, &two_oy, p);
    cmod_sub_qq(b, d, &two_oy, eq, p);
    mod_halve_inplace_fast(b, &two_oy, p);
    unload_bits(b, &two_oy, oy);

    mod_add_qq_fast(b, d, x, p);
    unload_bits(b, d, ox);
}

fn round564_square_add_selected(b: &mut B, acc: &[QubitId], x: &[QubitId], p: U256) {
    if std::env::var("ROUND564_YTAIL_PHASE_CLEAN_SQUARES")
        .ok()
        .as_deref()
        == Some("1")
    {
        squaring_add_to_acc_schoolbook_phase_clean(b, acc, x, p);
    } else {
        squaring_add_to_acc_schoolbook(b, acc, x, p);
    }
}

fn round564_square_sub_selected(b: &mut B, acc: &[QubitId], x: &[QubitId], p: U256) {
    if std::env::var("ROUND564_YTAIL_PHASE_CLEAN_SQUARES")
        .ok()
        .as_deref()
        == Some("1")
    {
        squaring_sub_from_acc_schoolbook_phase_clean(b, acc, x, p);
    } else {
        squaring_sub_from_acc_schoolbook_lowq_shift22(b, acc, x, p);
    }
}

fn round564_emit_polarized_third_square_ytail_component(
    b: &mut B,
    x: &[QubitId],
    u: &[QubitId],
    ox: &[BitId],
    oy: &[BitId],
    y_acc: &[QubitId],
    p: U256,
) {
    debug_assert_eq!(x.len(), N);
    debug_assert_eq!(u.len(), N);
    debug_assert_eq!(ox.len(), N);
    debug_assert_eq!(oy.len(), N);
    debug_assert_eq!(y_acc.len(), N);

    b.set_phase("round564_ytail_eq_diff");
    let eq_diff = load_bits(b, ox);
    mod_sub_qq_fast(b, &eq_diff, x, p);
    let eq = b.alloc_qubit();
    toggle_eq_zero_flag_fast(b, &eq_diff, eq);

    b.set_phase("round564_ytail_compute_d");
    let d = round564_compute_polarized_d(b, x, ox, oy, eq, p);

    b.set_phase("round564_ytail_compute_u_plus_d");
    let u_plus_d = b.alloc_qubits(N);
    for i in 0..N {
        b.cx(u[i], u_plus_d[i]);
    }
    mod_add_qq_fast(b, &u_plus_d, &d, p);

    b.set_phase("round564_ytail_add_u_plus_d_square");
    round564_square_add_selected(b, y_acc, &u_plus_d, p);
    b.set_phase("round564_ytail_sub_u_square");
    round564_square_sub_selected(b, y_acc, u, p);
    b.set_phase("round564_ytail_sub_d_square");
    round564_square_sub_selected(b, y_acc, &d, p);

    b.set_phase("round564_ytail_halve_polarized_product");
    mod_halve_inplace_fast(b, y_acc, p);
    b.set_phase("round564_ytail_sub_offset_y");
    mod_sub_qb(b, y_acc, oy, p);

    b.set_phase("round564_ytail_compute_derivative_square");
    let ox_q = load_bits(b, ox);
    let derivative = b.alloc_qubits(N);
    round564_square_add_selected(b, &derivative, &ox_q, p);
    b.set_phase("round564_ytail_sub_eq_derivative_x3");
    for _ in 0..3 {
        cmod_sub_qq(b, y_acc, &derivative, eq, p);
    }
    b.set_phase("round564_ytail_uncompute_derivative_square");
    round564_square_sub_selected(b, &derivative, &ox_q, p);
    b.free_vec(&derivative);
    unload_bits(b, &ox_q, ox);

    b.set_phase("round564_ytail_uncompute_u_plus_d");
    mod_sub_qq_fast(b, &u_plus_d, &d, p);
    for i in (0..N).rev() {
        b.cx(u[i], u_plus_d[i]);
    }
    b.free_vec(&u_plus_d);

    b.set_phase("round564_ytail_uncompute_d");
    round564_uncompute_polarized_d(b, &d, x, ox, oy, eq, p);

    b.set_phase("round564_ytail_uncompute_eq");
    toggle_eq_zero_flag_fast(b, &eq_diff, eq);
    b.free(eq);
    mod_add_qq_fast(b, &eq_diff, x, p);
    unload_bits(b, &eq_diff, ox);
}

pub fn build_round564_polarized_third_square_ytail_component() -> Vec<Op> {
    build_round564_polarized_third_square_ytail_component_builder().ops
}

fn build_round564_polarized_third_square_ytail_component_builder() -> B {
    let mut b = B::new();
    let x = b.alloc_qubits(N);
    b.declare_qubit_register(&x);
    let u = b.alloc_qubits(N);
    b.declare_qubit_register(&u);
    let ox = b.alloc_bits(N);
    b.declare_bit_register(&ox);
    let oy = b.alloc_bits(N);
    b.declare_bit_register(&oy);
    let y_acc = b.alloc_qubits(N);
    b.declare_qubit_register(&y_acc);

    round564_emit_polarized_third_square_ytail_component(
        &mut b,
        &x,
        &u,
        &ox,
        &oy,
        &y_acc,
        SECP256K1_P,
    );
    b
}

