fn d1_direct_quotient_compute_product_from_raw_inverse(
    b: &mut B,
    numerator: &[QubitId],
    quotient: &[QubitId],
    inv_raw: &[QubitId],
    p: U256,
) {
    let compute_mul = std::env::var("D1_DIRECT_QUOTIENT_COMPUTE_MUL").ok();
    let compute_mul = compute_mul.as_deref().or_else(|| {
        if d1_phase_corrected_arith_core_enabled() {
            Some("schoolbook")
        } else {
            None
        }
    });
    match compute_mul {
        Some("schoolbook") => {
            mod_mul_write_into_zero_acc_schoolbook(b, quotient, numerator, inv_raw, p)
        }
        Some("schoolbook_lowq") => {
            mod_mul_write_into_zero_acc_schoolbook_lowq(b, quotient, numerator, inv_raw, p)
        }
        Some("schoolbook_peak_lowq") => {
            mod_mul_write_into_zero_acc_schoolbook_peak_lowq(b, quotient, numerator, inv_raw, p)
        }
        Some("horner") => mod_mul_horner_add_qq(b, quotient, numerator, inv_raw, p),
        Some("karatsuba1") | Some("1") => {
            mod_mul_write_into_zero_acc_karatsuba(b, quotient, numerator, inv_raw, p)
        }
        Some("karatsuba_lowq") | Some("lowq") => {
            mod_mul_write_into_zero_acc_karatsuba_lowq(b, quotient, numerator, inv_raw, p)
        }
        _ => mod_mul_write_into_zero_acc_karatsuba2(b, quotient, numerator, inv_raw, p),
    }
}

fn d1_direct_quotient_unscale_neg_product(
    b: &mut B,
    quotient: &[QubitId],
    p: U256,
    inverse_iters: usize,
) {
    let exact_unscale = std::env::var("D1_DIRECT_QUOTIENT_EXACT_UNSCALE")
        .ok()
        .as_deref()
        == Some("1");
    if exact_unscale {
        mod_neg_inplace(b, quotient, p);
    } else {
        mod_neg_inplace_fast(b, quotient, p);
    }
    for _ in 0..inverse_iters {
        if exact_unscale {
            mod_halve_inplace(b, quotient, p);
        } else {
            mod_halve_inplace_fast(b, quotient, p);
        }
    }
}

fn round588_folded_solinas_raw_consumer(
    b: &mut B,
    numerator: &[QubitId],
    quotient: &[QubitId],
    raw_r: &[QubitId],
    p: U256,
    inverse_iters: usize,
) {
    debug_assert_eq!(numerator.len(), N);
    debug_assert_eq!(quotient.len(), N);
    debug_assert_eq!(raw_r.len(), 399);
    let (raw_low, raw_high) = raw_r.split_at(N);
    debug_assert_eq!(raw_high.len(), 143);

    b.set_phase("round588_folded_low_256_product");
    d1_direct_quotient_compute_product_from_raw_inverse(b, numerator, quotient, raw_low, p);

    b.set_phase("round588_folded_high_init_c_times_num");
    let high_term = b.alloc_qubits(N);
    let solinas_c = (U256::from(1u64) << 32) + U256::from(977u64);
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, false);

    b.set_phase("round588_folded_high_143_controls");
    for i in 0..raw_high.len() {
        cmod_add_qq(b, quotient, &high_term, raw_high[i], p);
        if i + 1 < raw_high.len() {
            mod_double_inplace_fast(b, &high_term, p);
        }
    }

    b.set_phase("round588_folded_high_restore_scale");
    for _ in 1..raw_high.len() {
        mod_halve_inplace_fast(b, &high_term, p);
    }

    b.set_phase("round588_folded_high_uncompute_c_times_num");
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, true);
    b.free_vec(&high_term);

    b.set_phase("round588_folded_unscale");
    d1_direct_quotient_unscale_neg_product(b, quotient, p, inverse_iters);
}

fn schoolbook_rect_mul_into(b: &mut B, x: &[QubitId], y: &[QubitId], tmp_ext: &[QubitId]) {
    let n = x.len();
    let m = y.len();
    debug_assert!(tmp_ext.len() >= n + m);
    for i in 0..m {
        let row = b.alloc_qubits(n);
        for k in 0..n {
            b.ccx(y[i], x[k], row[k]);
        }
        let pad = b.alloc_qubit();
        let mut row_padded = row.clone();
        row_padded.push(pad);
        let slice: Vec<QubitId> = tmp_ext[i..i + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_add_fast(b, &row_padded, &slice, c_in);
        b.free(c_in);
        b.free(pad);
        for k in 0..n {
            let m = b.alloc_bit();
            b.hmr(row[k], m);
            b.cz_if(y[i], x[k], m);
        }
        b.free_vec(&row);
    }
}

fn schoolbook_rect_mul_into_inverse(b: &mut B, x: &[QubitId], y: &[QubitId], tmp_ext: &[QubitId]) {
    let n = x.len();
    let m = y.len();
    debug_assert!(tmp_ext.len() >= n + m);
    for i in (0..m).rev() {
        let row = b.alloc_qubits(n);
        for k in 0..n {
            b.ccx(y[i], x[k], row[k]);
        }
        let pad = b.alloc_qubit();
        let mut row_padded = row.clone();
        row_padded.push(pad);
        let slice: Vec<QubitId> = tmp_ext[i..i + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_sub_fast(b, &row_padded, &slice, c_in);
        b.free(c_in);
        b.free(pad);
        for k in 0..n {
            let m = b.alloc_bit();
            b.hmr(row[k], m);
            b.cz_if(y[i], x[k], m);
        }
        b.free_vec(&row);
    }
}

fn schoolbook_rect_mul_into_addsub(b: &mut B, x: &[QubitId], y: &[QubitId], tmp_ext: &[QubitId]) {
    let n = x.len();
    let m = y.len();
    debug_assert!(tmp_ext.len() >= n + m);

    let low = b.alloc_qubit();
    let mut wide: Vec<QubitId> = Vec::with_capacity(n + m + 1);
    wide.push(low);
    wide.extend_from_slice(&tmp_ext[..n + m]);

    for k in 0..m {
        let slice: Vec<QubitId> = wide[k..k + n + 1].to_vec();
        controlled_add_subtract_fast(b, x, &slice, y[k]);
    }

    // Rectangular Litinski correction:
    // intermediate = 2xy + 2^(n+m) - 2^m*x - 2^n*(y+1) + x.
    // Apply +2^n*(y+1) + 2^m*x - 2^(n+m) - x.
    {
        let pad = b.alloc_qubit();
        let mut y_ext = y.to_vec();
        y_ext.push(pad);
        let slice: Vec<QubitId> = wide[n..n + m + 1].to_vec();
        let c_in = b.alloc_qubit();
        b.x(c_in);
        cuccaro_add_fast(b, &y_ext, &slice, c_in);
        b.x(c_in);
        b.free(c_in);
        b.free(pad);
    }

    b.x(wide[n + m]);

    {
        let mut x_ext: Vec<QubitId> = x.to_vec();
        while x_ext.len() < n + m + 1 {
            x_ext.push(b.alloc_qubit());
        }
        let c_in = b.alloc_qubit();
        cuccaro_sub(b, &x_ext, &wide, c_in);
        b.free(c_in);
        for _ in n..n + m + 1 {
            let q = x_ext.pop().unwrap();
            b.free(q);
        }
    }

    {
        let pad = b.alloc_qubit();
        let mut x_ext = x.to_vec();
        x_ext.push(pad);
        let slice: Vec<QubitId> = wide[m..m + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_add_fast(b, &x_ext, &slice, c_in);
        b.free(c_in);
        b.free(pad);
    }

    b.free(low);
}

fn schoolbook_rect_mul_into_addsub_inverse(
    b: &mut B,
    x: &[QubitId],
    y: &[QubitId],
    tmp_ext: &[QubitId],
) {
    let n = x.len();
    let m = y.len();
    debug_assert!(tmp_ext.len() >= n + m);

    let low = b.alloc_qubit();
    let mut wide: Vec<QubitId> = Vec::with_capacity(n + m + 1);
    wide.push(low);
    wide.extend_from_slice(&tmp_ext[..n + m]);

    {
        let pad = b.alloc_qubit();
        let mut x_ext = x.to_vec();
        x_ext.push(pad);
        let slice: Vec<QubitId> = wide[m..m + n + 1].to_vec();
        let c_in = b.alloc_qubit();
        cuccaro_sub_fast(b, &x_ext, &slice, c_in);
        b.free(c_in);
        b.free(pad);
    }

    {
        let mut x_ext: Vec<QubitId> = x.to_vec();
        while x_ext.len() < n + m + 1 {
            x_ext.push(b.alloc_qubit());
        }
        let c_in = b.alloc_qubit();
        cuccaro_add(b, &x_ext, &wide, c_in);
        b.free(c_in);
        for _ in n..n + m + 1 {
            let q = x_ext.pop().unwrap();
            b.free(q);
        }
    }

    b.x(wide[n + m]);

    {
        let pad = b.alloc_qubit();
        let mut y_ext = y.to_vec();
        y_ext.push(pad);
        let slice: Vec<QubitId> = wide[n..n + m + 1].to_vec();
        let c_in = b.alloc_qubit();
        b.x(c_in);
        cuccaro_sub_fast(b, &y_ext, &slice, c_in);
        b.x(c_in);
        b.free(c_in);
        b.free(pad);
    }

    for k in (0..m).rev() {
        let slice: Vec<QubitId> = wide[k..k + n + 1].to_vec();
        controlled_add_subtract_fast_inverse(b, x, &slice, y[k]);
    }

    b.free(low);
}

fn round589_rectangular_solinas_raw_consumer(
    b: &mut B,
    numerator: &[QubitId],
    quotient: &[QubitId],
    raw_r: &[QubitId],
    p: U256,
    inverse_iters: usize,
) {
    debug_assert_eq!(numerator.len(), N);
    debug_assert_eq!(quotient.len(), N);
    debug_assert_eq!(raw_r.len(), 399);
    let (raw_low, raw_high) = raw_r.split_at(N);
    debug_assert_eq!(raw_high.len(), 143);

    b.set_phase("round589_rect_low_256_product");
    d1_direct_quotient_compute_product_from_raw_inverse(b, numerator, quotient, raw_low, p);

    b.set_phase("round589_rect_high_init_c_times_num");
    let high_term = b.alloc_qubits(N);
    let solinas_c = (U256::from(1u64) << 32) + U256::from(977u64);
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, false);

    b.set_phase("round589_rect_high_product");
    let tmp_ext = b.alloc_qubits(2 * N);
    schoolbook_rect_mul_into(b, &high_term, raw_high, &tmp_ext);

    b.set_phase("round589_rect_high_reduce");
    mod_add_solinas_ext_product(b, quotient, &tmp_ext, p);

    b.set_phase("round589_rect_high_unproduct");
    schoolbook_rect_mul_into_inverse(b, &high_term, raw_high, &tmp_ext);
    b.free_vec(&tmp_ext);

    b.set_phase("round589_rect_high_uncompute_c_times_num");
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, true);
    b.free_vec(&high_term);

    b.set_phase("round589_rect_unscale");
    d1_direct_quotient_unscale_neg_product(b, quotient, p, inverse_iters);
}

fn round590_rectangular_addsub_solinas_raw_consumer(
    b: &mut B,
    numerator: &[QubitId],
    quotient: &[QubitId],
    raw_r: &[QubitId],
    p: U256,
    inverse_iters: usize,
) {
    debug_assert_eq!(numerator.len(), N);
    debug_assert_eq!(quotient.len(), N);
    debug_assert_eq!(raw_r.len(), 399);
    let (raw_low, raw_high) = raw_r.split_at(N);
    debug_assert_eq!(raw_high.len(), 143);

    b.set_phase("round590_addsub_low_256_product");
    d1_direct_quotient_compute_product_from_raw_inverse(b, numerator, quotient, raw_low, p);

    b.set_phase("round590_addsub_high_init_c_times_num");
    let high_term = b.alloc_qubits(N);
    let solinas_c = (U256::from(1u64) << 32) + U256::from(977u64);
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, false);

    b.set_phase("round590_addsub_high_product");
    let tmp_ext = b.alloc_qubits(2 * N);
    schoolbook_rect_mul_into_addsub(b, &high_term, raw_high, &tmp_ext);

    b.set_phase("round590_addsub_high_reduce");
    mod_add_solinas_ext_product(b, quotient, &tmp_ext, p);

    b.set_phase("round590_addsub_high_unproduct");
    schoolbook_rect_mul_into_addsub_inverse(b, &high_term, raw_high, &tmp_ext);
    b.free_vec(&tmp_ext);

    b.set_phase("round590_addsub_high_uncompute_c_times_num");
    mul_by_const_acc(b, numerator, solinas_c, &high_term, p, true);
    b.free_vec(&high_term);

    b.set_phase("round590_addsub_unscale");
    d1_direct_quotient_unscale_neg_product(b, quotient, p, inverse_iters);
}

fn round592_residue_solinas_raw_consumer(
    b: &mut B,
    numerator: &[QubitId],
    quotient: &[QubitId],
    raw_r: &[QubitId],
    p: U256,
    inverse_iters: usize,
) {
    debug_assert_eq!(numerator.len(), N);
    debug_assert_eq!(quotient.len(), N);
    debug_assert_eq!(raw_r.len(), 399);
    let (raw_low, raw_high) = raw_r.split_at(N);
    debug_assert_eq!(raw_high.len(), 143);

    let residue = b.alloc_qubits(N);

    b.set_phase("round592_residue_copy_low");
    for i in 0..N {
        b.cx(raw_low[i], residue[i]);
    }

    b.set_phase("round592_residue_high_reduce");
    let solinas_c = (U256::from(1u64) << 32) + U256::from(977u64);
    for i in 0..raw_high.len() {
        cmod_add_qc_fast(b, &residue, solinas_c << i, raw_high[i], p);
    }

    b.set_phase("round592_residue_low_256_product");
    d1_direct_quotient_compute_product_from_raw_inverse(b, numerator, quotient, &residue, p);

    b.set_phase("round592_residue_high_unreduce");
    for i in (0..raw_high.len()).rev() {
        cmod_sub_qc_fast(b, &residue, solinas_c << i, raw_high[i], p);
    }

    b.set_phase("round592_residue_uncopy_low");
    for i in (0..N).rev() {
        b.cx(raw_low[i], residue[i]);
    }
    b.free_vec(&residue);

    b.set_phase("round592_residue_unscale");
    d1_direct_quotient_unscale_neg_product(b, quotient, p, inverse_iters);
}

fn build_round588_folded_solinas_raw_splice_builder() -> B {
    let mut b = B::new();
    let numerator = b.alloc_qubits(N);
    b.declare_qubit_register(&numerator);
    let quotient = b.alloc_qubits(N);
    b.declare_qubit_register(&quotient);
    let packed_us = b.alloc_qubits(257);
    b.declare_qubit_register(&packed_us);
    let packed_vr_raw = b.alloc_qubits(399);
    b.declare_qubit_register(&packed_vr_raw);
    let m_hist = b.alloc_qubits(399);
    b.declare_qubit_register(&m_hist);

    round588_folded_solinas_raw_consumer(
        &mut b,
        &numerator,
        &quotient,
        &packed_vr_raw,
        SECP256K1_P,
        400,
    );

    let _ = (packed_us, m_hist);
    b
}

pub fn build_round588_folded_solinas_raw_splice_component() -> Vec<Op> {
    build_round588_folded_solinas_raw_splice_builder().ops
}

pub fn build_round588_folded_solinas_raw_splice_phase_resources(
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round588_folded_solinas_raw_splice_builder();
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

