pub const ROUND556_SHIFTED_SOURCE_ROW_BENCH_ENV: &str = "ROUND556_SHIFTED_SOURCE_ROW_BENCH";
pub const ROUND556_SHIFTED_SOURCE_ROW_WIDTH_ENV: &str = "ROUND556_SHIFTED_SOURCE_ROW_WIDTH";
pub const ROUND556_SHIFTED_SOURCE_ROW_QBITS_ENV: &str = "ROUND556_SHIFTED_SOURCE_ROW_QBITS";

fn round556_shifted_source_row_bench_enabled() -> bool {
    std::env::var(ROUND556_SHIFTED_SOURCE_ROW_BENCH_ENV)
        .ok()
        .as_deref()
        == Some("1")
}

fn round556_shifted_source_row_width_from_env() -> usize {
    std::env::var(ROUND556_SHIFTED_SOURCE_ROW_WIDTH_ENV)
        .ok()
        .and_then(|s| s.parse::<usize>().ok())
        .filter(|&width| width >= 2)
        .unwrap_or(258)
}

fn round556_shifted_source_row_qbits_from_env(width: usize) -> usize {
    std::env::var(ROUND556_SHIFTED_SOURCE_ROW_QBITS_ENV)
        .ok()
        .and_then(|s| s.parse::<usize>().ok())
        .filter(|&q_bits| (1..=width).contains(&q_bits))
        .unwrap_or(26.min(width))
}

fn round556_cmp_lt_shifted_source_into_fast(
    b: &mut B,
    left: &[QubitId],
    source: &[QubitId],
    shift: usize,
    flag: QubitId,
) {
    assert_eq!(left.len(), source.len());
    assert!(shift < left.len());

    // Compare left < (source << shift) without allocating the shifted word.
    // The low shifted positions are compile-time zero, so they cannot create a
    // borrow/carry from the initial zero carry-in.  The comparison is therefore
    // exactly left[shift..] < source[..width-shift].
    let active = left.len() - shift;
    cmp_lt_into_fast(b, &left[shift..], &source[..active], flag);
}

fn round556_cmp_lt_shifted_source_into_borrowed_cin(
    b: &mut B,
    left: &[QubitId],
    source: &[QubitId],
    shift: usize,
    flag: QubitId,
    cmp_cin: QubitId,
) {
    assert_eq!(left.len(), source.len());
    assert!(shift < left.len());

    let active = left.len() - shift;
    cmp_lt_into_borrowed_cin(b, &left[shift..], &source[..active], flag, cmp_cin);
}

fn round556_cmp_lt_shifted_source_into_fast_borrowed_carries(
    b: &mut B,
    left: &[QubitId],
    source: &[QubitId],
    shift: usize,
    flag: QubitId,
    cmp_cin: QubitId,
    cmp_carries: &[QubitId],
) {
    assert_eq!(left.len(), source.len());
    assert!(shift < left.len());

    let active = left.len() - shift;
    cmp_lt_into_fast_borrowed_carries(
        b,
        &left[shift..],
        &source[..active],
        flag,
        cmp_cin,
        &cmp_carries[..active],
    );
}

fn cmp_lt_into_fast_borrowed_carries(
    b: &mut B,
    u: &[QubitId],
    v: &[QubitId],
    flag: QubitId,
    c_in: QubitId,
    carries: &[QubitId],
) {
    let n = u.len();
    assert_eq!(n, v.len());
    assert!(n > 0);
    assert!(carries.len() >= n);

    for i in 0..n {
        b.x(u[i]);
    }

    b.cx(u[0], v[0]);
    b.cx(u[0], c_in);
    b.ccx(c_in, v[0], carries[0]);
    b.cx(carries[0], u[0]);
    for i in 1..n {
        b.cx(u[i], v[i]);
        b.cx(u[i], u[i - 1]);
        b.ccx(u[i - 1], v[i], carries[i]);
        b.cx(carries[i], u[i]);
    }

    b.cx(u[n - 1], flag);

    for i in (1..n).rev() {
        b.cx(carries[i], u[i]);
        let m = b.alloc_bit();
        b.hmr(carries[i], m);
        b.cz_if(u[i - 1], v[i], m);
        b.cx(u[i], u[i - 1]);
        b.cx(u[i], v[i]);
    }
    b.cx(carries[0], u[0]);
    let m0 = b.alloc_bit();
    b.hmr(carries[0], m0);
    b.cz_if(c_in, v[0], m0);
    b.cx(u[0], c_in);
    b.cx(u[0], v[0]);

    for i in 0..n {
        b.x(u[i]);
    }
}

fn round556_load_gated_shifted_source(
    b: &mut B,
    control: QubitId,
    source: &[QubitId],
    shift: usize,
    gated: &[QubitId],
) {
    assert_eq!(source.len(), gated.len());
    assert!(shift < source.len());
    for bit in shift..source.len() {
        b.ccx(control, source[bit - shift], gated[bit]);
    }
}

fn round556_clear_gated_shifted_source_hmr(
    b: &mut B,
    control: QubitId,
    source: &[QubitId],
    shift: usize,
    gated: &[QubitId],
) {
    assert_eq!(source.len(), gated.len());
    assert!(shift < source.len());
    for bit in (shift..source.len()).rev() {
        let m = b.alloc_bit();
        b.hmr(gated[bit], m);
        b.cz_if(control, source[bit - shift], m);
        b.bit_store0(m);
    }
}

fn round556_load_gated_word(b: &mut B, control: QubitId, source: &[QubitId], gated: &[QubitId]) {
    assert_eq!(source.len(), gated.len());
    for i in 0..source.len() {
        b.ccx(control, source[i], gated[i]);
    }
}

fn round556_clear_gated_word_hmr(
    b: &mut B,
    control: QubitId,
    source: &[QubitId],
    gated: &[QubitId],
) {
    assert_eq!(source.len(), gated.len());
    for i in (0..source.len()).rev() {
        let m = b.alloc_bit();
        b.hmr(gated[i], m);
        b.cz_if(control, source[i], m);
        b.bit_store0(m);
    }
}

fn round556_fused_sign_controlled_addsub_digit(
    b: &mut B,
    acc: &[QubitId],
    addend: &[QubitId],
    sign: QubitId,
) {
    assert_eq!(acc.len(), addend.len());
    assert!(acc.len() >= 2);

    // sign=1 means add; sign=0 means subtract.  Toggle the addend and carry-in
    // by !sign, then run the same HMR-clean Cuccaro adder for both cases.
    let nonnegative = b.alloc_qubit();
    b.x(nonnegative);
    b.cx(sign, nonnegative);
    for &wire in addend {
        b.cx(nonnegative, wire);
    }
    cuccaro_add_fast(b, addend, acc, nonnegative);
    for &wire in addend.iter().rev() {
        b.cx(nonnegative, wire);
    }
    b.cx(sign, nonnegative);
    b.x(nonnegative);
    b.free(nonnegative);
}

fn round556_fused_sign_controlled_addsub_digit_borrowed(
    b: &mut B,
    acc: &[QubitId],
    addend: &[QubitId],
    sign: QubitId,
    nonnegative: QubitId,
    carries: &[QubitId],
) {
    assert_eq!(acc.len(), addend.len());
    assert!(acc.len() >= 2);
    assert!(carries.len() >= acc.len() - 1);

    // Same add/sub convention as `round556_fused_sign_controlled_addsub_digit`,
    // but the caller supplies the one-bit sign scratch and the carry lane.
    b.x(nonnegative);
    b.cx(sign, nonnegative);
    for &wire in addend {
        b.cx(nonnegative, wire);
    }
    cuccaro_add_fast_borrowed_carries(b, addend, acc, nonnegative, &carries[..acc.len() - 1]);
    for &wire in addend.iter().rev() {
        b.cx(nonnegative, wire);
    }
    b.cx(sign, nonnegative);
    b.x(nonnegative);
}

fn round556_emit_forward_remainder_digit(
    b: &mut B,
    rem: &[QubitId],
    rem_divisor: &[QubitId],
    gated: &[QubitId],
    lt_tmp: QubitId,
    qbit: QubitId,
    shift: usize,
) {
    round556_cmp_lt_shifted_source_into_fast(b, rem, rem_divisor, shift, lt_tmp);
    b.x(lt_tmp);
    b.cx(lt_tmp, qbit);
    b.x(lt_tmp);
    b.x(qbit);
    b.cx(qbit, lt_tmp);
    b.x(qbit);
    round556_load_gated_shifted_source(b, qbit, rem_divisor, shift, gated);
    round556_fused_sign_controlled_addsub_digit(b, rem, gated, lt_tmp);
    round556_clear_gated_shifted_source_hmr(b, qbit, rem_divisor, shift, gated);
}

fn round556_emit_forward_remainder_digit_borrowed(
    b: &mut B,
    rem: &[QubitId],
    rem_divisor: &[QubitId],
    gated: &[QubitId],
    lt_tmp: QubitId,
    nonnegative: QubitId,
    cmp_carries: &[QubitId],
    carries: &[QubitId],
    qbit: QubitId,
    shift: usize,
) {
    round556_cmp_lt_shifted_source_into_fast_borrowed_carries(
        b,
        rem,
        rem_divisor,
        shift,
        lt_tmp,
        nonnegative,
        cmp_carries,
    );
    b.x(lt_tmp);
    b.cx(lt_tmp, qbit);
    b.x(lt_tmp);
    b.x(qbit);
    b.cx(qbit, lt_tmp);
    b.x(qbit);
    round556_load_gated_shifted_source(b, qbit, rem_divisor, shift, gated);
    round556_fused_sign_controlled_addsub_digit_borrowed(
        b,
        rem,
        gated,
        lt_tmp,
        nonnegative,
        carries,
    );
    round556_clear_gated_shifted_source_hmr(b, qbit, rem_divisor, shift, gated);
}

fn round556_emit_coeff_update_erase_digit(
    b: &mut B,
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    gated: &[QubitId],
    sign_one: QubitId,
    qbit: QubitId,
    shift: usize,
) {
    round556_load_gated_shifted_source(b, qbit, coeff_divisor, shift, gated);
    round556_fused_sign_controlled_addsub_digit(b, coeff, gated, sign_one);
    round556_clear_gated_shifted_source_hmr(b, qbit, coeff_divisor, shift, gated);
    b.x(qbit);
    round556_cmp_lt_shifted_source_into_fast(b, coeff, coeff_divisor, shift, qbit);
}

fn round556_emit_coeff_update_erase_digit_borrowed(
    b: &mut B,
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    gated: &[QubitId],
    sign_one: QubitId,
    nonnegative: QubitId,
    cmp_carries: &[QubitId],
    carries: &[QubitId],
    qbit: QubitId,
    shift: usize,
) {
    round556_load_gated_shifted_source(b, qbit, coeff_divisor, shift, gated);
    round556_fused_sign_controlled_addsub_digit_borrowed(
        b,
        coeff,
        gated,
        sign_one,
        nonnegative,
        carries,
    );
    round556_clear_gated_shifted_source_hmr(b, qbit, coeff_divisor, shift, gated);
    b.x(qbit);
    round556_cmp_lt_shifted_source_into_fast_borrowed_carries(
        b,
        coeff,
        coeff_divisor,
        shift,
        qbit,
        nonnegative,
        cmp_carries,
    );
}

fn emit_direct_centered_shifted_source_qbit_row(
    b: &mut B,
    rem: &[QubitId],
    rem_divisor: &[QubitId],
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    qbits: &[QubitId],
    gated: &[QubitId],
    lt_tmp: QubitId,
    sign_one: QubitId,
    nonnegative: QubitId,
    carries: &[QubitId],
) {
    let width = rem.len();
    assert_eq!(rem_divisor.len(), width);
    assert_eq!(coeff.len(), width);
    assert_eq!(coeff_divisor.len(), width);
    assert_eq!(gated.len(), width);
    assert!(!qbits.is_empty());
    assert!(qbits.len() <= width);
    assert!(carries.len() >= width - 1);
    let mut remainder_cmp_carries = Vec::with_capacity(width);
    remainder_cmp_carries.extend_from_slice(&carries[..width - 1]);
    remainder_cmp_carries.push(sign_one);
    let mut coeff_cmp_carries = Vec::with_capacity(width);
    coeff_cmp_carries.extend_from_slice(&carries[..width - 1]);
    coeff_cmp_carries.push(lt_tmp);

    b.set_phase("direct_centered_shifted_source_qbit_remainder_digits");
    for q_index in (0..qbits.len()).rev() {
        round556_emit_forward_remainder_digit_borrowed(
            b,
            rem,
            rem_divisor,
            gated,
            lt_tmp,
            nonnegative,
            &remainder_cmp_carries,
            carries,
            qbits[q_index],
            q_index,
        );
    }

    b.set_phase("direct_centered_shifted_source_qbit_coeff_digits");
    b.x(sign_one);
    for q_index in 0..qbits.len() {
        round556_emit_coeff_update_erase_digit_borrowed(
            b,
            coeff,
            coeff_divisor,
            gated,
            sign_one,
            nonnegative,
            &coeff_cmp_carries,
            carries,
            qbits[q_index],
            q_index,
        );
    }
    b.x(sign_one);
}

fn round556_emit_word_controlled_add(
    b: &mut B,
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    gated: &[QubitId],
    sign_one: QubitId,
    control: QubitId,
) {
    round556_load_gated_word(b, control, coeff_divisor, gated);
    round556_fused_sign_controlled_addsub_digit(b, coeff, gated, sign_one);
    round556_clear_gated_word_hmr(b, control, coeff_divisor, gated);
}

fn round556_emit_sigma_subtract(
    b: &mut B,
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    gated: &[QubitId],
    sigma: QubitId,
    sign_zero: QubitId,
) {
    round556_load_gated_word(b, sigma, coeff_divisor, gated);
    round556_fused_sign_controlled_addsub_digit(b, coeff, gated, sign_zero);
    round556_clear_gated_word_hmr(b, sigma, coeff_divisor, gated);
}

fn emit_round556_shifted_source_row_component(
    b: &mut B,
    rem: &[QubitId],
    rem_divisor: &[QubitId],
    coeff: &[QubitId],
    coeff_divisor: &[QubitId],
    sigma: QubitId,
    q_increment: QubitId,
    lt_tmp: QubitId,
    sign_one: QubitId,
    qbits: &[QubitId],
    gated: &[QubitId],
) {
    let width = rem.len();
    assert_eq!(rem_divisor.len(), width);
    assert_eq!(coeff.len(), width);
    assert_eq!(coeff_divisor.len(), width);
    assert_eq!(gated.len(), width);
    assert!(!qbits.is_empty());
    assert!(qbits.len() <= width);

    b.set_phase("round556_shifted_source_remainder_digits");
    for q_index in (0..qbits.len()).rev() {
        round556_emit_forward_remainder_digit(
            b,
            rem,
            rem_divisor,
            gated,
            lt_tmp,
            qbits[q_index],
            q_index,
        );
    }

    b.set_phase("round556_shifted_source_coeff_digits");
    b.x(sign_one);
    for q_index in 0..qbits.len() {
        round556_emit_coeff_update_erase_digit(
            b,
            coeff,
            coeff_divisor,
            gated,
            sign_one,
            qbits[q_index],
            q_index,
        );
    }
    round556_emit_word_controlled_add(b, coeff, coeff_divisor, gated, sign_one, q_increment);
    b.x(sign_one);

    b.set_phase("round556_shifted_source_sigma_subtract");
    round556_emit_sigma_subtract(b, coeff, coeff_divisor, gated, sigma, lt_tmp);
}

fn build_round556_shifted_source_row_component_builder(width: usize, q_bits: usize) -> B {
    assert!(width >= 2);
    assert!((1..=width).contains(&q_bits));

    let mut b = B::new();
    let rem = b.alloc_qubits(width);
    b.declare_qubit_register(&rem);
    let rem_divisor = b.alloc_qubits(width);
    b.declare_qubit_register(&rem_divisor);
    let coeff = b.alloc_qubits(width);
    b.declare_qubit_register(&coeff);
    let coeff_divisor = b.alloc_qubits(width);
    b.declare_qubit_register(&coeff_divisor);
    let sigma = b.alloc_qubit();
    let q_increment = b.alloc_qubit();
    let lt_tmp = b.alloc_qubit();
    let sign_one = b.alloc_qubit();
    let qbits = b.alloc_qubits(q_bits);
    let mut meta = vec![sigma, q_increment, lt_tmp, sign_one];
    meta.extend(qbits.iter().copied());
    b.declare_qubit_register(&meta);
    let gated = b.alloc_qubits(width);

    emit_round556_shifted_source_row_component(
        &mut b,
        &rem,
        &rem_divisor,
        &coeff,
        &coeff_divisor,
        sigma,
        q_increment,
        lt_tmp,
        sign_one,
        &qbits,
        &gated,
    );

    b.set_phase("round556_shifted_source_free_gated");
    b.free_vec(&gated);
    b
}

pub fn build_round556_shifted_source_row_component(width: usize, q_bits: usize) -> Vec<Op> {
    build_round556_shifted_source_row_component_builder(width, q_bits).ops
}

pub fn build_round556_shifted_source_row_component_phase_resources(
    width: usize,
    q_bits: usize,
) -> (Vec<Op>, Vec<PhaseResource>, u32, &'static str) {
    let b = build_round556_shifted_source_row_component_builder(width, q_bits);
    let rows = phase_resources(&b.ops, &b.phase_transitions);
    (b.ops, rows, b.peak_qubits, b.peak_phase)
}

